import type { Verse } from '../types';

// Repositório centralizado para os capítulos de Gênesis
export const GENESIS_CHAPTERS: Record<number, Verse[]> = {
  1: [
    { n: 1, text: 'Eku sunguleni Xikwembu xi tumbuluxile matilo ni misava.' },
    { n: 2, text: 'Kasi misava a yi nga ri na xivumbeko, yi ri hava; ni munyama a wu ri ehenhla ka vuenti bya mati, kutani Moya wa Xikwembu wu endzelela ehenhla ka mati.' },
    { n: 3, text: 'Kutani Xikwembu xi ku: A ku ve ni ku vonakala; kutani ku va ni ku vonakala.' },
    { n: 4, text: 'Xikwembu xi vona ku vonakala leswaku ku sasekile; Xikwembu xi hambanisa ku vonakala ni munyama.' },
    { n: 5, text: 'Xikwembu xi vitana ku vonakala ku ri Nhlekanhi, munyama xi wu vitana Vusiku. Kutani ku va ni madyambu ni mixo, siku ro sungula.' },
    { n: 6, text: 'Xikwembu xi ku: A ku ve ni xikhunlu exikarhi ka mati, xi hambanisa mati eka mati.' },
    { n: 7, text: 'Xikwembu xi endla xikhunlu, xi hambanisa mati lama nga ehansi ka xikhunlu ni mati lama nga ehenhla ka xikhunlu; kutani swi va tano.' },
    { n: 8, text: 'Xikwembu xi vitana xikhunlu ku ri Matilo. Kutani ku va ni madyambu ni mixo, siku ra vumbirhi.' },
    { n: 9, text: 'Xikwembu xi ku: Mati lama nga ehansi ka matilo a ma hlengeletane ndhawini yin\u2019we, ku humelela ndhawu leyi omeke; kutani swi va tano.' },
    { n: 10, text: 'Xikwembu xi vitana ndhawu leyi omeke ku ri Misava, ni ku hlengeletana ka mati xi ku vitana Malwandle; Xikwembu xi vona leswaku swi sasekile.' },
    { n: 11, text: 'Kutani Xikwembu xi ku: Misava a yi meryise swimilana swa mixaka-xaka, leswi tswalaka timbeu, ni mirhi leyi nga ni mihandzu leyi nga ni timbeu endzeni ka yona; kutani swi va tano.' },
    { n: 12, text: 'Misava yi humesa swimilana leswi tswalaka timbeu hi mixaka ya swona, ni mirhi leyi nga ni mihandzu leyi nga ni timbeu endzeni ka yona hi mixaka ya yona. Kutani Xikwembu xi vona leswaku swi sasekile.' },
    { n: 13, text: 'Kutani ku va ni madyambu ni mixo, siku ra vunharhu.' },
    { n: 14, text: 'Kutani Xikwembu xi ku: A ku ve ni swivoningo empfhukeni wa tilo, leswaku swi hambanisa nhlekanhi ni vusiku; swi ta va swikombiso swo tiva minkarhi, ni masiku, ni malembe;' },
    { n: 15, text: 'naswona a swi ve swivoningo empfhukeni wa tilo, leswaku swi voninga ehenhla ka misava; kutani swi va tano.' },
    { n: 16, text: 'Kutani Xikwembu xi endla swivoningo swimbirhi leswikulu: xivoningo lexikulu leswaku xi fuma nhlekanhi, ni xivoningo lexitsongo leswaku xi fuma vusiku; xi endla ni tinyeleti.' },
    { n: 17, text: 'Xikwembu xi swi veka empfhukeni wa tilo leswaku swi voninga ehenhla ka misava,' },
    { n: 18, text: 'swi fuma nhlekanhi ni vusiku, ni ku hambanisa ku vonakala ni munyama. Kutani Xikwembu xi vona leswaku swi sasekile.' },
    { n: 19, text: 'Kutani ku va ni madyambu ni mixo, siku ra vumune.' },
    { n: 20, text: 'Kutani Xikwembu xi ku: Mati a ma tale hi swivumbiwa leswi hanyaka, ni tinyanyana ti haha ehenhla ka misava, empfhukeni wa tilo.' },
    { n: 21, text: 'Hiloko Xikwembu xi tumbuluxa swiharhi swikulu swa lwandle, ni swivumbiwa hinkwaswo leswi hanyaka leswi fambaka ni leswi talaka ematini hi mixaka ya swona, ni tinyanyana hinkwato ti ri na timapa hi mixaka ya tona. Kutani Xikwembu xi vona leswaku swi sasekile.' },
    { n: 22, text: 'Kutani Xikwembu xi swi katekisa, xi ku: Tswalanani, mi anama, mi tala ematini ya lwandle, ni tinyanyana a ti tale emisaveni.' },
    { n: 23, text: 'Kutani ku va ni madyambu ni mixo, siku ra vuntlhanu.' },
    { n: 24, text: 'Kutani Xikwembu xi ku: Misava a yi humese swivumbiwa leswi hanyaka hi mixaka ya swona: swifuwo, swilundzu, ni swiharhi swa nhova hi mixaka ya swona; kutani swi va tano.' },
    { n: 25, text: 'Xikwembu xi endla swiharhi swa nhova hi mixaka ya swona, ni swifuwo hi mixaka ya swona, ni swilundzu hinkwaswo swa misava hi mixaka ya swona. Kutani Xikwembu xi vona leswaku swi sasekile.' },
    { n: 26, text: 'Kutani Xikwembu xi ku: A hi endleni munhu hi xifaniso xa hina, a fana na hina; a a fume tinhlampfi ta lwandle, ni tinyanyana ta tilo, ni swifuwo, ni misava hinkwayo, ni swilundzu hinkwaswo leswi fambaka ehenhla ka misava.' },
    { n: 27, text: 'Hiloko Xikwembu xi tumbuluxa munhu hi xifaniso xa xona; xi n\u2019wi tumbuluxile hi xifaniso ka Xikwembu; xi va tumbuluxile va ri wa xinuna ni wa xisati.' },
    { n: 28, text: 'Kutani Xikwembu xi va katekisa, xi ku ka vona: Tswalanani, mi tala, mi tata misava, mi yi fuma; fumani tinhlampfi ta lwandle, ni tinyanyana ta tilo, ni swivumbiwa hinkwaswo leswi hanyaka leswi fambaka ehenhla ka misava.' },
    { n: 29, text: 'Kutani Xikwembu xi ku: Vonani, ndzi mi nyikile swimilana hinkwaswo leswi tswalaka timbeu leswi nga ehenhla ka misava hinkwayo, ni mirhi hinkwayo leyi nga ni mihandzu leyi nga ni timbeu; swi ta va swakudya swa n\u2019wina.' },
    { n: 30, text: 'Swiharhi hinkwaswo swa misava, ni tinyanyana hinkwato ta tilo, ni swilundzu hinkwaswo leswi fambaka ehenhla ka misava, leswi nga ni vutomi, ndzi swi nyikile swimilana hinkwaswo swa rihlaza leswaku swi va swakudya swa swona; kutani swi va tano.' },
    { n: 31, text: 'Kutani Xikwembu xi vona hinkwaswo leswi xi swi endleke, naswona, vonani, a swi sasekile ngopfu. Kutani ku va ni madyambu ni mixo, siku ra vutsevu.' },
  ],
  2: [
    { n: 1, text: 'Matilo ni misava ni swivandla hinkwaswo swa swona swi hetiwa hi mukhuva wolowo.' },
    { n: 2, text: 'Kutani hi siku ra vunkombo Xikwembu xi heta ntirho wa xona lowu xi wu endleke; xi wisa hi siku ra vunkombo emintirhweni ya xona hinkwayo leyi xi yi endleke.' },
    { n: 3, text: 'Xikwembu xi katekisa siku ra vunkombo, xi ri hlawula, hikuva hi rona xi wiseke emintirhweni ya xona hinkwayo ya ku tumbuluxa, leyi Xikwembu xi yi endleke.' },
    { n: 4, text: 'Hi lowu nkarhi lowu matilo ni misava swi tumbuluxiweke ha wona, loko Hosi Xikwembu xi endla misava ni matilo.' },
    { n: 5, text: 'A ku nga si va na xihlahla xa nhova emisaveni, ni swimilana swa nhova a swi nga si mila; hikuva Hosi Xikwembu a xi nga si nisa mpfula emisaveni, naswona a ku nga si va na munhu wo rima misava.' },
    { n: 6, text: 'Kambe ku hunga mhungu yi huma emisaveni, yi tsakamisa hinkwako ehenhla ka misava.' },
    { n: 7, text: 'Kutani Hosi Xikwembu xi vumba munhu hi ntshuri wa misava, xi huhutela eminyingwini ya yena ku hefemula ka vutomi; hiloko munhu a hundzuka xihanyami lexi hanyaka.' },
    { n: 8, text: 'Hosi Xikwembu xi rima ntanga le Edeni, tlhelo ra le vuxeni, xi veka kona munhu loyi xi n\u2019wi vumbeke.' },
    { n: 9, text: 'Hosi Xikwembu xi meryise emisaveni mirhi hinkwayo leyi tsakisaka ku yi vona, ni leyi nga ni swakudya swo nandziha; ni murhi wa vutomi exikarhi ka ntanga, ni murhi wo tiva leswinene ni leswobiha.' },
    { n: 10, text: 'Nambu wu huma le Edeni wu ta tsakamisa ntanga; kutani wu hambana hi swihlala swa mune.' },
    { n: 11, text: 'Vito ra lowo sungula i Pixoni; hi lowu rhendzelaka tiko hinkwaro ra Havhila, lomu nsuku wu kumekaka kona.' },
    { n: 12, text: 'Nsuku wa tiko rero wu sasekile; ku ni bedeliyumu ni ribye ra lulama kona.' },
    { n: 13, text: 'Vito ra nambu wa vumbirhi i Gihoni; hi lowu rhendzelaka tiko hinkwaro ra Kuxi.' },
    { n: 14, text: 'Vito ra nambu wa vunharhu i Tigrisi; hi lowu khulukaka hi le vuxeni ka tiko ra Asiriya. Nambu wa vumune i Yufrata.' },
    { n: 15, text: 'Kutani Hosi Xikwembu xi teka munhu, xi n\u2019wi veka entangeni wa Edeni leswaku a wu rima, a wu hlayisa.' },
    { n: 16, text: 'Hosi Xikwembu xi laya munhu, xi ku: U pfumeleriwile ku dya emirhini hinkwayo ya ntanga;' },
    { n: 17, text: 'kambe lowu a wu fanelanga ku dya eka wona i murhi wo tiva leswinene ni leswobiha; hikuva siku u dyaka eka wona, u ta fa hakunene.' },
    { n: 18, text: 'Kutani Hosi Xikwembu xi ku: A swi sasekanga leswaku munhu a va swakwe; ndzi ta n\u2019wi endlela mupfuni la n\u2019wi faneleke.' },
    { n: 19, text: 'Hosi Xikwembu xi vumba hi misava swiharhi hinkwaswo swa nhova ni tinyanyana hinkwato ta tilo; xi ti tisa eka munhu leswaku xi vona leswi a nga ta ti vitanisa xiswona; vito rin\u2019wana ni rin\u2019wana leri munhu a nga ta vitana xihanyami ha rona, ri va vito ra xona.' },
    { n: 20, text: 'Kutani munhu a thya swifuwo hinkwaswo mavito, ni tinyanyana ta tilo, ni swiharhi hinkwaswo swa nhova; kambe eka Adamu a ku kumekanga mupfuni la n\u2019wi faneleke.' },
    { n: 21, text: 'Hiloko Hosi Xikwembu xi tisa vurhongo lebyikulu eka munhu, a etlela; xi teka rimbambu rin\u2019wana ra yena, xi pfalela ndhawu ya rona hi nyama.' },
    { n: 22, text: 'Kutani rimbambu leri Hosi Xikwembu xi ri tekeke eka munhu, xi ri endla wansati, xi n\u2019wi tisa eka munhu.' },
    { n: 23, text: 'Hiloko munhu a ku: Loko ku ri lwalwu, i rhamu ra marhamu ya mina, ni nyama ya nyama ya mina; u ta vitaniwa wansati, hikuva u tekiwile eka wanuna.' },
    { n: 24, text: 'Hi swona leswi endlekaka leswaku wanuna a siya tata wa yena ni mana wa yena, a namarhela wansati wa yena; kutani va va nyama yin\u2019we.' },
    { n: 25, text: 'Kasi havumbirhi ka vona, wanuna ni wansati wa yena, a va nga ambalanga nchumu, kambe a va nga khomiwi hi tingana.' },
  ],
  3: [
    { n: 1, text: 'Nyoka a yi tlharihile ku tlula swiharhi hinkwaswo swa nhova leswi Hosi Xikwembu xi swi endleke. Yi ku eka wansati: Hakunene Xikwembu xi vurile leswaku mi nga dyi eka mirhi hinkwayo ya ntanga xana?' },
    { n: 2, text: 'Wansati a hlamula nyoka, a ku: Hi nga dya mihandzu ya mirhi ya ntanga;' },
    { n: 3, text: 'kambe loko eku ri mihandzu ya murhi lowu nga exikarhi ka ntanga, Xikwembu xi vurile xi ku: Mi nga tshuki mi yi dya, mi nga yi khumbi, leswaku mi nga fi.' },
    { n: 4, text: 'Kutani nyoka yi ku eka wansati: E-e, mi nga ka mi nga fi hakunene;' },
    { n: 5, text: 'hikuva Xikwembu xa tiva leswaku siku mi dyaka eka wona, mahlo ya n\u2019wina ma ta pfuleka, mi ta fana ni Xikwembu, mi tiva leswinene ni leswobiha.' },
    { n: 6, text: 'Loko wansati a vona leswaku murhi lowu wu sasekile eka swakudya, ni leswaku wa tsakisa emonlhweni, ni ku va murhi wo navela leswaku munhu a tlhariha, a teka mihandzu ya wona, a dya; a nyika ni nuna wa yena loyi a a ri na yena, na yena a dya.' },
    { n: 7, text: 'Hiloko mahlo ya vona havumbirhi ma pfuleka, va swi tiva leswaku va mbyandzu; va fambisa marhamu ya nkuwa, va tiendlela switandzhana.' },
    { n: 8, text: 'Kutani va twa mpfumawulo wa Hosi Xikwembu xi ri karhi xi famba-famba entangeni hi nkarhi wa madyambu, kutani wanuna ni wansati wa yena va tifihla emahlweni ka Hosi Xikwembu exikarhi ka mirhi ya ntanga.' },
    { n: 9, text: 'Hosi Xikwembu xi vitana wanuna, xi ku ka yena: U kwihi xana?' },
    { n: 10, text: 'A hlamula a ku: Ndzi twile mpfumawulo wa wena entangeni, ndzi chava hikuva ndzi mbyandzu; hiloko ndzi tifihla.' },
    { n: 11, text: 'Xi ku: I mani la ku byeleke leswaku u mbyandzu xana? Xana u dyile eka murhi lowu ndzi ku layeke leswaku u nga dyi eka wona?' },
    { n: 12, text: 'Wanuna a ku: Wansati loyi u ndzi nyikeke yena leswaku a va na mina, hi yena la ndzi nyikeke swa murhi lowu, ndzi dya.' },
    { n: 13, text: 'Hosi Xikwembu xi ku eka wansati: I ncini lexi u xi endleke xana? Wansati a ku: Nyoka yi ndzi kangarhisile, hiloko ndzi dya.' },
    { n: 14, text: 'Kutani Hosi Xikwembu xi ku eka nyoka: Leswi u endleke sweswo, u rhukaniwile exikarhi ka swifuwo hinkwaswo ni swiharhi hinkwaswo swa nhova; u ta famba hi khwiri ra wena, u dya ntshuri masiku hinkwaswo ya vutomi bya wena.' },
    { n: 15, text: 'Ndzi ta veka vunyengi exikarhi ka wena ni wansati, ni xikarhi ka mbewu ya wena ni mbewu ya yena; yona yi ta ku faya nhloko, wena u ta yi luma xirhendze.' },
    { n: 16, text: 'Eka wansati xi ku: Ndzi ta Yenisa swinene kuhlupheka ka wena ni ku mita ka wena; u ta tswala vana hi kuhlupheka, navelo wa wena wu ta va eka nuna wa wena, kutani u ta ku fuma.' },
    { n: 17, text: 'Kuni eka Adamu xi ku: Leswi u yingiseke rito ra wansati wa wena, u dya eka murhi lowu ndzi ku layeke ha wona, ndzi ku: U nga tshuki u dya eka wona, misava yi rhukaniwile hi mhaka ya wena; u ta dya swa yona hi kuhlupheka masiku hinkwaswo ya vutomi bya wena.' },
    { n: 18, text: 'Yi ta ku meryisela mitwa ni mihlwa, kutani u ta dya swimilana swa nhova.' },
    { n: 19, text: 'U ta dya vuswa hi nyuku wa xikandza xa wena, u kondza u vuyela emisaveni, hikuva u tekiwile eka yona; leswi u nga ntshuri, u ta vuyela entshurini.' },
    { n: 20, text: 'Wanuna a thya wansati wa yena vito ra Evha, hikuva hi yena mana wa hinkwavo va hanyaka.' },
    { n: 21, text: 'Hosi Xikwembu xi endlela Adamu ni wansati wa yena tinguvu ta makhumba, xi va ambeza.' },
    { n: 22, text: 'Kutani Hosi Xikwembu xi ku: Vonani, munhu u fana ni un\u2019wana wa hina, u tiva leswinene ni leswobiha; sweswi hikuva a nga tshuki a tshambuluta voko ra yena, a teka ni swa murhi wa vutomi, a dya, a hanya hilaha ku nga heriki,' },
    { n: 23, text: 'hiloko Hosi Xikwembu xi n\u2019wi hlongola entangeni wa Edeni leswaku a rima misava leyi a tekiweke eka yona.' },
    { n: 24, text: 'Xi hlongola munhu; xi veka makerubimi ni tlhari ra langavi ra ndzilo leri rhendzelekaka hinkwako etlhelo ra le vuxeni ra ntanga wa Edeni, swo rindza ndlela ya murhi wa vutomi.' },
  ],
  4: [
    { n: 1, text: 'Adamu a hlangana ni Evha wansati wa yena; hiloko a mita, a tswala Kayini, a ku: Ndzi kumile wanuna hi mupfuno wa Hosi.' },
    { n: 2, text: 'A tlhela a tswala Abhele, ndzisana ya yena. Abhele a a ri murisi wa swifuwo, kasi Kayini a a ri murimi wa misava.' },
    { n: 3, text: 'Endzhaku ka masiku, Kayini a tisa swin\u2019wana swa mihandzu ya misava, a endla ha swona gandzelo eka Hosi.' },
    { n: 4, text: 'Abhele na yena a tisa swin\u2019wana swa mativula ya swifuwo swa yena, ni mafurha ya swona. Hosi yi hlalukela Abhele ni gandzelo ra yena;' },
    { n: 5, text: 'kambe eka Kayini ni gandzelo ra yena a yi hlalukelanga. Hiloko Kayini a kariha ngopfu, xikandza xa yena xi dzwihala.' },
    { n: 6, text: 'Kutani Hosi yi ku eka Kayini: U karihela yini xana? Ni xikandza xa wena xi dzwihalela yini?' },
    { n: 7, text: 'Loko u endla leswinene, xana u nga ka u nga amukeriwi xana? Kambe loko u nga endli leswinene, xidyoho xi ku rhendzele enyangweni, naswona navelo wa xona wu le ka wena, kambe u fanele ku xi fuma.' },
    { n: 8, text: 'Kutani Kayini a vulavula ni Abhele ndzisana ya yena. Loko va ri enhoveni, Kayini a pfukela Abhele ndzisana ya yena, a n\u2019wi dlaya.' },
    { n: 9, text: 'Hiloko Hosi yi ku eka Kayini: U kwihi Abhele ndzisana ya wena xana? A hlamula a ku: A ndzi tivi; xana ndzi muhlayisi wa ndzisana ya mina xana?' },
    { n: 10, text: 'Xi ku: I ncini lexi u xi endleke xana? Mpfumawulo wa ngati ya ndzisana ya wena wu huwelela eka mina wu huma emisaveni.' },
    { n: 11, text: 'Sweswi u rhukaniwile emisaveni, leyi pfulaka nomu wa yona ku amukela ngati ya ndzisana ya wena exandleni xa wena.' },
    { n: 12, text: 'Loko u rima misava, yi nga ka yi nga ha ku nyiki matimba ya yona; u ta va muhlundzuki ni mutluli-ndlela emisaveni.' },
    { n: 13, text: 'Kutani Kayini a ku eka Hosi: Ku xupuriwa ka mina i kukulu, ku tsandza ku rhwaleka.' },
    { n: 14, text: 'Vonani, ndzi hlongorile namuntlha ehenhla ka misava leyi, ndzi ta tifihla emahlweni ka wena; ndzi ta va muhlundzuki ni mutluli-ndlela emisaveni, un\u2019wana ni un\u2019wana la nga ta ndzi kuma u ta ndzi dlaya.' },
    { n: 15, text: 'Kambe Hosi yi ku ka yena: E-e, un\u2019wana ni un\u2019wana la dlayaka Kayini u ta rihisewa ka ntlhanu na katsandza. Kutani Hosi yi veka mfungo eka Kayini leswaku un\u2019wana ni un\u2019wana la n\u2019wi kumaka a nga n\u2019wi dlayi.' },
    { n: 16, text: 'Hiloko Kayini a suka emahlweni ka Hosi, a ya tshama etikweni ra Nodi, tlhelo ra le vuxeni ka Edeni.' },
    { n: 17, text: 'Kayini a hlangana ni wansati wa yena; hiloko a mita, a tswala Enoko. Kayini a a ri karhi a aka muti, a thya muti lowu vito ra n\u2019wana wa yena Enoko.' },
    { n: 18, text: 'Enoko a tswala Irada; Irada a tswala Mehuyaele; Mehuyaele a tswala Metuxaele; Metuxaele a tswala Lameke.' },
    { n: 19, text: 'Lameke a teka vavasati vambirhi; vito ra un\u2019wana a a ri Ada, ni vito ra wa vumbirhi a a ri Sila.' },
    { n: 20, text: 'Ada a tswala Yabale; hi yena tata wa lava tshamaka ematandzeni, va ri na swifuwo.' },
    { n: 21, text: 'Vito ra ndzisana ya yena a a ri Yubale; hi yena tata wa hinkwavo lava tlangaka xichandju ni nanga.' },
    { n: 22, text: 'Sila na yena a tswala Tubal-kayini, muendli wa mavele hinkwawo ya nsuku ni ntsimbhi. Vito ra nhwanyana wa Tubal-kayini a a ri Naama.' },
    { n: 23, text: 'Lameke a ku eka vavasati va yena Ada ni Sila: Yingisani rito ra mina, vavasati va Lameke, rhiyani ndleve eka leswi ndzi swi vulaka: Ndzi dlayile wanuna hi mhaka ya mbanga ya mina, ni jaha hi mhaka ya ku xupuriwa ka mina.' },
    { n: 24, text: 'Loko Kayini a rihisewa ka ntlhanu na katsandza, Lameke u ta rihisewa ka makume ntlhanu na kambirhi na katsandza.' },
    { n: 25, text: 'Adamu a tlhela a hlangana ni wansati wa yena; hiloko a tswala n\u2019wana wa wanuna, a n\u2019wi thya vito ra Setha, a ku: Hikuva Xikwembu xi ndzi nyikile mbewu yin\u2019wana emandleni va Abhele, lowu Kayini a n\u2019wi dlayeke.' },
    { n: 26, text: 'Setha na yena a tswala n\u2019wana wa wanuna, a n\u2019wi thya vito ra Enoxi; hi nkarhi wolowo ku sunguriwile ku khongela vito ra Hosi.' },
  ],
  5: [
    { n: 1, text: 'Leli i buku ya tinxaka ta Adamu. Siku Xikwembu xi vumbeke munhu ha rona, xi n\u2019wi endle hi xifaniso xa Xikwembu;' },
    { n: 2, text: 'xi va vumbile va ri wa xinuna ni wa xisati, xi va katekisa, xi va thya vito ra Munhu, hi siku leri va vumbiekaeke ha rona.' },
    { n: 3, text: 'Adamu a hanya malembe ya dzana ni makume manharhu, a tswala n\u2019wana wa wanuna la fanaka na yena, hi xifaniso xa yena, a n\u2019wi thya vito ra Setha.' },
    { n: 4, text: 'Masiku ya Adamu endzhaku ka loko a tswarile Setha ma ve malembe ya nhungu wa madzana; a tswala vana va xinuna ni va xisati.' },
    { n: 5, text: 'Masiku hinkwaswo lawa Adamu a hanyeke wona ma ve malembe ya kume ra madzana ni makume manharhu ma hlongolaka masiku ya ntlhanu na manharhu; kutani a fa.' },
    { n: 6, text: 'Setha a hanya malembe ya dzana ni ntlhanu, a tswala Enoxi.' },
    { n: 7, text: 'Setha a hanya endzhaku ka loko a tswarile Enoxi malembe ya nhungu wa madzana ni ku hlongola masiku ya ntlhanu na mbirhi; a tswala vana va xinuna ni va xisati.' },
    { n: 8, text: 'Masiku hinkwaswo ya Setha ma ve malembe ya kume ra madzana ni makume mambirhi; kutani a fa.' },
    { n: 9, text: 'Enoxi a hanya malembe ya tuvu, a tswala Kenani.' },
    { n: 10, text: 'Enoxi a hanya endzhaku ka loko a tswarile Kenani malembe ya nhungu wa madzana ni ku hlongola masiku ya ntlhanu; a tswala vana va xinuna ni va xisati.' },
    { n: 11, text: 'Masiku hinkwaswo ya Enoxi ma ve malembe ya kume ra madzana ni ntlhanu; kutani a fa.' },
    { n: 12, text: 'Kenani a hanya malembe ya ntsandza-vahlayi, a tswala Mahalalele.' },
    { n: 13, text: 'Kenani a hanya endzhaku ka loko a tswarile Mahalalele malembe ya nhungu wa madzana ni makume mana; a tswala vana va xinuna ni va xisati.' },
    { n: 14, text: 'Masiku hinkwaswo ya Kenani ma ve malembe ya kume ra madzana ni khume; kutani a fa.' },
    { n: 15, text: 'Mahalalele a hanya malembe ya makume tshevu ni ntlhanu, a tswala Yaredi.' },
    { n: 16, text: 'Mahalalele a hanya endzhaku ka loko a tswarile Yaredi malembe ya nhungu wa madzana ni makume manharhu; a tswala vana va xinuna ni va xisati.' },
    { n: 17, text: 'Masiku hinkwaswo ya Mahalalele ma ve malembe ya nhungu wa madzana ni makume kaye ni ntlhanu; kutani a fa.' },
    { n: 18, text: 'Yaredi a hanya malembe ya dzana ni makume tshevu ni mambirhi, a tswala Enoko.' },
    { n: 19, text: 'Yaredi a hanya endzhaku ka loko a tswarile Enoko malembe ya nhungu wa madzana; a tswala vana va xinuna ni va xisati.' },
    { n: 20, text: 'Masiku hinkwaswo ya Yaredi ma ve malembe ya kume ra madzana ni makume tshevu ni mambirhi; kutani a fa.' },
    { n: 21, text: 'Enoko a hanya malembe ya makume tshevu ni ntlhanu, a tswala Metuxala.' },
    { n: 22, text: 'Enoko a famba ni Xikwembu; endzhaku ka loko a tswarile Metuxala, a hanya malembe ya madzana manharhu, a tswala vana va xinuna ni va xisati.' },
    { n: 23, text: 'Masiku hinkwaswo ya Enoko ma ve malembe ya madzana manharhu ni makume tshevu ni ntlhanu.' },
    { n: 24, text: 'Enoko a famba ni Xikwembu, kutani a nga ha kumiwanga, hikuva Xikwembu xi n\u2019wi tekile.' },
    { n: 25, text: 'Metuxala a hanya malembe ya dzana ni makume nhungu ni ntsandza-vahlayi, a tswala Lameke.' },
    { n: 26, text: 'Metuxala a hanya endzhaku ka loko a tswarile Lameke malembe ya nhungu wa madzana ni makume tshevu ni mambirhi; a tswala vana va xinuna ni va xisati.' },
    { n: 27, text: 'Masiku hinkwaswo ya Metuxala ma ve malembe ya kume ra madzana ni makume tshevu ni kaye; kutani a fa.' },
    { n: 28, text: 'Lameke a hanya malembe ya dzana ni makume nhungu ni mambirhi, a tswala n\u2019wana wa wanuna;' },
    { n: 29, text: 'a n\u2019wi thya vito ra Nowa, a ku: Loyi u ta va yena la nga ta hi chavelela emintirhweni ya hina ni le kuhluphekeni ka mavoko ya hina loku humaka emisaveni leyi Hosi yi yi rhukaneke.' },
    { n: 30, text: 'Lameke a hanya endzhaku ka loko a tswarile Nowa malembe ya ntlhanu wa madzana ni makume kaye ni ntlhanu; a tswala vana va xinuna ni va xisati.' },
    { n: 31, text: 'Masiku hinkwaswo ya Lameke ma ve malembe ya nhungu wa madzana ni makume ntlhanu na katsandza; kutani a fa.' },
    { n: 32, text: 'Nowa a a ri ni malembe ya ntlhanu wa madzana; hiloko Nowa a tswala Xeme, Hama ni Yafeta.' },
  ],
  6: [
    { n: 1, text: 'Kutani loko vanhu va sungula ku tala ehenhla ka misava, va tswala vanhwanyana,' },
    { n: 2, text: 'vana va xinuna va Xikwembu va vona leswaku vanhwanyana va vanhu va sasekile; kutani va titeketela vavasati eka hinkwavo lava va va hlawuleke.' },
    { n: 3, text: 'Kuni Hosi yi ku: Moya wa mina a wu nga ka wu nga tshameli ku lwa ni munhu hilaha ku nga heriki, hikuva na yena i nyama; hikwalaho masiku ya yena ya ta va malembe ya dzana ni makume mambirhi.' },
    { n: 4, text: 'Ku ni swihontlovila emisaveni emasikwini wolawo, na le ndzhaku ka swona, loko vana va xinuna va Xikwembu va nghena eka vanhwanyana va vanhu, va va tswalela vana. Hi vona vhenyi va khale, vanhu va ndhuma.' },
    { n: 5, text: 'Kutani Hosi yi vona leswaku vuhomboloki bya munhu i bukulu emisaveni, ni leswaku makungu hinkwawo ya mianakanyo ya mbilu ya yena ma bihile ntsena minkarhi hinkwayo.' },
    { n: 6, text: 'Hiloko Hosi yi tisola leswi yi endleke munhu emisaveni, swi yi vavisa mbilu.' },
    { n: 7, text: 'Kutani Hosi yi ku: Ndzi ta herisa munhu loyi ndzi n\u2019wi vumbeke ehenhla ka misava; ku sukela eka munhu ku ya fika eka swifuwo, ni swilundzu, ni tinyanyana ta tilo; hikuva ndzi dlayiwa hi ku tisola leswi ndzi swi endleke.' },
    { n: 8, text: 'Kambe Nowa u kumile tintswalo emonlhweni ka Hosi.' },
    { n: 9, text: 'Leti i tinxaka ta Nowa. Nowa a a ri wanuna la lulameke, la nga riki na xisandzu exikarhi ka vanhu va nkarhi wa yena; Nowa a a famba ni Xikwembu.' },
    { n: 10, text: 'Nowa a tswala vana vanharhu va xinuna: Xeme, Hama ni Yafeta.' },
    { n: 11, text: 'Kasi misava a yi onhekile emahlweni ka Xikwembu, yi tale hi madzolonga.' },
    { n: 12, text: 'Xikwembu xi languta misava, kutani, vonani, yi onhekile, hikuva vanhu hinkwavo va onhile tindlela ta vona emisaveni.' },
    { n: 13, text: 'Kutani Xikwembu xi ku eka Nowa: Makumu ya vanhu hinkwavo ya tile emahlweni ka mina, hikuva misava yi tale hi madzolonga hikwalaho ka vona; kutani vonani, ndzi ta va herisa swin\u2019we ni misava.' },
    { n: 14, text: 'Tiendlele ngalava hi ntsandza wa gofere; u ta endla tikamara endzeni ka yona, u yi totela mbyaka endzeni ni le handle.' },
    { n: 15, text: 'Kutani u ta yi endla hi ndlela leyi: ku leha ka ngalava ku ta va timitara ta dzana ni makume ntlhanu, ku anama ka yona ku va timitara ta makume mambirhi ni ntlhanu, ni ku tlakuka ka yona ku va timitara ta khume ni ntlhanu.' },
    { n: 16, text: 'U ta endlela ngalava fastele, u yi heta ehenhla ka xipimo xa voko rin\u2019we; u ta veka nyangwa ya ngalava etlhelo ra yona; u ta yi endla yi va ni magandlati ya le hansi, ni ya vumbirhi, ni ya vunharhu.' },
    { n: 17, text: 'Hikuva vona, mina ndzi tisa ndhambi ya mati ehenhla ka misava, leswaku yi herisa nyama hinkwayo leyi nga ni moya wa vutomi ehansi ka matilo; hinkwaswo leswi nga emisaveni swi ta fa.' },
    { n: 18, text: 'Kambe ndzi ta simeka ntwanano wa mina na wena; u ta nghena engalaveni, wena ni vana va wena va xinuna, ni wansati wa wena, ni vavasati va vana va wena na wena.' },
    { n: 19, text: 'Kutani eka swivumbiwa hinkwaswo leswi hanyaka, eka nyama hinkwayo, u ta nghenisa swimbirhi-swimbirhi swa mixaka hinkwayo engalaveni, leswaku swi ta tshama swi hanyile na wena; swi ta va wa xinuna ni wa xisati.' },
    { n: 20, text: 'Eka tinyanyana hi mixaka ya tona, ni le ka swifuwo hi mixaka ya swona, ni le ka swilundzu hinkwaswo swa misava hi mixaka ya swona, swimbirhi-swimbirhi swa mixaka hinkwayo swi ta ta eka wena, leswaku u swi hlayisa swi hanya.' },
    { n: 21, text: 'Kona teka swakudya hinkwaswo leswi dyiwaka, u swi hlengeletela eka wena; swi ta va swakudya swa wena ni swa swona.' },
    { n: 22, text: 'Nowa a endla tano; a endla hinkwaswo hilaha Xikwembu xi n\u2019wi leriseke hakona.' },
  ],
  7: [
    { n: 1, text: 'Kutani Hosi yi ku eka Nowa: Nghena engalaveni, wena ni ndyangu wa wena hinkwako, hikuva ndzi ku vonile u lulamile mahlweni ka mina exikarhi ka vanhu va nkarhi lowu.' },
    { n: 2, text: 'Eka swifuwo hinkwaswo leswi tengeke, u ta teka ntlhanu na swimbirhi, wa xinuna ni wa xisati wa swona; kambe eka swifuwo leswi nga tengangiki u teka swimbirhi, wa xinuna ni wa xisati wa swona;' },
    { n: 3, text: 'na le ka tinyanyana ta tilo u teka ntlhanu na swimbirhi, wa xinuna ni wa xisati, leswaku mbewu ya tona yi tshama yi hanyile ehenhla ka misava hinkwayo.' },
    { n: 4, text: 'Hikuva endzhaku ka masiku ya ntlhanu na mambirhi, ndzi ta nisa mpfula emisaveni masiku ya makume mana ni vusiku va makume mana; ndzi ta herisa swivumbiwa hinkwaswo leswi hanyaka leswi ndzi swi endleke ehenhla ka misava.' },
    { n: 5, text: 'Nowa a endla hinkwaswo hilaha Hosi xi n\u2019wi leriseke hakona.' },
    { n: 6, text: 'Nowa a a ri ni malembe ya ntlhanu wa madzana ni madzana mambirhi loko ndhambi ya mati yi fika ehenhla ka misava.' },
    { n: 7, text: 'Hiloko Nowa a nghena engalaveni, ni vana va yena va xinuna, ni wansati wa yena, ni vavasati va vana va yena na yena, hikwalaho ka mati ya ndhambi.' },
    { n: 8, text: 'Eka swifuwo leswi tengeke, ni swifuwo leswi nga tengangiki, ni tinyanyana, ni swilundzu hinkwaswo leswi fambaka ehenhla ka misava,' },
    { n: 9, text: 'swi nghena swimbirhi-swimbirhi eka Nowa engalaveni, wa xinuna ni wa xisati, hilaha Xikwembu xi leriseke Nowa hakona.' },
    { n: 10, text: 'Kutani endzhaku ka masiku ya ntlhanu na mambirhi, mati ya ndhambi ma fika ehenhla ka misava.' },
    { n: 11, text: 'Hi lembe ra ntlhanu wa madzana ni madzana mambirhi ya vutomi bya Nowa, hi n\u2019weti va vumbirhi, hi siku ra khume na ntlhanu na mambirhi ra n\u2019weti, hi siku rero swihlovo hinkwaswo va vuenti byikulu swi pfurisiwa, ni mafastele ya tilo ma pfuliwa.' },
    { n: 12, text: 'Kutani mpfula yi nisa ehenhla ka misava masiku ya makume mana ni vusiku va makume mana.' },
    { n: 13, text: 'Hi siku rero hakunene, Nowa, ni Xeme, ni Hama, ni Yafeta, vana va Nowa, ni wansati wa Nowa, ni vavasati vanharhu va vana va yena na vona, va nghena engalaveni;' },
    { n: 14, text: 'vona, ni swiharhi hinkwaswo swa nhova hi mixaka ya swona, ni swifuwo hinkwaswo hi mixaka ya swona, ni swilundzu hinkwaswo leswi fambaka ehenhla ka misava hi mixaka ya swona, ni tinyanyana hinkwato hi mixaka ya tona, tinyanyana hinkwato ta mixaka-xaka leyi nga ni timapa.' },
    { n: 15, text: 'Swi nghena eka Nowa engalaveni swimbirhi-swimbirhi swa nyama hinkwayo leyi nga ni moya wa vutomi.' },
    { n: 16, text: 'Leswi ngheneke, swi nghene va ri wa xinuna ni wa xisati va nyama hinkwayo, hilaha Xikwembu xi n\u2019wi leriseke hakona; kutani Hosi yi n\u2019wi pfalela endzeni.' },
    { n: 17, text: 'Ndhambi yi va ehenhla ka misava masiku ya makume mana; mati ma tala, ma tlakusa ngalava, hiloko yi famba ehenhla ka misava.' },
    { n: 18, text: 'Mati ma nyandlamela, ma tala swinene ehenhla ka misava; kutani ngalava yi famba ehenhla ka mati.' },
    { n: 19, text: 'Mati ma nyandlamela swinene-nene ehenhla ka misava, hiloko tintsava hinkwato leti tlakukeke leti nga ehansi ka matilo hinkwato ti funengetiwa.' },
    { n: 20, text: 'Mati ma tlakuka timitara ta ntlhanu na timbeu ehenhla ka tona, kutani tintsava ti funengetiwa.' },
    { n: 21, text: 'Hiloko nyama hinkwayo leyi fambaka ehenhla ka misava yi fa: tinyanyana, swifuwo, swiharhi swa nhova, swivumbiwa hinkwaswo leswi talaka emisaveni, ni vanhu hinkwavo.' },
    { n: 22, text: 'Hinkwaswo leswi nga ni ku hefemula ka moya wa vutomi eminyingwini ya swona, eka hinkwaswo leswi a swi ri emavandleni lama omeke, swi fa.' },
    { n: 23, text: 'Kutani swivumbiwa hinkwaswo leswi hanyaka leswi a swi ri ehenhla ka misava swi herisiwa, ku sukela eka munhu ku ya fika eka swifuwo, ni swilundzu, ni tinyanyana ta tilo; swi herisiwile emisaveni; ku sala Nowa ntsena ni lava a va ri na yena engalaveni.' },
    { n: 24, text: 'Kutani mati ma nyandlamela ehenhla ka misava masiku ya dzana ni makume ntlhanu.' },
  ],
  8: [
    { n: 1, text: 'Kutani Xikwembu xi tsundzuka Nowa, ni swiharhi hinkwaswo leswi hanyaka, ni swifuwo hinkwaswo leswi a va ri na yena engalaveni; kutani Xikwembu xi endla leswaku ku hunga mheho ehenhla ka misava, hiloko mati ma sungula ku miyela.' },
    { n: 2, text: 'Swihlovo va vuenti ni mafastele ya tilo swi pfaleka, ni mpfula leyi humaka etilweni yi miyetiwa;' },
    { n: 3, text: 'mati ma hunguka emisaveni hi mukhuva wolowo; kutani endzhaku ka masiku ya dzana ni makume ntlhanu mati ma hunguka.' },
    { n: 4, text: 'Hi n\u2019weti wa vunkombo, hi siku ra khume na ntlhanu na mambirhi ra n\u2019weti, ngalava yi ya tshama ehenhla ka tintsava ta Ararati.' },
    { n: 5, text: 'Mati ma ya mahlweni ma hunguka ku fikela n\u2019weti wa vukhume; hi n\u2019weti wa vukhume, hi siku ro sungula ra n\u2019weti, tinhlohlorhi ta tintsava ti humelela.' },
    { n: 6, text: 'Kutani endzhaku ka masiku ya makume mana, Nowa a pfula fastele ya ngalava leyi xi yi endleke,' },
    { n: 7, text: 'a rhuma gava; rona ri huma ri famba ri vuye-vuye mati ma kondza ma oma ehenhla ka misava.' },
    { n: 8, text: 'A tlhela a rhuma tuva leswaku a vona loko mati ma hungukile ehenhla ka misava;' },
    { n: 9, text: 'kambe tuva ri nga kumi ndhawu yo wisisa nkondzo wa rona, hiloko ri vuyela eka yena engalaveni, hikuva mati a ma ha ri ehenhla ka misava hinkwayo; a tshambuluta voko ra yena, a ri teka, a ri nghenisa eka yena engalaveni.' },
    { n: 10, text: 'A rindza masiku man\u2019wana ya ntlhanu na mambirhi, a tlhela a rhuma tuva leri ri huma engalaveni;' },
    { n: 11, text: 'kutani tuva ri vuyela eka yena hi nkarhi wa madyambu, kutani, vonani, a ku ri ni rhiyana ra mutlvari leri tsembiweke ra rihlaza enonwini wa rona; hiloko Nowa a tiva leswaku mati ma hungukile ehenhla ka misava.' },
    { n: 12, text: 'A rindza masiku man\u2019wana ya ntlhanu na mambirhi, a rhuma tuva; rona leri ri nga ha vuyelangana eka yena.' },
    { n: 13, text: 'Hi lembe ra ntlhanu wa madzana ni madzana mambirhi ni rin\u2019we, hi n\u2019weti ro sungula, hi siku ro sungula ra n\u2019weti, mati ma oma ehenhla ka misava; kutani Nowa a susa xifunengeto xa ngalava, a languta, kutani, vonani, ehenhla ka misava a ku omile.' },
    { n: 14, text: 'Hi n\u2019weti wa vumbirhi, hi siku ra makume mambirhi ni ntlhanu na mambirhi ra n\u2019weti, misava a yi omile hi ku helela.' },
    { n: 15, text: 'Kutani Xikwembu xi vulavula ni Nowa, xi ku:' },
    { n: 16, text: 'Huma engalaveni, wena ni wansati wa wena, ni vana va wena va xinuna, ni vavasati va vana va wena na wena.' },
    { n: 17, text: 'Humesa na wena swivumbiwa hinkwaswo leswi hanyaka leswi nga na wena, swa nyama hinkwayo: tinyanyana, swifuwo, ni swilundzu hinkwaswo leswi fambaka ehenhla ka misava, leswaku swi tala emisaveni, swi tswalana, swi anama ehenhla ka misava.' },
    { n: 18, text: 'Hiloko Nowa a huma, ni vana va yena va xinuna, ni wansati wa yena, ni vavasati va vana va yena na yena.' },
    { n: 19, text: 'Swiharhi hinkwaswo, swilundzu hinkwaswo, ni tinyanyana hinkwato, hinkwaswo leswi fambaka ehenhla ka misava, hi mixaka ya swona, swi huma engalaveni.' },
    { n: 20, text: 'Kutani Nowa a akela Hosi alitari; a teka swin\u2019wana swa swifuwo hinkwaswo leswi tengeke ni swin\u2019wana swa tinyanyana hinkwato leti tengeke, a humesa magandzelo lama na maveleiki ehenhla ka alitari.' },
    { n: 21, text: 'Hosi yi nuhetela risuna leri nandzihaika; kutani Hosi yi ku embilu ya yona: Ndzi nga ka ndzi nga ha rhukani misava hikwalaho ka munhu, hikuva makungu ya mbilu ya munhu ma bihile ku sukela evuntshweni bya yena; naswona ndzi nga ka ndzi nga ha dlayi swivumbiwa hinkwaswo leswi hanyaka, hilaha ndzi endleke hakona.' },
    { n: 22, text: 'Masiku hinkwaswo lawa misava yi nga ta tshama ha wona, ku rima ni ku tshovelela, xirhami ni mumu, xixika ni ximumu, nhlekanhi ni vusiku, swi nga ka swi nga miyetiwi.' },
  ],
  9: [
    { n: 1, text: 'Kutani Xikwembu xi katekisa Nowa ni vana va yena va xinuna, xi ku ka vona: Tswalanani, mi tala, mi tata misava.' },
    { n: 2, text: 'Ku chava n\u2019wina ni ku rhendzeleka ha n\u2019wina swi ta va eka swiharhi hinkwaswo swa misava, ni le ka tinyanyana hinkwato ta tilo, eka hinkwaswo leswi fambaka ehenhla ka misava, ni le ka tinhlampfi hinkwato ta lwandle; swi nyikiwile emavokweni ya n\u2019wina.' },
    { n: 3, text: 'Hinkwaswo leswi fambaka swi hanya swi ta va swakudya swa n\u2019wina; hilaha ndzi mi nyikeke swimilana swa rihlaza, ndzi mi nyika hinkwaswo sweswi.' },
    { n: 4, text: 'Kambe nyama leyi nga ni vutomi bya yona, loku nga ngati ya yona, mi nga tshuki mi yi dya.' },
    { n: 5, text: 'Hakunene ngati ya vutomi bya n\u2019wina ndzi ta yi lava; ndzi ta yi lava exandleni xa xiharhi xinun\u2019wana ni xinun\u2019wana; naswona exandleni xa munhu, exandleni xa makwavo wa munhu unun\u2019wana ni unun\u2019wana ndzi ta lava vutomi bya munhu.' },
    { n: 6, text: 'Loyi a halataka ngati ya munhu, ngati ya yena yi ta halatiwa hi munhu; hikuva Xikwembu xi endle munhu hi xifaniso xa xona.' },
    { n: 7, text: 'Kuni n\u2019wina, tswalanani, mi tala; andlalekani emisaveni, mi tala eka yona.' },
    { n: 8, text: 'Kutani Xikwembu xi vulavula ni Nowa ni vana va yena va xinuna lava a va ri na yena, xi ku:' },
    { n: 9, text: 'Vonani, mina ndzi simeka ntwanano wa mina na n\u2019wina, ni mbewu ya n\u2019wina endzhaku ka n\u2019wina,' },
    { n: 10, text: 'ni swivumbiwa hinkwaswo leswi hanyaka leswi nga na n\u2019wina: tinyanyana, swifuwo, ni swiharhi hinkwaswo swa nhova swa misava leswi nga na n\u2019wina, ku sukela eka hinkwaswo leswi humeke engalaveni ku ya fika eka swiharhi hinkwaswo swa misava.' },
    { n: 11, text: 'Ndzi simeka ntwanano wa mina na n\u2019wina: Nyama hinkwayo yi nga ka yi nga ha herisiwi hi mati ya ndhambi; naswona ku nga ka ku nga ha vi na ndhambi yo herisa misava.' },
    { n: 12, text: 'Kutani Xikwembu xi ku: Leli i xikombiso xa ntwanano lowu ndzi wu endlaka exikarhi ka mina na n\u2019wina ni swivumbiwa hinkwaswo leswi hanyaka leswi nga na n\u2019wina, eka tinxaka hinkwato leti nga ha vuyaka:' },
    { n: 13, text: 'Ndzi veka nkwangulatilo wa mina emapapeni, kutani wu ta va xikombiso xa ntwanano exikarhi ka mina ni misava.' },
    { n: 14, text: 'Kutani loko ndzi tisa mapapa ehenhla ka misava, kutani nkwangulatilo wu humelela emapapeni,' },
    { n: 15, text: 'ndzi ta tsundzuka ntwanano wa mina, lowu nga exikarhi ka mina na n\u2019wina ni swivumbiwa hinkwaswo leswi hanyaka swa nyama hinkwayo; kutani mati ma nga ka ma nga ha hundzuki ndhambi yo herisa nyama hinkwayo.' },
    { n: 16, text: 'Nkwangulatilo wu ta va emapapeni, kutani ndzi wu languta leswaku ndzi tsundzuka ntwanano lowu nga heriki exikarhi ka Xikwembu ni swivumbiwa hinkwaswo leswi hanyaka swa nyama hinkwayo leyi nga ehenhla ka misava.' },
    { n: 17, text: 'Kutani Xikwembu xi ku eka Nowa: Leli i xikombiso xa ntwanano lowu ndzi wu simekeke exikarhi ka mina ni nyama hinkwayo leyi nga ehenhla ka misava.' },
    { n: 18, text: 'Vana va Nowa lava humeke engalaveni a a ri Xeme, Hama ni Yafeta; Hama i tata wa Kanana.' },
    { n: 19, text: 'Lava vanharhu i vana va Nowa; kutani hi vona lava vanhu hinkwavo va misava va hangalakeke ha vona.' },
    { n: 20, text: 'Nowa a sungula ku va murimi wa misava, a rima ntanga wa vhinyo.' },
    { n: 21, text: 'A nwa vhinyo, hiloko a pyopya, a tiandlaleka mbyandzu endzeni ka tende xa yena.' },
    { n: 22, text: 'Hama, tata wa Kanana, a vona ku mbyandzu ka tata wa yena, a ya byela vamakwavo vambirhi va nga handle.' },
    { n: 23, text: 'Kutani Xeme ni Yafeta va teka nguvu, va yi veka ematshurini ya vona havumbirhi, va famba va ndzuluka, va funengeta ku mbyandzu ka tata wa vona; swikandza va vona swi langute ndzhaku, a va nga ku vonanga ku mbyandzu ka tata wa vona.' },
    { n: 24, text: 'Loko Nowa a pfuka eku pyopyeni ka yena, a tiva leswi n\u2019wana wa yena lontsongo xi n\u2019wi endleke swona.' },
    { n: 25, text: 'Hiloko a ku: U rhukaniwile Kanana; u ta va nandza wa nandza eka vamakwavo.' },
    { n: 26, text: 'A tlhela a ku: A ku nkhensike Hosi, Xikwembu xa Xeme; kutani Kanana a a ve nandza wa yena.' },
    { n: 27, text: 'Xikwembu a xi anamise Yafeta, a a tshame ematendzeni ya Xeme; kutani Kanana a a ve nandza wa yena.' },
    { n: 28, text: 'Nowa a hanya endzhaku ka ndhambi malembe ya madzana manharhu ni makume ntlhanu.' },
    { n: 29, text: 'Masiku hinkwaswo ya Nowa ma ve malembe ya madzana kaye ni makume ntlhanu; kutani a fa.' },
  ],
  10: [
    { n: 1, text: 'Leti i tinxaka ta vana va Nowa: Xeme, Hama ni Yafeta; va tswariwile vana endzhaku ka ndhambi.' },
    { n: 2, text: 'Vana va Yafeta: Gomere, Magogi, Madayi, Yavhana, Tubale, Mexeke ni Tirasi.' },
    { n: 3, text: 'Vana va Gomere: Axkenazi, Rifata ni Togarma.' },
    { n: 4, text: 'Vana va Yavhana: Elixa, Tarsis, Kitimi ni Dodanimi.' },
    { n: 5, text: 'Ku sukela eka lava, swihlala va matiko swi hangalakile ematikweni ya swona, un\u2019wana ni un\u2019wana hi ririmi ra yena, hi tinxaka ta vona, ematikweni ya vona.' },
    { n: 6, text: 'Vana va Hama: Kuxi, Mizrayimi, Puti ni Kanana.' },
    { n: 7, text: 'Vana va Kuxi: Seba, Havhila, Sabta, Raama ni Sabteka. Vana va Raama: Xeba ni Dedani.' },
    { n: 8, text: 'Kuxi a tswala Nimbrodi; hi yena la sunguleke ku va ni matimba lamakulu emisaveni.' },
    { n: 9, text: 'A a ri muhloti la nga ni matimba lamakulu mahlweni ka Hosi; hikwalaho swi vuriwaka: Kukota Nimbrodi muhloti la nga ni matimba lamakulu mahlweni ka Hosi.' },
    { n: 10, text: 'Kusungula ka mfumo wa yena ku ve le Babele, Ereke, Akadi ni Kalne, etikweni ra Xinari.' },
    { n: 11, text: 'Ku sukela etikweni rero a ya le Asiriya, a aka muti wa Ninivha, Rehoboti-iri, Kala,' },
    { n: 12, text: 'ni Resene exikarhi ka Ninivha ni Kala; lowu i muti lowukulu.' },
    { n: 13, text: 'Mizrayimi a tswala Ludimi, Anamimi, Lehabimi, Naftuhimi,' },
    { n: 14, text: 'Patrusimi ni Kasluhimi (lomu Vafilista va humeke kona), ni Kaftorimi.' },
    { n: 15, text: 'Kanana a tswala Sidoni mativula ya yena, ni Heti,' },
    { n: 16, text: 'ni Vayebusi, Vaamori, Vagirgaxi,' },
    { n: 17, text: 'Vahivhi, Vaarki, Vasini,' },
    { n: 18, text: 'Varvhadi, Vasemari ni Vahamati; endzhaku tinxaka ta Vakanana ti hangalaka.' },
    { n: 19, text: 'Kutani ndzilakana wa Vakanana a wu ri ku sukela le Sidoni, loko u ya eGerara, ku ya fika le Gaza; loko u ya le Sodoma, Gomora, Adma ni Seboyimi, ku ya fika le Laxa.' },
    { n: 20, text: 'Lava i vana va Hama hi tinxaka ta vona, hi tindzimi ta vona, ematikweni ya vona, emifun\u2019wini ya vona.' },
    { n: 21, text: 'Xeme na yena u tswariwile vana, hosi ya vana hinkwavo va Eberu, makwavo wa Yafeta la nga nkulukumba.' },
    { n: 22, text: 'Vana va Xeme: Elama, Axuru, Arfaksadi, Ludi ni Aramu.' },
    { n: 23, text: 'Vana va Aramu: Uzi, Hulu, Getere ni Maxe.' },
    { n: 24, text: 'Arfaksadi a tswala Xala, Xala a tswala Eberu.' },
    { n: 25, text: 'Eberu u tswariwile vana vambirhi va xinuna; vito ra un\u2019wana a a ri Pelegi, hikuva emasikwini ya yena misava yi avanyisiwile; vito ra makwavo a a ri Yoktani.' },
    { n: 26, text: 'Yoktani a tswala Almodadi, Xelefe, Hasarmavhete, Yera,' },
    { n: 27, text: 'Hadorame, Uzale, Dikla,' },
    { n: 28, text: 'Obale, Abimayele, Xeba,' },
    { n: 29, text: 'Ofiri, Havhila ni Yobabe; hinkwavo lava a a ri vana va Yoktani.' },
    { n: 30, text: 'Kutsama ka vona a ku ri ku sukela le Mexa, loko u ya eSefara, ntsava va le vuxeni.' },
    { n: 31, text: 'Lava i vana va Xeme hi tinxaka ta vona, hi tindzimi ta vona, ematikweni ya vona, hi ku landza emifun\u2019wini ya vona.' },
    { n: 32, text: 'Leti i tinxaka ta vana va Nowa hi ku landza ku tswalana ka vona, emifun\u2019wini ya vona; kutani ku sukela eka lava, matiko va hangalakile ehenhla ka misava endzhaku ka ndhambi.' },
  ],
  11: [
    { n: 1, text: 'Kuni misava hinkwayo a yi ri ni ririmi rin\u2019we ni mavulavulelo man\u2019we.' },
    { n: 2, text: 'Kutani loko vanhu va famba hi tlhelo ra vuxeni, va kuma rivala etikweni ra Xinari, hiloko va tshama kona.' },
    { n: 3, text: 'Kuni va vurisanela va ku: Tanani, hi endla switini, hi swi txisa swinene hi ndzilo. Hiloko switini swi va mavele ya vona ematshan\u2019wini xa maribye, ni mbyaka yi va xitirho xa vona xo hanganisa.' },
    { n: 4, text: 'Kuni va ku: Tanani, hi tiakela muti ni xihondzo lexi tinhlohlorhi ya xona yi nga ta fika etilweni, leswaku hi tiendlela vito leri nga ta duma, hi nga tshuki hi hangalaka ehenhla ka misava hinkwayo.' },
    { n: 5, text: 'Kuni Hosi yi xika leswaku yi ta vona muti ni xihondzo lexi vana va vanhu va xi akaka.' },
    { n: 6, text: 'Kuni Hosi yi ku: Vonani, vanhu lava i van\u2019we naswona hinkwavo va ni ririmi rin\u2019we; kutani lexi i kusungula ntsena ka leswi va nga ta swi endla; sweswi ku nga ka ku nga vi na leswi va swi rhandzaka leswi va nga ta tsandzeka ku swi endla.' },
    { n: 7, text: 'Tanani, hi xika hi ya pfilunganya ririmi ra vona kwalaho, leswaku va nga ha twanani emavulavulelweni ya vona.' },
    { n: 8, text: 'Hiloko Hosi yi va hangalasa ku sukela kwalaho ehenhla ka misava hinkwayo, kutani va tshika ku aka muti wolowo.' },
    { n: 9, text: 'Hikwalaho vito ra wona ri thiyiweke Babele, hikuva kwalaho Hosi yi pfilunganyile ririmi ra misava hinkwayo; kutani ku sukela kwalaho Hosi yi va hangalasile ehenhla ka misava hinkwayo.' },
    { n: 10, text: 'Leti i tinxaka ta Xeme: Xeme a a ri ni malembe ya dzana loko a tswala Arfaksadi, endzhaku ka malembe mambirhi ndhambi yi hundzile.' },
    { n: 11, text: 'Xeme a hanya malembe ya ntlhanu wa madzana endzhaku ka loko a tswarile Arfaksadi, a tswala vana van\u2019wana va xinuna ni va xisati.' },
    { n: 12, text: 'Arfaksadi a hanya malembe ya makume manharhu ni ntlhanu, a tswala Xala.' },
    { n: 13, text: 'Arfaksadi a hanya malembe ya madzana mana ni manharhu endzhaku ka loko a tswarile Xala, a tswala vana van\u2019wana va xinuna ni va xisati.' },
    { n: 14, text: 'Xala a hanya malembe ya makume manharhu, a tswala Eberu.' },
    { n: 15, text: 'Xala a hanya malembe ya madzana mana ni manharhu endzhaku ka loko a tswarile Eberu, a tswala vana van\u2019wana va xinuna ni va xisati.' },
    { n: 16, text: 'Eberu a hanya malembe ya makume manharhu ni mune, a tswala Pelegi.' },
    { n: 17, text: 'Eberu a hanya malembe ya madzana mana ni makume manharhu endzhaku ka loko a tswarile Pelegi, a tswala vana van\u2019wana va xinuna ni va xisati.' },
    { n: 18, text: 'Pelegi a hanya malembe ya makume manharhu, a tswala Rehu.' },
    { n: 19, text: 'Pelegi a hanya malembe ya madzana mambirhi ni kaye endzhaku ka loko a tswarile Rehu, a tswala vana van\u2019wana va xinuna ni va xisati.' },
    { n: 20, text: 'Rehu a hanya malembe ya makume mambirhi ni khume na mambirhi, a tswala Serugi.' },
    { n: 21, text: 'Rehu a hanya malembe ya madzana mambirhi ni ntlhanu na mambirhi endzhaku ka loko a tswarile Serugi, a tswala vana van\u2019wana va xinuna ni va xisati.' },
    { n: 22, text: 'Serugi a hanya malembe ya makume manharhu, a tswala Nahori.' },
    { n: 23, text: 'Serugi a hanya malembe ya madzana mambirhi endzhaku ka loko a tswarile Nahori, a tswala vana van\u2019wana va xinuna ni va xisati.' },
    { n: 24, text: 'Nahori a hanya malembe ya makume mambirhi ni kaye, a tswala Tera.' },
    { n: 25, text: 'Nahori a hanya malembe ya dzana ni khume na kaye endzhaku ka loko a tswarile Tera, a tswala vana van\u2019wana va xinuna ni va xisati.' },
    { n: 26, text: 'Tera a hanya malembe ya makume nkombo, kutani a tswala Abrama, Nahori ni Harani.' },
    { n: 27, text: 'Leti i tinxaka ta Tera: Tera a tswala Abrama, Nahori ni Harani; kutani Harani a tswala Loti.' },
    { n: 28, text: 'Harani a fela emahlweni ka Tera tata wa yena, etikweni ra ku tswariwa ka yena, le Uru wa Vakhaldiya.' },
    { n: 29, text: 'Abrama ni Nahori va titeketela vavasati; vito ra wansati wa Abrama a a ri Sarayi, kutani vito ra wansati wa Nahori a a ri Milka, n\u2019wana wa Harani, tata wa Milka na Iska.' },
    { n: 30, text: 'Kambe Sarayi a a ri n\u2019umba; a a nga ri na n\u2019wana.' },
    { n: 31, text: 'Tera a teka Abrama n\u2019wana wa yena, ni Loti n\u2019wana wa Harani, ntukulu wa yena, ni Sarayi n\u2019wingi wa yena, wansati wa Abrama n\u2019wana wa yena; hiloko va huma swin\u2019we le Uru wa Vakhaldiya leswaku va ya etikweni ra Kanana; kambe loko va fika le Harani, va tshama kwalaho.' },
    { n: 32, text: 'Masiku hinkwaswo ya Tera ma ve malembe ya madzana mambirhi ni ntlhanu; kutani Tera a fela le Harani.' },
  ],
  12: [
    { n: 1, text: 'Kuni Hosi yi ku eka Abrama: Suka etikweni ra ka n\u2019wina, exikarhi ka maxaka ya wena, ni le ndyangwini wa tata wa wena, u ya etikweni leri ndzi nga ta ku komba rona.' },
    { n: 2, text: 'Ndzi ta ku endla tiko lerikulu, ndzi ku katekisa, ndzi kulisa vito ra wena; kutani u ta va nkateko.' },
    { n: 3, text: 'Ndzi ta katekisa lava va ku katekisaka, ni loyi a ku rhukanaka ndzi ta n\u2019wi rhukana; kutani tinxaka hinkwato ta misava ti ta katekisiwa ha wena.' },
    { n: 4, text: 'Hiloko Abrama a suka, hilaha Hosi xi n\u2019wi byeleke hakona; kutani Loti a famba na yena. Abrama a a ri ni malembe ya makume nkombo ni ntlhanu loko a suka le Harani.' },
    { n: 5, text: 'Abrama a teka Sarayi wansati wa yena, ni Loti n\u2019wana wa makwavo wa yena, ni rifuwo hinkwaro leri va ri hlengeleteleke, ni vutomi hinkwabyo lebyi va va vumbeke le Harani; hiloko va suka va ya etikweni ra Kanana, va fika etikweni rero.' },
    { n: 6, text: 'Abrama a tsemakanya tiko ku ya fika endhawini ya Sikeme, ku ya fika emutsandzeni wa More; emasikwini wolawo Vakanana a va tshama etikweni rero.' },
    { n: 7, text: 'Kuni Hosi yi humelela eka Abrama, yi ku: Ndzi ta nyika mbewu ya wena tiko leri. Kutani a akela Hosi alitari kwalaho, yona leyi yi n\u2019wi humeleleke.' },
    { n: 8, text: 'Ku sukela kwalaho a ya emugangeni wa le vuxeni bya Betele, a pacha tende ra yena, Betele ri ri hi tlhelo ra vuxeni, ni Ayi hi tlhelo ra vupela-dyambu; kutani a akela Hosi alitari kwalaho, a vitana vito ra Hosi.' },
    { n: 9, text: 'Kutani Abrama a ya mahlweni a famba, a tshinela hi tlhelo ra Negeve.' },
    { n: 10, text: 'Kambe ku va ni ndlala etikweni rero; hiloko Abrama a xika a ya le Egipta leswaku a ya luvela kwalaho, hikuva ndlala a yi ri yikulu etikweni rero.' },
    { n: 11, text: 'Kuni loko a fika kusuhi ni ku nghena le Egipta, a ku eka Sarayi wansati wa yena: Vonani, ndzi swi tiva leswaku u wansati la sasekeke swinene.' },
    { n: 12, text: 'Loko Vaegipta va ku vona, va ta ku: \u2018Loyi i wansati wa yena\u2019; kutani va ta ndzi dlaya, kambe wena va ta ku tshika u hanya.' },
    { n: 13, text: 'Ndzi kombela u ku u makwavo wa mina, leswaku ndzi khomiwa kahle hikwalaho ka wena, ni vutomi bya mina byi ponisiwa hikwalaho ka wena.' },
    { n: 14, text: 'Loko Abrama a nghena le Egipta, Vaegipta va vona wansati loyi leswaku u sasekile swinene.' },
    { n: 15, text: 'Tihosi ta Faro na tona ti n\u2019wi vona, ti n\u2019wi tlangela emahlweni ka Faro; hiloko wansati a yisiwa endlwini ya Faro.' },
    { n: 16, text: 'U n\u2019wi khome kahle Abrama hikwalaho ka yena; kutani a kuma tinyimpfu, ni tihomu, ni timbhongolo ta xinuna, ni malandza ya xinuna ni ya xisati, ni timbhongolo ta xisati, ni tikamela.' },
    { n: 17, text: 'Kambe Hosi yi ba Faro ni ndyangu wa yena hi makhombo lamakulu hikwalaho ka Sarayi, wansati wa Abrama.' },
    { n: 18, text: 'Hiloko Faro a vitana Abrama, a ku: I yini lexi u ndzi endleke xona? Ha yini u nga ndzi byelangiki leswaku loyi i wansati wa wena?' },
    { n: 19, text: 'Ha yini u te: \u2018I makwavo wa mina\u2019, ndzi kondza ndzi n\u2019wi teka a va wansati wa mina? Sweswi, loyi i wansati wa wena; n\u2019wi teke u famba!' },
    { n: 20, text: 'Kutani Faro a nyika vanhu va yena mileriso hikwalaho ka yena, va n\u2019wi fambisa, yena ni wansati wa yena, ni hinkwaswo leswi a a ri na swona.' },
  ],
  13: [
    { n: 1, text: 'Hiloko Abrama a suka le Egipta, a tlhandlukela le Negeve, yena ni wansati wa yena, ni hinkwaswo leswi a a ri na swona, na Loti a a ri na yena.' },
    { n: 2, text: 'Abrama a a fuwile swinene hi swifuwo, ni silivhere, ni nsuku.' },
    { n: 3, text: 'A famba hi tindlela ta yena ku sukela le Negeve ku ya fika le Betele, endhawini leyi tende ra yena a ri pachiwe kona kusunguleni, exikarhi ka Betele ni Ayi,' },
    { n: 4, text: 'endhawini ya alitari leyi a yi akeke kwalaho kusunguleni; kutani Abrama a khongela vito ra Hosi kwalaho.' },
    { n: 5, text: 'Na Loti loyi a a famba ni Abrama, a a ri ni tinyimpfu, ni tihomu, ni matende.' },
    { n: 6, text: 'Tiko ri nga ka ri nga va firi leswaku va tshama swin\u2019we, hikuva rifuwo ra vona a ri ri rikulu, hikwalaho a va nga koti ku tshama swin\u2019we.' },
    { n: 7, text: 'Kuni ku va ni ku herana exikarhi ka varisi va swifuwo swa Abrama ni varisi va swifuwo swa Loti; emasikwini wolawo Vakanana ni Vaperizi a va tshama etikweni rero.' },
    { n: 8, text: 'Kutani Abrama a ku eka Loti: Ndzi kombela ku nga vi na ku herana exikarhi ka mina na wena, ni le xikarhi ka varisi va mina ni varisi va wena, hikuva hi vamakwavo.' },
    { n: 9, text: 'Xana tiko hinkwaro a ri le mahlweni ka wena ke? Hambana na mina, ndzi kombela u endla tano; loko u ya hi tlhelo ra ximatsi, ndzi ta ya hi tlhelo ra xinene; loku u ya hi tlhelo ra xinene, ndzi ta ya hi tlhelo ra ximatsi.' },
    { n: 10, text: 'Loti a languta, a vona hinkwaro rivala ra Yordani, leswaku ri tale hi mati hinkwako-nako, emahlweni ka loko Hosi yi nga si herisa Sodoma ni Gomora, kukota ntanga wa Hosi, kukota tiko ra Egipta, loko u ya eSoara.' },
    { n: 11, text: 'Hiloko Loti a hlawula hinkwaro rivala ra Yordani; kutani Loti a famba hi tlhelo ra vuxeni; hiloko va hambana un\u2019wana ni un\u2019wana.' },
    { n: 12, text: 'Abrama a tshama etikweni ra Kanana, kutani Loti a tshama emitiyeni ya rivala, a pacha matende ya yena ku ya fika le Sodoma.' },
    { n: 13, text: 'Kambe vanhu va Sodoma a va bihile, va ri vadyohi lavakulu mahlweni ka Hosi.' },
    { n: 14, text: 'Kuni Hosi yi ku eka Abrama, endzhaku ka loko Loti a hambanile na yena: Languta sweswi, u languta ku sukela endhawini leyi u nga ka yona, hi tlhelo ra n\u2019walungu, ni ra wele-ehansi, ni ra vuxeni, ni ra vupela-dyambu;' },
    { n: 15, text: 'hikuva tiko hinkwaro leri u ri vonaka, ndzi ta ku nyika rona ni mbewu ya wena hilaha ku nga heriki.' },
    { n: 16, text: 'Ndzi ta endla mbewu ya wena yi tala kukota ntshuri wa misava; leswaku loko un\u2019wana a kota ku hlaya ntshuri wa misava, mbewu ya wena na yona yi ta hlayiwa.' },
    { n: 17, text: 'Pfuka, u famba-famba etikweni hi ku leha ka rona ni ku anama ka rona; hikuva ndzi ta ku nyika rona.' },
    { n: 18, text: 'Hiloko Abrama a fambisa matende ya yena, a ya tshama emutsandzeni wa Mamre, lowu nga le Hebroni, kutani a akela Hosi alitari kwalaho.' },
  ],
  14: [
    { n: 1, text: 'Kutani emasikwini ya Amrafeli, hosi ya Xinari, Ariyoko, hosi ya Elasara, Kedorlaomere, hosi ya Elama, ni Tidali, hosi ya matiko,' },
    { n: 2, text: 'va endla nyimpi ni Bera, hosi ya Sodoma, Birsa, hosi ya Gomora, Sinabu, hosi ya Adma, Semeberi, hosi ya Seboyimi, ni hosi ya Bela (yona leyi nga Soara).' },
    { n: 3, text: 'Hinkwavo lava va hlengeletana exinon\u2019wini xa Sidimi (loku nga Lwandle ra Munyu).' },
    { n: 4, text: 'Va tirhele Kedorlaomere malembe ya khume na mambirhi, kambe hi lembe ra vukhume na manharhu va n\u2019wi pfukela.' },
    { n: 5, text: 'Hi lembe ra vukhume na mune, Kedorlaomere ni tihosi leti a ti ri na yena va ta, va hlula Varefayimi eAsteroti-Karnayimi, ni Vasuzimi le Hamu, ni Vaemi erivaleni ra Kiriyatayimi,' },
    { n: 6, text: 'ni Vahori entsaveni ya vona ya Seiri, ku ya fika eEla-Parani, leri nga kusuhi ni mananga.' },
    { n: 7, text: 'Kutani va tlhela va ta eEni-Mispati (lowu nga Kadesi), va fika va herisa tiko hinkwaro ra Vaamaleke, na Vaamori lava a va tshama eHasasoni-Tamara.' },
    { n: 8, text: 'Hiloko hosi ya Sodoma, ni hosi ya Gomora, ni hosi ya Adma, ni hosi ya Seboyimi, ni hosi ya Bela (yona leyi nga Soara), va huma va hleka tinyimpi ta vona leswaku va lwa na vona exinon\u2019wini xa Sidimi;' },
    { n: 9, text: 'va lwa ni Kedorlaomere, hosi ya Elama, Tidali, hosi ya matiko, Amrafeli, hosi ya Xinari, ni Ariyoko, hosi ya Elasara; tihosi ta mune ti lwa ni ta ntlhanu.' },
    { n: 10, text: 'Kasi xinon\u2019wi xa Sidimi a xi tale hi migodi ya mbyaka; kutani loko tihosi ta Sodoma ni Gomora ti tsutsuma, ti wela kwalaho; kutani lava va saleke va tsutsumela etintsaveni.' },
    { n: 11, text: 'Tihosi ta mune ti teka rifuwo hinkwaro ra Sodoma ni Gomora, ni swakudya swa vona hinkwaswo, hiloko va famba.' },
    { n: 12, text: 'Va teka na Loti, n\u2019wana wa makwavo wa Abrama, loyi a a tshama le Sodoma, ni rifuwo ra yena, va famba.' },
    { n: 13, text: 'Kuni un\u2019we la balekeke a ta byela Abrama wa Muheberu; a a tshama kusuhi ni mitsandza ya Mamre wa Muamori, makwavo wa Exikoli ni wa Aneru; lava a va ri ni ntwanano na Abrama.' },
    { n: 14, text: 'Loko Abrama a twa leswaku makwavo u khomiwile, a hlomisa vanhu va yena lava averiweke emutini wa yena, lava tswariweke endlwini ya yena, va ri madzana manharhu ni khume na nhungu, a va landza ku ya fika le Dani.' },
    { n: 15, text: 'A avanyisa vanhu va yena, a lwa na vona nivusiku, yena ni malandza ya yena, a va hlula, a va landza ku ya fika le Hoba, leri nga hi tlhelo ra ximatsi ra Damasika.' },
    { n: 16, text: 'A vuyisa rifuwo hinkwaro, a vuyisa na Loti makwavo, ni rifuwo ra yena, ni vavasati, ni vanhu van\u2019wana hinkwavo.' },
    { n: 17, text: 'Loko a vunya hi ku hlula Kedorlaomere ni tihosi leti a ti ri na yena, hosi ya Sodoma yi huma yi ya n\u2019wi hlanganisa exinon\u2019wini xa Save (lexi nga Xinon\u2019wi xa Hosi).' },
    { n: 18, text: 'Kutani Melkisedeke, hosi ya Salema, a humesa vhinyo ni xinkwa; a a ri muprista wa Xikwembu lexi nga ehenhla-henhla.' },
    { n: 19, text: 'A n\u2019wi katekisa, a ku: A ku katekisiwe Abrama hi Xikwembu lexi nga ehenhla-henhla, Muendli wa tilo ni misava;' },
    { n: 20, text: 'naswona a ku dzunisiwe Xikwembu lexi nga ehenhla-henhla, lexi nyiketeke valala va wena emavokweni ya wena. Kutani Abrama a n\u2019wi nyika vukhume bya hinkwaswo.' },
    { n: 21, text: 'Kuni hosi ya Sodoma yi ku eka Abrama: Ndzi nyike vanhu, kambe rifuwo u tiendlela rona.' },
    { n: 22, text: 'Kambe Abrama a ku eka hosi ya Sodoma: Ndzi tlakusile voko ra mina eka Hosi, Xikwembu lexi nga ehenhla-henhla, Muendli wa tilo ni misava,' },
    { n: 23, text: 'leswaku ndzi nga ka ndzi nga teki nchumu na wun\u2019we wa leswi nga swa wena, hambi ku ri ncinga kumbe ngoti ya patu, leswaku u nga vuli u ku: \u2018Hi mina ndzi fuwiseke Abrama\u2019;' },
    { n: 24, text: 'ndzi nga teki nchumu, handle xa leswi vafana va swi dyeke, ni xiavelo xa vavanuna lava fambeke na mina: Aneru, Exikoli ni Mamre; lava va nga teka xiavelo xa vona.' },
  ],
  15: [
    { n: 1, text: 'Endzhaku ka swilo leswi, rito ra Hosi ri ta eka Abrama hi xivono, ri ku: U nga chavi, Abrama; hi mina xitlhangu xa wena, hakelo ya wena yi ta va yikulu swinene.' },
    { n: 2, text: 'Kambe Abrama a ku: Hosi Xikwembu, u ta ndzi nyika yini, leswi ndzi fambaka ndzi nga ri na n\u2019wana, kutani loyi a nga ta dya ndzhaka ya yindlu ya mina i Eliyezeri wa Damasika ke?' },
    { n: 3, text: 'Abrama a tlhela a ku: Vonani, a ndzi nyikanga mbewu; kutani, vona, nandza la tswariweke endlwini ya mina u ta va mudyi wa ndzhaka ya mina.' },
    { n: 4, text: 'Kutani, vonani, rito ra Hosi ri ta eka yena, ri ku: Loyi a nga ka a nga vi mudyi wa ndzhaka ya wena; kambe loyi a nga ta huma emilengeni ya wena hi yena a nga ta va mudyi wa ndzhaka ya wena.' },
    { n: 5, text: 'Yi n\u2019wi humesela handle, yi ku: Languta sweswi etilweni, u hlaya tinyeleti, loko u ri ni matimba yo ti hlaya. Yi ku eka yena: Yi ta va tano mbewu ya wena.' },
    { n: 6, text: 'A pfumela eka Hosi, kutani yi swi hlayela eka yena ku va ku lulama.' },
    { n: 7, text: 'Yi ku eka yena: Hi mina Hosi leyi ku humeseke le Uru wa Vakhaldiya, leswaku ndzi ku nyika tiko leri ri va ndzhaka ya wena.' },
    { n: 8, text: 'Kambe a ku: Hosi Xikwembu, ndzi ta tiva njhani leswaku ndzi ta ri dya ndzhaka ke?' },
    { n: 9, text: 'Yi ku eka yena: Ndzi tekela mathokazi ya malembe manharhu, ni mbuti ya malembe manharhu, ni nyimpfu ya xinuna ya malembe manharhu, ni rati, ni xituvana.' },
    { n: 10, text: 'A yi tekela hinkwaswo leswi, a swi avanyisa hi le xikarhi, a veka xiphemu xinun\u2019wana a langutana ni xinun\u2019wana; kambe tinyanyana a nga ti avanyisanga.' },
    { n: 11, text: 'Loko tinyanyana leti dlayaka swifuwo ti xikela ehenhla ka mintsumbu, Abrama a ti hlongola.' },
    { n: 12, text: 'Kutana loko dyambu ri lava ku pela, ku rhurhumela lokukulu ku wela ehenhla ka Abrama; kutani, vonani, munyama lowukulu ni lowu chavisaka wu n\u2019wi wela ehenhla.' },
    { n: 13, text: 'Kutani Hosi yi ku eka Abrama: Tiva swinene leswaku mbewu ya wena yi ta va vahluri etikweni leri nga riki ra vona, kutani va ta va tirhela, va va xanisa malembe ya madzana mune.' },
    { n: 14, text: 'Kambe tiko leri va nga ta ri tirhela, ndzi ta ri yavanyisa na mina; endzhaku ka swona va ta huma va ri ni rifuwo lerikulu.' },
    { n: 15, text: 'Kuni wena u ta ya eka vatata wa wena hi ku rhula; u ta lahliwa u dyuhale swinene.' },
    { n: 16, text: 'Kambe hi xitukulwana xa vumune va ta vuyela kwala, hikuva vuhomboloki bya Vaamori a byi nga si fika eku heleni.' },
    { n: 17, text: 'Kutani loko dyambu ri perile, ku va ni munyama lowukulu, kutani, vonani, paipi leri mbyaka ni ririmi ra ndzilo swi tsemakanya exikarhi ka swiphemu swoleswo.' },
    { n: 18, text: 'Hi siku rero Hosi yi endla ntwanano ni Abrama, yi ku: Ndzi nyikile mbewu ya wena tiko leri, ku sukela enambyeni wa Egipta ku ya fika enambyeni lowukulu, lowu nga nambu wa Yufrata;' },
    { n: 19, text: 'Vakeni, Vakenizi, Vakadmoni,' },
    { n: 20, text: 'Vaheti, Vaperizi, Varefayimi,' },
    { n: 21, text: 'Vaamori, Vakanana, Vagirgaxi ni Vayebusi.' },
  ],
  16: [
    { n: 1, text: 'Kasi Sarayi, wansati wa Abrama, a a nga n\u2019wi tswalelanga vana; kambe a a ri ni nandza wa xisati wa Muegipta, loyi vito ra yena a a ri Agara.' },
    { n: 2, text: 'Kuni Sarayi a ku eka Abrama: Sweswi, vona, Hosi yi ndzi siverile ku tswala; ndzi kombela u nghena eka nandza wa mina wa xisati; kumbexana ndzi nga kuma vana ha yena. Kutani Abrama a yingisa rito ra Sarayi.' },
    { n: 3, text: 'Endzhaku ka loko Abrama a tshamile malembe ya khume etikweni ra Kanana, Sarayi, wansati wa Abrama, a teka Agara wa Muegipta, nandza wa yena wa xisati, a n\u2019wi nyika Abrama nuna wa yena ku va wansati wa yena.' },
    { n: 4, text: 'A nghena eka Agara, hiloko a tika; kutani loko a vona leswaku u tikile, n\u2019wini wa yena a sandziwa emonlhweni ka yena.' },
    { n: 5, text: 'Kutani Sarayi a ku eka Abrama: Ku onha leri ndzi endleriweke rona a ku ve ehenhla ka wena; ndzi nyikile nandza wa mina wa xisati exifuveni xa wena; kutani loko a vona leswaku u tikile, ndzi sandziwile emonlhweni ka yena; Hosi a yi yavanyise exikarhi ka mina na wena.' },
    { n: 6, text: 'Kambe Abrama a ku eka Sarayi: Vona, nandza wa wena u le vokweni ra wena; n\u2019wi endle leswi ku tsakisaka mahlweni ka wena. Hiloko Sarayi a n\u2019wi xanisa, kutani Agara a n\u2019wi balekela.' },
    { n: 7, text: 'Ntsumi ya Hosi yi n\u2019wi kuma ekusuhi ni xihlovo xa mati emananga, ekusuhi ni xihlovo lexi nga endleleni ya ya le Suri.' },
    { n: 8, text: 'Yi ku: Agara, nandza wa Sarayi, u huma kwihi, u ya kwihi ke? A ku: Ndzi balekela Sarayi n\u2019wini wa mina.' },
    { n: 9, text: 'Ntsumi ya Hosi yi ku eka yena: Vuyela eka n\u2019wini wa wena, u tiyisela ehansi ka mavoko ya yena.' },
    { n: 10, text: 'Ntsumi ya Hosi yi tlhela yi ku eka yena: Ndzi ta tswalisa mbewu ya wena swinene, lerova yi nga ka yi nga hlayiwi hikwalaho ka vutalo.' },
    { n: 11, text: 'Ntsumi ya Hosi yi ku eka yena: Vona, u tikile, u ta tswala n\u2019wana wa xinuna, u ta n\u2019wi thya vito ra Ismayele; hikuva Hosi yi twile ku xaniseka ka wena.' },
    { n: 12, text: 'Yena u ta va munhu wa nhova; voko ra yena ri ta lwa ni hinkwavo, ni voko ra hinkwavo ri lwa na yena; u ta tshama emahlweni ka vamakwavo hinkwavo.' },
    { n: 13, text: 'A thya vito ra Hosi leyi vulavuleke na yena a ku: \u2018Hi wena Xikwembu lexi vonaka\u2019; hikuva a ku: \u2018Xana ndzi vonile kwala endzhaku ka loyi a ndzi vonaka ke?\u2019' },
    { n: 14, text: 'Hikwalaho xihlovo xero xi thiyiweke vito ra Beere-Lahayi-Royi; xi le xikarhi ka Kadesi ni Beredi.' },
    { n: 15, text: 'Agara a tswalela Abrama n\u2019wana wa xinuna; kutani Abrama a thya n\u2019wana wa yena loyi Agara a n\u2019wi tswaleke vito ra Ismayele.' },
    { n: 16, text: 'Abrama a a ri ni malembe ya makume nhungu ni tsevu loko Agara a tswalela Abrama Ismayele.' },
  ],

  17: [
    { n: 1, text: 'Loko Abrama a a ri ni malembe ya makume kaye ni kaye, Hosi yi humelela eka Abrama, yi ku eka yena: Hi mina Xikwembu xa Matimba Hinkwaswo; famba mahlweni ka mina, u lulama.' },
    { n: 2, text: 'Ndzi ta simeka ntwanano wa mina exikarhi ka mina na wena, ndzi ta ku tswalisa swinene-nene.' },
    { n: 3, text: 'Abrama a tiandlaleka hi xikandza ehansi; kutani Xikwembu xi vulavula na yena, xi ku:' },
    { n: 4, text: 'Kuni mina, vona, ntwanano wa mina wu na wena, u ta va tata wa tinxaka to tala swinene.' },
    { n: 5, text: 'Vito ra wena ri nga ka ri nga ha vuriwi Abrama, kambe vito ra wena ku ta va Abrahama; hikuva ndzi ku endle tata wa tinxaka to tala.' },
    { n: 6, text: 'Ndzi ta ku tswalisa swinene-nene, ndzi ta ku endla tinxaka, ni tihosi ti ta huma eka wena.' },
    { n: 7, text: 'Ndzi ta simeka ntwanano wa mina exikarhi ka mina na wena ni mbewu ya wena endzhaku ka wena, eka tinxaka hinkwato ta vona, ku va ntwanano lowu nga heriki, ku va Xikwembu xa wena ni xa mbewu ya wena endzhaku ka wena.' },
    { n: 8, text: 'Ndzi ta ku nyika tiko leri u luvelaka eka rona, tiko hinkwaro ra Kanana, ri va ndzhaka leyi nga heriki; kutani ndzi ta va Xikwembu xa vona.' },
    { n: 9, text: 'Xikwembu xi ku eka Abrahama: Kutani wena u ta hlayisa ntwanano wa mina, wena ni mbewu ya wena endzhaku ka wena, eka tinxaka ta vona.' },
    { n: 10, text: 'Leyi i ntwanano wa mina lowu mi nga ta wu hlayisa, exikarhi ka mina na n\u2019wina ni mbewu ya wena endzhaku ka wena: Wanuna un\u2019wana ni un\u2019wana exikarhi ka n\u2019wina u ta tsemiwa nsuvu.' },
    { n: 11, text: 'Mi ta tsema nyama ya nsuvu wa n\u2019wina, kutani swi ta va xikombiso xa ntwanano exikarhi ka mina na n\u2019wina.' },
    { n: 12, text: 'N\u2019wana wa masiku ya nhungu exikarhi ka n\u2019wina u ta tsemiwa nsuvu, wanuna un\u2019wana ni un\u2019wana eka tinxaka hinkwato ta n\u2019wina, loyi a tswariweke endlwini kumbe loyi a xaviweke hi mali eka muluveri loyi a nga riki wa mbewu ya wena.' },
    { n: 13, text: 'Loyi a tswariweke endlwini ya wena ni loyi a xaviweke hi mali ya wena u ta tsemiwa nsuvu; kutani ntwanano wa mina wu ta va enyameni ya n\u2019wina wu va ntwanano lowu nga heriki.' },
    { n: 14, text: 'Kuni wanuna la nga tsemiwangiki nsuvu, loyi a nga tsemiwangiki nyama ya nsuvu wa yena, moya wolowo u ta herisiwa exikarhi ka vanhu va yena; u tlurile ntwanano wa mina.' },
    { n: 15, text: 'Xikwembu xi tlhela xi ku eka Abrahama: Sarayi wansati wa wena u nga ha n\u2019wi vitani Sarayi, hikuva vito ra yena ku ta va Sara.' },
    { n: 16, text: 'Ndzi ta n\u2019wi katekisa, ndzi ku nyika n\u2019wana wa xinuna ha yena; ndzi ta n\u2019wi katekisa, a va tinxaka; tihosi ta vanhu ti ta huma eka yena.' },
    { n: 17, text: 'Hiloko Abrahama a tiandlaleka hi xikandza ehansi, a hleka, a ku embilu ya yona: Xana n\u2019wana a nga tswariwa eka munhu la nga ni malembe ya dzana ke? Kutani Sara, xana a nga tswala na a ri ni malembe ya makume kaye ke?' },
    { n: 18, text: 'Kutani Abrahama a ku eka Xikwembu: A ku hanyike Ismayele mahlweni ka wena!' },
    { n: 19, text: 'Kambe Xikwembu xi ku: Sara wansati wa wena u ta ku tswalela n\u2019wana wa xinuna hakunene, u ta n\u2019wi thya vito ra Isaka; ndzi ta simeka ntwanano wa mina na yena wu va ntwanano lowu nga heriki eka mbewu ya yena endzhaku ka yena.' },
    { n: 20, text: 'Kuni hi tlhelo ra Ismayele ndzi ku twile; vona, ndzi n\u2019wi katekasile, ndzi ta n\u2019wi tswalisa, ndzi n\u2019wi andzisa swinene; u ta tswala tihosi ta khume na timbeu, ndzi ta n\u2019wi endla tiko lerikulu.' },
    { n: 21, text: 'Kambe ntwanano wa mina ndzi ta wu simeka na Isaka, loyi Sara a nga ta ku tswalela yena hi nkarhi lowu vekiweke eka lembe leri taka.' },
    { n: 22, text: 'Loko xi herise ku vulavula na yena, Xikwembu xi tlhandluka xi suka eka Abrahama.' },
    { n: 23, text: 'Abrahama a teka Ismayele n\u2019wana wa yena, ni hinkwavo lava tswariweke endlwini ya yena, ni hinkwavo lava xaviweke hi mali ya yena, wanuna un\u2019wana ni un\u2019wana exikarhi ka vanhu va yindlu ya Abrahama, a va tsema nsuvu hi siku rero hakunene, hilaha Xikwembu xi n\u2019wi byeleke hakona.' },
    { n: 24, text: 'Abrahama a a ri ni malembe ya makume kaye ni kaye loko a tsemiwa nsuvu.' },
    { n: 25, text: 'Ismayele n\u2019wana wa yena a a ri ni malembe ya khume na manharhu loko a tsemiwa nsuvu.' },
    { n: 26, text: 'Hi siku rero hakunene Abrahama a tsemiwa nsuvu swin\u2019we ni Ismayele n\u2019wana wa yena.' },
    { n: 27, text: 'Ni vavanuna hinkwavo va yindlu ya yena, lava tswariweke endlwini ni lava xaviweke hi mali eka muluveri, va tsemiwa nsuvu na yena.' },
  ],
  18: [
    { n: 1, text: 'Hosi yi humelela eka yena emutsandzeni wa Mamre, loko a tshamile enyangweni ya tende hi nkarhi wa ku hisa ka dyambu.' },
    { n: 2, text: 'A tlakusa mahlo ya yena a languta, kutani, vonani, ku na vavanuna vanharhu va yime kusuhi na yena; loko a va vona, a tsutsuma ku suka enyangweni ya tende leswaku a ya va hlanganisa, a nkhinsama ehansi,' },
    { n: 3, text: 'a ku: Hosi ya mina, ndzi kombela u ku, loko ndzi kumile tintswalo emonlhweni ka wena, u nga hundzi u nga yimanga eka nandza wa wena.' },
    { n: 4, text: 'A ku tisiwe mati matsongo, mi hlamba milenge ya n\u2019wina, mi wisa ehansi ka ntsandza;' },
    { n: 5, text: 'ndzi ta mi tekela xiphemu xa xinkwa, mi tiyisa mbilu ya n\u2019wina; endzhaku ka swona mi nga hundza, hikuva mi fikele nandza wa n\u2019wina. Hiloko va ku: Endla hilaha u vuleke hakona.' },
    { n: 6, text: 'Abrahama a hatlisela etendeni eka Sara, a ku: Hatlisa, teka swipimo swinharhu swa mavele layo saseka, u fula mavele, u endla makeke.' },
    { n: 7, text: 'Abrahama a tsutsumela exifuveni, a teka rhole lero olova ni lero saseka, a n\u2019wi nyika nandza, loyi a hatliseke ku n\u2019wi lulamisa.' },
    { n: 8, text: 'A teka botere, ni ntswamba, ni rhole leri a ri lulamiseke, a swi veka mahlweni ka vona; a yima kusuhi na vona ehansi ka ntsandza loko va karhi va dya.' },
    { n: 9, text: 'Hiloko va ku eka yena: U kwihi Sara wansati wa wena? A ku: O le tendeni.' },
    { n: 10, text: 'Kuni un\u2019we a ku: Ndzi ta vuyela eka wena hakunene hi nkarhi lowu swi tekelelaka ha wona; kutani, vona, Sara wansati wa wena u ta va ni n\u2019wana wa xinuna. Sara a a ri karhi a yingisela enyangweni ya tende, leyi a yi ri endzhaku ka yena.' },
    { n: 11, text: 'Kasi Abrahama ni Sara a va dyuhele swinene; Sara a a tshike ku tswala hi mukhuva wa vavasati.' },
    { n: 12, text: 'Hikwalaho Sara a hleka embilu ya yena, a ku: Endzhaku ka loko ndzi dyuhele, xana ndzi ta va ni ku tsaka ke? Ni n\u2019wini wa mina u dyuhele na yena.' },
    { n: 13, text: 'Kuni Hosi yi ku eka Abrahama: Ha yini Sara a hlekeke, a ku: \u2018Xana ndzi ta tswala n\u2019wana hakunene, kasi ndzi dyuhele ke?\u2019' },
    { n: 14, text: 'Xana ku ni nchumu lowu nga rharhaka Hosi ke? Hi nkarhi lowu vekiweke ndzi ta vuyela eka wena, hi nkarhi lowu swi tekelelaka ha wona, kutani Sara u ta va ni n\u2019wana wa xinuna.' },
    { n: 15, text: 'Kambe Sara a ala, a ku: A ndzi hlekanga; hikuva a a chavile. Kambe Hosi yi ku: Ee, u hlekile.' },
    { n: 16, text: 'Hiloko vavanuna lava va suka kwalaho, va languta hi tlhelo ra Sodoma; kutani Abrahama a famba na vona leswaku a ya va heleketa.' },
    { n: 17, text: 'Kuni Hosi yi ku: Xana ndzi ta n\u2019wi fihlela Abrahama leswi ndzi lavaka ku swi endla ke?' },
    { n: 18, text: 'Leswi Abrahama a nga ta va tiko lerikulu ni ra matimba hakunene, ni matiko hinkwato ta misava ti ta katekisiwa ha yena ke?' },
    { n: 19, text: 'Hikuva ndzi n\u2019wi hlawurile, leswaku a ta lerisa vana va yena ni ndyangu wa yena endzhaku ka yena, va hlayisa ndlela xa Hosi hi ku endla ku lulama ni ku avanyisa loku kene; leswaku Hosi yi tisa ehenhla ka Abrahama leswi yi vulavuleke swona hikwalaho ka yena.' },
    { n: 20, text: 'Kutani Hosi yi ku: Leswi xivilelo xa Sodoma ni Gomora xi nga xikulu swinene, ni xidyoho xa vona xi tika swinene,' },
    { n: 21, text: 'ndzi ta xika sweswi, ndzi ya vona loko va endle hi ku helela hi ku landza xivilelo lexi fikeke eka mina; loko swi nga ri tano, ndzi ta swi tiva.' },
    { n: 22, text: 'Hiloko vavanuna lava va ndzuluka kwalaho, va ya hi tlhelo ra Sodoma; kambe Abrahama a a ha yimile mahlweni ka Hosi.' },
    { n: 23, text: 'Abrahama a tshinela kusuhi, a ku: Xana u ta herisa la lulameke swin\u2019we ni la hombolokeke ke?' },
    { n: 24, text: 'Kumbexana ku ni vanhu va makume ntlhanu lava lulameke endzeni ka muti; xana u ta herisa hakunene, u nga tshiki ndhawu yoleswo hikwalaho ka vanhu va makume ntlhanu lava lulameke lava nga endzeni ka yona ke?' },
    { n: 25, text: 'Ku nga va kule na wena ku endla hi mukhuva wolowo, ku dlaya la lulameke swin\u2019we ni la hombolokeke, lerova la lulameke a fana ni la hombolokeke; ku nga va kule na wena! Xana Muavanyisi wa misava hinkwayo a nga ka a nga endli leswi lulameke ke?' },
    { n: 26, text: 'Kuni Hosi yi ku: Loko ndzi kuma le Sodoma vanhu va makume ntlhanu lava lulameke endzeni ka muti, ndzi ta tshika ndhawu hinkwayo hikwalaho ka vona.' },
    { n: 27, text: 'Abrahama a hlamula, a ku: Vona sweswi, ndzi tiyisile ku vulavula ni Hosi, mina loyi ndzi nga ntshuri ni nkuma ntsena;' },
    { n: 28, text: 'Kumbexana eka lava va makume ntlhanu lava lulameke ku ta pfumaleka vanhu va ntlhanu; xana u ta herisa muti hinkwaro hikwalaho ka vanhu lava va ntlhanu ke? Yi ku: Ndzi nga ka ndzi nga wu herisi loko ndzi kuma makume mana ni ntlhanu kwalaho.' },
    { n: 29, text: 'A tlhela a vulavula na yona, a ku: Kumbexana ku ta kumiwa makume mana kwalaho. Yi ku: Ndzi nga ka ndzi nga swi endli hikwalaho ka lava va makume mana.' },
    { n: 30, text: 'A ku: Ndzi kombela Hosi yi nga karixi, ndzi ta vulavula: Kumbexana ku ta kumiwa makume manharhu kwalaho. Yi ku: Ndzi nga ka ndzi nga swi endli loko ndzi kuma makume manharhu kwalaho.' },
    { n: 31, text: 'A ku: Vona sweswi, ndzi tiyisile ku vulavula ni Hosi: Kumbexana ku ta kumiwa makume mambirhi kwalaho. Yi ku: Ndzi nga ka ndzi nga wu herisi hikwalaho ka lava va makume mambirhi.' },
    { n: 32, text: 'A ku: Ndzi kombela Hosi yi nga karixi, ndzi ta vulavula ntsena nkarhi lowu wa vutano: Kumbexana ku ta kumiwa va khume kwalaho. Yi ku: Ndzi nga ka ndzi nga wu herisi hikwalaho ka lava va khume.' },
    { n: 33, text: 'Kuni Hosi yi famba loko yi herise ku vulavula ni Abrahama; kutani Abrahama a vuyela endhawini ya yena.' },
  ],
  19: [
    { n: 1, text: 'Kuni tintsumi letiyambirhi ti fika le Sodoma hi nkarhi wa madyambu; Loti a a tshamile enyangweni ya Sodoma; loko Loti a ti vona, a pfuka leswaku a ya ti hlanganisa, a nkhinsama hi xikandza ehansi,' },
    { n: 2, text: 'a ku: Vonani sweswi, tihosi ta mina, ndzi kombela mi nghena endlwini ya nandza wa n\u2019wina, mi etlela, mi hlamba milenge ya n\u2019wina; endzhaku ka swona mi ta pfuka nimpundzu, mi famba endleleni ya n\u2019wina. Ti ku: Ine, hi ta etlela erivaleni mbyana.' },
    { n: 3, text: 'Kambe a ti sindzisa swinene; hiloko ti pambuka ti ya eka yena, ti nghena endlwini ya yena; a ti endlela nkhuvo, a ti swekela makeke lama nga riki na mbyaka, hiloko ti dya.' },
    { n: 4, text: 'Kambe ti nga si etlela, vavanuna va muti, vavanuna va Sodoma, va rhendzela yindlu, ku sukela eka lavatsongo ku ya fika eka lavakulu, vanhu hinkwavo va miganga hinkwayo;' },
    { n: 5, text: 'va vitana Loti, va ku eka yena: Va kwihi vavanuna lava va fikeke eka wena nivusiku ke? Va humesele eka hina leswaku hi va tiva.' },
    { n: 6, text: 'Hiloko Loti a humela eka vona enyangweni, a pfala nyangwa endzhaku ka yena,' },
    { n: 7, text: 'a ku: Ndzi kombela vamakwerhu, mi nga endli vuhomboloki byo tano.' },
    { n: 8, text: 'Vonani sweswi, ndzi ni vana vambirhi va vanhwanyana lava nga tivangiki wanuna; ndzi kombela ndzi mi humesela vona, mi va endla leswi nga saseka emonlhweni ka n\u2019wina; ntsena vavanuna lava mi nga va endli nchumu, hikuva va nghene ehansi ka ntsandza wa lwangu ra mina.' },
    { n: 9, text: 'Kambe va ku: Suka kwalaho! Va ku: Loyi u tile ku va muluveri ntsena, kutani sweswi u lava ku tiendla muavanyisi! Sweswi hi ta ku endla swo biha swinene ku tlula vona. Va sindzisa Loti swinene, va tshinela leswaku va tshova nyangwa.' },
    { n: 10, text: 'Kambe vavanuna lava va tshambuluta mavoko va nghenisa Loti endlwini eka vona, va pfala nyangwa.' },
    { n: 11, text: 'Kutani va ba vavanuna lava a va ri enyangweni ya yindlu hi vubofu, ku sukela eka lavatsongo ku ya fika eka lavakulu, lerova va karhala hi ku lava nyangwa.' },
    { n: 12, text: 'Kuni vavanuna lava va ku eka Loti: Xana u ni van\u2019wana kwala ke? Mukon\u2019wana, ni vana va wena va xinuna, ni vana va wena va vanhwanyana, ni hinkwavo lava u nga na vona emutini, va humese endhawini leyi;' },
    { n: 13, text: 'hikuva hi ta herisa ndhawu leyi, leswi xivilelo xa yona xi nga xikulu mahlweni ka Hosi; kutani Hosi yi hi rhumile ku yi herisa.' },
    { n: 14, text: 'Hiloko Loti a huma, a ya vulavula ni vakon\u2019wana va yena, lava a va ta teka vana va yena va vanhwanyana, a ku: Pfukani, mi huma endhawini leyi, hikuva Hosi yi ta herisa muti lowu. Kambe swi tikile mahlweni ka vakon\u2019wana va yena kukota loyi a tlangaka.' },
    { n: 15, text: 'Loko ripona ri humelela, tintsumi ti sindzisa Loti, ti ku: Pfuka, teka wansati wa wena ni vana va wena vambirhi va vanhwanyana lava va nga kwala, leswaku u nga herisiwi evuhombolokini bya muti lowu.' },
    { n: 16, text: 'Kambe a a hlwela; hiloko vavanuna va khoma voko ra yena, ni voko ra wansati wa yena, ni mavoko ya vana va yena vambirhi va vanhwanyana, hi ku landza tintswalo ta Hosi eka yena; va n\u2019wi humesa, va n\u2019wi veka handle xa muti.' },
    { n: 17, text: 'Loko va va humesele handle, un\u2019we a ku: Tsutsuma u ponisa vutomi bya wena! U nga languti ndzhaku, u nga yimi ndhawu na yimbirhi erivaleni; tsutsumela etintsaveni leswaku u nga herisiwi!' },
    { n: 18, text: 'Kambe Loti a ku eka vona: Ndzi kombela ku nga vi tano, tihosi ta mina!' },
    { n: 19, text: 'Vona sweswi, nandza wa wena u kumile tintswalo mahlweni ka wena, u kurisile tintswalo ta wena leti u ndzi endleleke tona hi ku ponisa vutomi bya mina; kambe mina ndzi nga ka ndzi nga koti ku tsutsumela etintsaveni, hikuva khombo ri nga ndzi fikeleila kutani ndzi fa.' },
    { n: 20, text: 'Vona sweswi, muti lowu wu kusuhi leswaku ndzi tsutsumela kona, i wutsongo swinene; ndzi kombela u ndzi tshika ndzi tsutsumela kona (xana a hi wutsongo ke?), kutani vutomi bya mina vuyi hanya.' },
    { n: 21, text: 'Yi ku eka yena: Vona, ndzi ku yingisile na le ka rito leri, ndzi nga ka ndzi nga herisi muti lowu u vulavuleke ha wona.' },
    { n: 22, text: 'Hatlisa, u tsutsumela kona, hikuva ndzi nga ka ndzi nga endli nchumu ku fikela loko u nghena kona. Hikwalaho vito ra muti lowu ri thiyiweke Soara.' },
    { n: 23, text: 'Dyambu a ri humile ehenhla ka misava loko Loti a nghena le Soara.' },
    { n: 24, text: 'Kuni Hosi yi nisa ehenhla ka Sodoma ni Gomora mbyaka ni ndzilo lowu humaka eka Hosi etilweni;' },
    { n: 25, text: 'yi herisa miti yoleswo, ni rivala hinkwaro, ni vanhu hinkwavo va miti, ni swimilana swa misava.' },
    { n: 26, text: 'Kambe wansati wa Loti a languta ndzhaku ka yena, hiloko a hundzuka xihondzo xa munyu.' },
    { n: 27, text: 'Abrahama a pfuka nimpundzu swinene, a ya endhawini leyi a a yimile mahlweni ka Hosi kona;' },
    { n: 28, text: 'a languta hi tlhelo ra Sodoma ni Gomora, ni tiko hinkwaro ra rivala, a languta, kutani, vonani, musi wa tiko a wu tlhandluka kukota musi wa mfutho.' },
    { n: 29, text: 'Kuni loko Xikwembu xi herisa miti ya rivala, Xikwembu xi tsundzuka Abrahama, xi humesa Loti exikarhi ka ku herisa, loko xi herisa miti leyi Loti a a tshama eka yona.' },
    { n: 30, text: 'Loti a suka le Soara, a ya tshama etintsaveni, ni vana va yena vambirhi va vanhwanyana na yena, hikuva a a chava ku tshama le Soara; a tshama ebaku, yena ni vana va yena vambirhi va vanhwanyana.' },
    { n: 31, text: 'Kutani lontsongo a ku eka lontsongo-ntsongo: Tata wa hina u dyuhele, kutani a ku na wanuna etikweni la nga nghenaka eka hina hi ku landza mukhuva wa misava hinkwayo.' },
    { n: 32, text: 'Tana, hi nwisa tata wa hina vhinyo, hi etlela na yena, leswaku hi ta hlayisa mbewu ya tata wa hina.' },
    { n: 33, text: 'Va nwisa tata wa vona vhinyo hi vusiku byero; hiloko lontsongo a nghena, a etlela ni tata wa yena; kambe yena a nga tivanga loko a tiandlaleka kumbe loko a pfuka.' },
    { n: 34, text: 'Hi siku leri landzelaka, lontsongo a ku eka lontsongo-ntsongo: Vona, ndzi etlele ni tata wa mina nivusiku bya tolo; a hi n\u2019wi nwiseni vhinyo na nivusiku leri, kutani wena u nghena, u etlela na yena, leswaku hi ta hlayisa mbewu ya tata wa hina.' },
    { n: 35, text: 'Va nwisa tata wa vona vhinyo na nivusiku rero; hiloko lontsongo-ntsongo a pfuka, a etlela na yena; kambe yena a nga tivanga loko a tiandlaleka kumbe loko a pfuka.' },
    { n: 36, text: 'Hiloko vana vambirhi va vanhwanyana va Loti va tika hi tata wa vona.' },
    { n: 37, text: 'Lontsongo a tswala n\u2019wana wa xinuna, a n\u2019wi thya vito ra Mowabu; hi yena tata wa Vamowabu va namuntlha.' },
    { n: 38, text: 'Ni lontsongo-ntsongo na yena u tswarile n\u2019wana wa xinuna, a n\u2019wi thya vito ra Ben-Ami; hi yena tata wa vana va Amoni va namuntlha.' },
  ],
20: [
    { n: 1, text: 'Abrahama a suka kwalaho, a ya etikweni ra le Dzongeni, a tshama exikarhi ka Kadesi ni Suru, a luvela le Gerari.' },
    { n: 2, text: 'Abrahama a vula leswi hikwalaho ka Sara wansati wa yena: I makwerhu wa xisati. Hiloko Abimeleke, hosi ya le Gerari, a rhumela vanhu, a teka Sara.' },
    { n: 3, text: 'Kambe Xikwembu xi fika eka Abimeleke hi norho nivusiku, xi ku eka yena: Vona, u munhu la feke hikwalaho ka wansati loyi u n\u2019wi tekeke; hikuva i nsati wa wanuna.' },
    { n: 4, text: 'Kambe Abimeleke a a nga si n\u2019wi tshinela; hiloko a ku: Hosi, xana u ta dlaya ni tiko leri lulameke ke?' },
    { n: 5, text: 'Xana yena a nga ndzi byelanga a ku: \u2018I makwerhu wa xisati\u2019 ke? Ni wansati na yena u tivulerile a ku: \u2018I makwerhu wa xinuna.\u2019 Ndzi endle leswi hi mbilu leyo lulama ni hi mavoko lama tengereke.' },
    { n: 6, text: 'Xikwembu xi ku eka yena hi norho: Ee, ndzi swi tivile leswaku u swi endle hi mbilu leyo lulama; na mina ndzi ku sivile ku dyohela mina; hikwalaho a ndzi ku pfumelelanga ku n\u2019wi thandzha.' },
    { n: 7, text: 'Sweswi vuyisa nsati wa wanuna loyi; hikuva i muprofeta, u ta ku khongelela kutani u ta hanya; kambe loko u nga n\u2019wi vuyisi, tiva leswaku u ta fa hakunene, wena ni hinkwavo lava nga va wena.' },
    { n: 8, text: 'Abimeleke a pfuka nimpundzu swinene, a vitana malandza ya yena hinkwato, a vula timhaka leti hinkwato etindleveni ta vona; hiloko vavanuna lava va chava swinene.' },
    { n: 9, text: 'Hiloko Abimeleke a vitana Abrahama, a ku eka yena: I ncini lexi u hi endleleke xona ke? Ndzi ku dyohele mfanelo muni, lerova u tisa ehenhla ka mina ni le henhla ka mfumo wa mina xidyoho lexikulu xongasi ke? U ndzi endlele swilo leswi nga fanelangiki ku endliwa.' },
    { n: 10, text: 'Abimeleke a ku eka Abrahama: U vone ncini leswaku u endla mhaka leyi ke?' },
    { n: 11, text: 'Abrahama a ku: Hikuva ndzi te: Hakunene ku chava Xikwembu a ku kona endhawini leyi, kutani va ta ndzi dlaya hikwalaho ka wansati wa mina.' },
    { n: 12, text: 'Kambe kunene i makwerhu wa xisati, i n\u2019wana wa tata wa mina, kambe a hi n\u2019wana wa manana wa mina; hiloko a hundzuka nsati wa mina.' },
    { n: 13, text: 'Kutani ku ri loko Xikwembu xi ndzi endla ndzi tsendzeleka kule ni yindlu ya tata wa mina, ndzi ku eka yena: \u2018Leyi i tintswalo ta wena leti u nga ta ndzi endlela tona: endhawini hinkwayo leyi hi nga ta fika eka yona, u vula hikwalaho ka mina u ku: I makwerhu wa xinuna.\u2019' },
    { n: 14, text: 'Hiloko Abimeleke a teka tiyimpfu, ni tihomu, ni malandza ya xinuna, ni malandza ya xisati, a swi nyika Abrahama, a n\u2019wi vuyisela ni Sara wansati wa yena.' },
    { n: 15, text: 'Abimeleke a ku: Vona, tiko ra mina ri mahlweni ka wena; tshama kwihi na kwihi loku nga saseka emonlhweni ka wena.' },
    { n: 16, text: 'Kutani a ku eka Sara: Vona, ndzi nyikile makwenu wa xinuna gidi ra swiphemu swa silivhere; vona, swi funengeto wa mahlo eka wena mahlweni ka hinkwavo lava nga na wena, ni mahlweni ka vanhu hinkwavo; kutani u kombisiwile ku lulama.' },
    { n: 17, text: 'Hiloko Abrahama a khongela eka Xikwembu; kutani Xikwembu xi hanyisa Abimeleke, ni nsati wa yena, ni malandza ya yena ya xisati; hiloko va tlhela va tswala vana.' },
    { n: 18, text: 'Hikuva Hosi a yi pfale makhwiri hinkwato ya yindlu ya Abimeleke hakunene, hikwalaho ka Sara wansati wa Abrahama.' },
  ],
  21: [
    { n: 1, text: 'Hosi yi endla eka Sara hilaha yi vuleke hakona, Hosi yi endlela Sara leswi yi swi tshembiseke.' },
    { n: 2, text: 'Sara a tika, a tswalela Abrahama n\u2019wana wa xinuna evudyuhari bya yena, hi nkarhi lowu vekiweke lowu Xikwembu xi n\u2019wi byeleke wona.' },
    { n: 3, text: 'Abrahama a thya n\u2019wana wa yena la tswariweke eka yena, loyi Sara a n\u2019wi tswaleleke yena, vito ra Isaka.' },
    { n: 4, text: 'Abrahama a tsema Isaka n\u2019wana wa yena nsuvu na a ri ni masiku ya nhungu, hilaha Xikwembu xi n\u2019wi leriseke hakona.' },
    { n: 5, text: 'Abrahama a a ri ni malembe ya dzana loko Isaka n\u2019wana wa yena a tswariwa eka yena.' },
    { n: 6, text: 'Kutani Sara a ku: Xikwembu xi ndzi endlile ndzi hleka; un\u2019wana ni un\u2019wana la nga ta swi twa u ta hleka na mina.' },
    { n: 7, text: 'A ku: I mani la a nga ta vula eka Abrahama leswaku Sara u ta anwisa vana ke? Hikuva ndzi n\u2019wi tswalele n\u2019wana wa xinuna evudyuhari bya yena.' },
    { n: 8, text: 'N\u2019wana a kula, a lumuriwa; kutani Abrahama a endla nkhuvo lowukulu hi siku leri Isaka a lumuriweke ha rona.' },
    { n: 9, text: 'Sara a vona n\u2019wana wa Agara wa le Egipta, loyi a n\u2019wi tswaleleke Abrahama, a ri karhi a tlanga hi ku hleka.' },
    { n: 10, text: 'Hikwalaho a ku eka Abrahama: Hlongola nandza loyi wa xisati ni n\u2019wana wa yena; hikuva n\u2019wana wa nandza loyi wa xisati a nga ka a nga vi mudzhaka swin\u2019we ni n\u2019wana wa mina Isaka.' },
    { n: 11, text: 'Mhaka leyi yi tika swinene emonlhweni ka Abrahama, hikwalaho ka n\u2019wana wa yena.' },
    { n: 12, text: 'Kambe Xikwembu xi ku eka Abrahama: Swi nga tiki emonlhweni ka wena hikwalaho ka mufana ni hikwalaho ka nandza wa wena wa xisati; eka hinkwaswo leswi Sara a ku byelaka swona, yingisa rito ra yena; hikuva eka Isaka hi kona loku mbewu ya wena yi nga ta vitaniwa ha kona.' },
    { n: 13, text: 'Ni n\u2019wana wa nandza loyi wa xisati ndzi ta n\u2019wi endla tiko, hikuva i mbewu ya wena.' },
    { n: 14, text: 'Abrahama a pfuka nimpundzu swinene, a teka xinkwa ni khuwana ra mati, a swi nyika Agara, a swi veka exirhumbini xa yena, a n\u2019wi nyika ni mufana, a n\u2019wi hlongola; hiloko a suka, a famba a tsendzeleka emananga ya Bereseba.' },
    { n: 15, text: 'Loko mati ya le khuwanini ya herile, a lahla mufana ehansi ka xin\u2019wana xa swimilana.' },
    { n: 16, text: 'A ya tshama hlanle, ku ringana mpfhuka wa ntshendzo wa vurha; hikuva a ku: Ndzi nga ka ndzi nga voni ku fa ka mufana. Kutani a tshama hlanle, a tlakusa rito ra yena, a rila.' },
    { n: 17, text: 'Xikwembu xi twa rito ra mufana; kutani ntsumi ya Xikwembu yi vitana Agara yi ri etilweni, yi ku eka yena: Ku na ncini, Agara ke? Unga chavi; hikuva Xikwembu xi twile rito ra mufana lomu a nga kona.' },
    { n: 18, text: 'Pfuka, tlakusa mufana, u n\u2019wi khoma hi voko; hikuva ndzi ta n\u2019wi endla tiko lerikulu.' },
    { n: 19, text: 'Xikwembu xi pfula mahlo ya yena, hiloko a vona xihlovo xa mati; a ya tatisa khuwana hi mati, a nwisa mufana.' },
    { n: 20, text: 'Xikwembu xi va na mufana; a kula, a tshama emananga, a hundzuka mucofi wa vurha.' },
    { n: 21, text: 'A tshama emananga ya Parani; kutani mana wa yena a n\u2019wi tekela wansati a huma etikweni ra Egipta.' },
    { n: 22, text: 'Hi nkarhi wolowo, Abimeleke na Pikoli, ndhuna ya vuthu xa yena, va vulavula na Abrahama, va ku: Xikwembu xi na wena eka hinkwaswo leswi u swi endlaka.' },
    { n: 23, text: 'Sweswi hlambanya eka mina hi Xikwembu kwala, leswaku u nga ka u nga ndzi kengi, hambi eka mina, hambi eka n\u2019wana wa mina, hambi eka ntukulu wa mina; kambe hi ku landza tintswalo leti ndzi ku endleleke tona, u ta ndzi endla tano na mina, ni tiko leri u luveleke eka rona.' },
    { n: 24, text: 'Abrahama a ku: Ndzi ta hlambanya.' },
    { n: 25, text: 'Kambe Abrahama a khondla Abimeleke hikwalaho ka xihlovo xa mati lexi malandza ya Abimeleke ya xi tekeke hi matimba.' },
    { n: 26, text: 'Abimeleke a ku: A ndzi tivi la endleke mhaka leyi; na wena a wu ndzi byelanga, na mina a ndzi swi twanga ku fikela namuntlha.' },
    { n: 27, text: 'Abrahama a teka tiyimpfu ni tihomu, a swi nyika Abimeleke; kutani va endla ntwanano hi vambirhi ka vona.' },
    { n: 28, text: 'Abrahama a veka swinyimpfana swa xisati swa ntsenga swa ntlhanu na swimbirhi hlanle.' },
    { n: 29, text: 'Abimeleke a ku eka Abrahama: Swi vula ncini swinyimpfana leswi swa xisati swa ntsenga swa ntlhanu na swimbirhi lexi u xi veke hlanle ke?' },
    { n: 30, text: 'A ku: Hikuva u ta amukela swinyimpfana leswi swa xisati swa ntlhanu na swimbirhi emavokweni ya mina, leswaku swi va vumbhoni eka mina leswaku hi mina ndzi cerieke xihlovo lexi.' },
    { n: 31, text: 'Hikwalaho nddhawu yoleswo a yi thya vito ra Bereseba; hikuva hi laha va hlambanyeke ha kona hi vambirhi ka vona.' },
    { n: 32, text: 'Va endla ntwanano le Bereseba; hiloko Abimeleke a pfuka na Pikoli ndhuna ya vuthu xa yena, va vuyela etikweni ra Vafilista.' },
    { n: 33, text: 'Abrahama a rhandza ntsandza wa tamariska le Bereseba, a vitana vito ra Hosi, Xikwembu lexi nga heriki, kwalaho.' },
    { n: 34, text: 'Abrahama a luvela etikweni ra Vafilista masiku yo tala.' },
  ],
  22: [
    { n: 1, text: 'Endzhaku ka swilo leswi, Xikwembu xi ringa Abrahama, xi ku eka yena: Abrahama! A ku: Hi mina loyi.' },
    { n: 2, text: 'Xi ku: Teka sweswi n\u2019wana wa wena, n\u2019wana wa wena la nga un\u2019we, loyi u n\u2019wi rhandzaka, Isaka, u ya etikweni ra Moriya; u n\u2019wi nyikela kwalaho a va gandzelo leri tshiwiki ehenhla ka yin\u2019wana ya tintshava leyi ndzi nga ta ku byela yona.' },
    { n: 3, text: 'Abrahama a pfuka nimpundzu swinene, a boha mbhongolo ya yena, a teka vavanuna vambirhi va malandza ya yena na yena, ni Isaka n\u2019wana wa yena; a pandzela tiandla ta gandzelo leri tshiwiki, a pfuka, a ya endhawini leyi Xikwembu xi n\u2019wi byeleke yona.' },
    { n: 4, text: 'Hi siku ra vuntlhanu na rin\u2019we Abrahama a tlakusa mahlo ya yena, a vona ndhawu yoleswo na ya ha ri kule.' },
    { n: 5, text: 'Abrahama a ku eka malandza ya yena: Tshamani kwala ni mbhongolo; mina ni mufana hi ta ya le, hi ya gandzela, ndzhi kona hi ta vuyela eka n\u2019wina.' },
    { n: 6, text: 'Abrahama a teka tiandla ta gandzelo leri tshiwiki, a swi veka ehenhla ka Isaka n\u2019wana wa yena; a teka ndzilo ni mukwama wa mukula evokweni ya yena; hiloko va famba hi vambirhi ka vona.' },
    { n: 7, text: 'Isaka a vulavula ni Abrahama tata wa yena, a ku: Tata! A ku: Hi mina loyi, n\u2019wana wa mina. A ku: Vona ndzilo ni tiandla; kambe rhole ra gandzelo leri tshiwiki ri kwihi ke?' },
    { n: 8, text: 'Abrahama a ku: N\u2019wana wa mina, Xikwembu xi ta tiendlela rhole ra gandzelo leri tshiwiki. Hiloko va famba mahlweni hi vambirhi ka vona.' },
    { n: 9, text: 'Va fika endhawini leyi Xikwembu xi n\u2019wi byeleke yona; Abrahama a aka alitari kwalaho, a lulamisa tiandla, a boha Isaka n\u2019wana wa yena, a n\u2019wi veka ealitarini ehenhla ka tiandla.' },
    { n: 10, text: 'Abrahama a tshambuluta voko ra yena, a teka mukwama wa mukula leswaku a dlaya n\u2019wana wa yena.' },
    { n: 11, text: 'Kambe ntsumi ya Hosi yi n\u2019wi vitana yi ri etilweni, yi ku: Abrahama, Abrahama! A ku: Hi mina loyi.' },
    { n: 12, text: 'Yi ku: U nga tshambuluti voko ra wena ehenhla ka mufana, u nga n\u2019wi endli nchumu; hikuva sweswi ndzi swi tivile leswaku wa chava Xikwembu, leswi u nga ndzi tsonangiki n\u2019wana wa wena, n\u2019wana wa wena la nga un\u2019we.' },
    { n: 13, text: 'Abrahama a tlakusa mahlo ya yena, a languta, kutani, vonani, endzhaku ka yena ku na khuna leri khomiweke hi timhondzo ta rona exihlahleni xa mitwa; Abrahama a ya teka khuna rero, a n\u2019wi nyikela a va gandzelo leri tshiwiki endhawini ya n\u2019wana wa yena.' },
    { n: 14, text: 'Abrahama a thya ndhawu yoleswo vito ra Hosi Yi Ta Nyika; hilaha swi vuriwaka hakona namuntlha: Entshaveni ya Hosi swi ta kumiwa.' },
    { n: 15, text: 'Ntsumi ya Hosi yi vitana Abrahama ra vumbirhi yi ri etilweni,' },
    { n: 16, text: 'yi ku: Ndzi hlambanyile hi mina n\u2019wini, ku vula Hosi, leswi u endleke mhaka leyi, u nga ndzi tsonangiki n\u2019wana wa wena, n\u2019wana wa wena la nga un\u2019we,' },
    { n: 17, text: 'leswaku hi ku katekisa ndzi ta ku katekisa, ni hi ku andzisa ndzi ta andzisa mbewu ya wena kukota tinyeleti ta tilo, ni kukota ntsenga lowu nga eribuweni xa lwandle; mbewu ya wena yi ta fuma nyangwa ya valala va yona;' },
    { n: 18, text: 'kutani eka mbewu ya wena tinxaka hinkwato ta misava ti ta katekisiwa, hikuva u yingisile rito ra mina.' },
    { n: 19, text: 'Hiloko Abrahama a vuyela eka malandza ya yena, va pfuka, va fambela swin\u2019we le Bereseba; kutani Abrahama a tshama le Bereseba.' },
    { n: 20, text: 'Endzhaku ka swilo leswi, va byela Abrahama, va ku: Vona, Milka na yena u tswalele Nakore makwenu vana;' },
    { n: 21, text: 'Uzi mativula ya yena, na Buzi makwenu wa yena, ni Kemuele tata wa Aramu,' },
    { n: 22, text: 'ni Kesede, na Hazo, na Pildaxi, na Jidlala, na Betuele.' },
    { n: 23, text: 'Betuele a tswala Rebeka. Lava va ntsenga wa nhungu Milka u va tswalele Nakore, makwenu wa Abrahama.' },
    { n: 24, text: 'Ni xigwitsana xa yena, lexi vito ra xona ku nga Reuma, na xona xi tswala Teba, na Gahamu, na Tahaxi, na Maaka.' },
  ],
  23: [
    { n: 1, text: 'Sara a a ri ni malembe ya dzana ni makume mambirhi ni ntlhanu na mambirhi; lawa i malembe ya vutomi bya Sara.' },
    { n: 2, text: 'Sara a fela le Kiriyata-Arba (nga yona Hebroni) etikweni ra Kanana; kutani Abrahama a nghena leswaku a rila Sara ni ku n\u2019wi lilela.' },
    { n: 3, text: 'Abrahama a pfuka mahlweni ka mufi wa yena, a vulavula ni vana va Heti, a ku:' },
    { n: 4, text: 'Ndzi muluveri ni mupfhumba exikarhi ka n\u2019wina; ndzi nyikeni ndhawu ya sirha exikarhi ka n\u2019wina, leswaku ndzi lahla mufi wa mina a nga ha vi mahlweni ka mina.' },
    { n: 5, text: 'Vana va Heti va hlamula Abrahama, va ku eka yena:' },
    { n: 6, text: 'Hi yingise, hosi ya mina: u ndhuna ya Xikwembu exikarhi ka hina; lahla mufi wa wena emasirheni ya hina lama hlawuriweke swinene; a ku na un\u2019we wa hina la nga ta ku tsona sirha ra yena leswaku u lahla mufi wa wena.' },
    { n: 7, text: 'Abrahama a pfuka, a nkhinsamela vanhu va tiko, vona vana va Heti,' },
    { n: 8, text: 'a vulavula na vona, a ku: Loko ku ri ku rhandza ka n\u2019wina leswaku ndzi lahla mufi wa mina a nga ha vi mahlweni ka mina, ndzi yingiseni, mi ndzi khongelela eka Efroni n\u2019wana wa Zohari,' },
    { n: 9, text: 'leswaku a ndzi nyika bako ra Makpela, leri a nga na rona emakumu ka nsimu ya yena; a a ndzi nyike rona exikarhi ka n\u2019wina hi ntsengo lowu heleleke wa mali, ri va ndhawu ya sirha.' },
    { n: 10, text: 'Efroni a a tshamile exikarhi ka vana va Heti; kutani Efroni wa Muheti a hlamula Abrahama, vana va Heti va karhi va yingisela, hinkwavo lava ngheneke hi nyangwa ya muti wa yena, a ku:' },
    { n: 11, text: 'Inene, hosi ya mina, ndzi yingise: Ndzi ku nyika nsimu leyi, ni bako leri nga endzeni ka yona, ndzi ku nyika rona; mahlweni ka vana va vanhu va mina ndzi ku nyika rona; lahla mufi wa wena.' },
    { n: 12, text: 'Abrahama a nkhinsama mahlweni ka vanhu va tiko,' },
    { n: 13, text: 'a vulavula ni Efroni, vanhu va tiko va karhi va yingisela, a ku: Ndzi kombela u ndzi yingisa: Ndzi ta nyika ntsengo wa nsimu hi mali; yi amukele emavokweni ya mina, ndzi lahla mufi wa mina kwalaho.' },
    { n: 14, text: 'Efroni a hlamula Abrahama, a ku eka yena:' },
    { n: 15, text: 'Hosi ya mina, ndzi yingise: Tiko leri xavaka madzana mana ya tixekele ta silivhere, xana i ncini exikarhi ka mina na wena ke? Lahla mufi wa wena ntsena.' },
    { n: 16, text: 'Abrahama a yingisa Efroni; kutani Abrahama a pima mali eka Efroni, leyi a yi vuleke etindleveni ta vana va Heti, madzana mana ya tixekele ta silivhere, hi ku landza ntsengo lowu amukelekaka eka vaxavisi.' },
    { n: 17, text: 'Kutani nsimu ya Efroni leyi a yi ri eMakpela, lowu nga mahlweni ka Mamre, nsimu ni bako leri a ri ri endzeni ka yona, ni mirhi hinkwayo leyi a yi ri endzeni ka nsimu, ni le mindzilakanini ya yona hinkwayo,' },
    { n: 18, text: 'swi tiyisiwa eka Abrahama swi va ndzhaka ya yena, mahlweni ka vana va Heti, mahlweni ka hinkwavo lava ngheneke hi nyangwa ya muti wa yena.' },
    { n: 19, text: 'Endzhaku ka swona, Abrahama a lahla Sara wansati wa yena ebako ra nsimu ya Makpela, mahlweni ka Mamre (lowu nga Hebroni), etikweni ra Kanana.' },
    { n: 20, text: 'Kutani nsimu ni bako leri nga endzeni ka yona swi tiyisiwa eka Abrahama hi vana va Heti, swi va ndhawu ya sirha.' },
  ],
  24: [
    { n: 1, text: 'Abrahama a a dyuhele swinene; kutani Hosi a yi katekise Abrahama eka hinkwaswo.' },
    { n: 2, text: 'Abrahama a ku eka nandza wa yena, loyi a a ri nkulukumba wa yindlu ya yena, loyi a a rhangela hinkwaswo leswi a a ri na swona: Ndzi kombela u veka voko ra wena ehansi ka nyonga ya mina,' },
    { n: 3, text: 'ndzi ta ku hlambanyisa hi Hosi, Xikwembu xa tilo ni Xikwembu xa misava, leswaku u nga ka u nga tekeli n\u2019wana wa mina nsati eka vanhwanyana va Vakanana, lava ndzi tshamaka exikarhi ka vona;' },
    { n: 4, text: 'kambe u ta ya etikweni ra mina ni le ka vaka hina, u ya tekela n\u2019wana wa mina Isaka wansati kwalaho.' },
    { n: 5, text: 'Nandza a ku eka yena: Kumbexana wansati a nga ka a nga rhandzi ku ndzi landza etikweni leri; xana ndzi fanele ku vuyisa n\u2019wana wa wena etikweni leri u sukeke eka rona ke?' },
    { n: 6, text: 'Abrahama a ku eka yena: Tivonele leswaku u nga vuyiseli n\u2019wana wa mina kwalaho.' },
    { n: 7, text: 'Hosi, Xikwembu xa tilo, lexi ndzi humeseke endlwini ya tata wa mina ni le tikweni ra vahlavari va mina, lexi vulavuleke na mina, lexi hlambanyeke eka mina, xi ku: \u2018Ndzi ta nyika mbewu ya wena tiko leri,\u2019 xi ta rhumela ntsumi ya xona mahlweni ka wena, kutani u ta tekela n\u2019wana wa mina wansati kwalaho.' },
    { n: 8, text: 'Kambe loko wansati a nga rhandzi ku ku landza, u ta va u ntshunxiwile eka ku hlambanya loku ka mina; ntsena u nga vuyiseli n\u2019wana wa mina kwalaho.' },
    { n: 9, text: 'Hiloko nandza a veka voko ra xona ehansi ka nyonga ya Abrahama n\u2019wini wa xona, a hlambanya eka yena hikwalaho ka mhaka leyi.' },
    { n: 10, text: 'Nandza a teka tikamela ta khume eka tikamela ta n\u2019wini wa xona, a suka a famba, a ri ni swilo swo saseka hinkwaswo swa n\u2019wini wa xona evokweni xa xona; a pfuka, a ya eMesopotamiya, emutini wa Nakore.' },
    { n: 11, text: 'A nkhinsamisa tikamela handle xa muti kusuhi ni xihlovo xa mati hi nkarhi wa madyambu, nkarhi lowu vavasati va humaka ha wona ku ka mati.' },
    { n: 12, text: 'A ku: Hosi, Xikwembu xa n\u2019wini wa mina Abrahama, ndzi kombela u ndzi nyika ku humelela namuntlha, u endlela n\u2019wini wa mina Abrahama tintswalo.' },
    { n: 13, text: 'Vona, ndzi yimile kusuhi ni xihlovo xa mati, kutani vanhwanyana va vanhu va muti va karhi va huma ku ka mati;' },
    { n: 14, text: 'ku nga va leswaku nhwanyana loyi ndzi nga ta ku eka yena: \u2018Ndzi kombela u ndzuluta khuwana ra wena ndzi nwa,\u2019 a ku: \u2018Nwa, ndzi ta nwisa ni tikamela ta wena na tona,\u2019 a va loyi u n\u2019wi vekeleke nandza wa wena Isaka; kutani hi swona ndzi nga ta tiva leswaku u endlele n\u2019wini wa mina tintswalo.' },
    { n: 15, text: 'A nga si heta ku vulavula, vonani, Rebeka, loyi a tswariweke eka Betuele n\u2019wana wa Milka, nsati wa Nakore makwenu wa Abrahama, a huma a rhwale khuwana ra yena exirhumbini xa yena.' },
    { n: 16, text: 'Nhwanyana loyi a a sasekile swinene ku languteka, a a ri mhandhi, ku nga na wanuna la nga n\u2019wi tiva; a xika exihlovweni, a tatisa khuwana ra yena, a tlhandluka.' },
    { n: 17, text: 'Nandza a tsutsuma ku ya n\u2019wi hlanganisa, a ku: Ndzi kombela u ndzi nyika mati matsongo ndzi nwa exihlovweni xa khuwana ra wena.' },
    { n: 18, text: 'A ku: Nwa, hosi ya mina. A hatla a xikisa khuwana ra yena evokweni ya yena, a n\u2019wi nwisa.' },
    { n: 19, text: 'Loko a n\u2019wi nwisile a heta, a ku: Ndzi ta kela ni tikamela ta wena na tona, ku fikela loko ti nwe ti tsemeka torha.' },
    { n: 20, text: 'A hatla a chulula khuwana ra yena exidyelweni, a tsutsumela exihlovweni ghandzi ku ya ka mati, a kela tikamela ta yena hinkwato.' },
    { n: 21, text: 'Wanuna loyi a a n\u2019wi miyela ntsena, a hlamala, a lava ku tiva loko Hosi yi humelerisile rhendzo ra yena kumbe e-e.' },
    { n: 22, text: 'Loko tikamela ti nwe ti tiyiseka, wanuna a teka ndzhengere wa nsuku lowu tikaka hafu ya xekele, ni masindza mambirhi ya mavoko ya yena lama tikaka tixekele ta khume ta nsuku,' },
    { n: 23, text: 'a ku: U n\u2019wana wa mani ke? Ndzi byele, ndzi kombela u ku: Xana ku ni ndhawu endlwini ya tata wa wena leswaku hi etlela kona ke?' },
    { n: 24, text: 'A ku eka yena: Ndzi n\u2019wana wa Betuele n\u2019wana wa Milka, loyi a n\u2019wi tswaleleke Nakore.' },
    { n: 25, text: 'A ku mahlweni: Hi ni duka ni swakudya swa swifuwo swo tala swinene, ni ndhawu yo etlela.' },
    { n: 26, text: 'Wanuna a korhama, a gandzela Hosi,' },
    { n: 27, text: 'a ku: A ku dzunisiwe Hosi, Xikwembu xa n\u2019wini wa mina Abrahama, lexi nga tsonangiki n\u2019wini wa mina tintswalo ta xona ni ntiyiso wa xona; loko ndzi ri endleleni, Hosi yi ndzi kongomisile endlwini ya vamakwenu va n\u2019wini wa mina.' },
    { n: 28, text: 'Nhwanyana a tsutsuma, a ya hlamusela vandyangu va mana wa yena swilo leswi hinkwaswo.' },
    { n: 29, text: 'Rebeka a a ri ni makwenu wa xinuna loyi vito ra yena ku nga Labani; hiloko Labani a tsutsumela ehandle eka wanuna loyi kusuhi ni xihlovo.' },
    { n: 30, text: 'Loko a vone ndzhengere ni masindza emavokweni ya makwenu wa xisati, ni ku twa marito ya Rebeka makwenu wa yena, a ku: \u2018Wanuna loyi u vulavule na mina hi ndlela leyi,\u2019 a fika eka wanuna; kutani, vonani, a a yimile kusuhi ni tikamela exihlovweni.' },
    { n: 31, text: 'A ku: Nghena, wena loyi u katekisiweke hi Hosi; ha yini u yima handle ke? Hikuva ndzi lulamisile yindlu ni ndhawu ya tikamela.' },
    { n: 32, text: 'Wanuna a nghena endlwini; Labani a ntshunxa tikamela, a ti nyika duka ni swakudya, a tisa ni mati yo hlamba milenge ya yena ni ya vavanuna lava a va ri na yena.' },
    { n: 33, text: 'Va veka swakudya mahlweni ka yena leswaku a dya; kambe a ku: Ndzi nga ka ndzi nga dyi ku fikela loko ndzi hlamusele mhaka ya mina. Labani a ku: Vulavula.' },
    { n: 34, text: 'A ku: Hi mina nandza wa Abrahama.' },
    { n: 35, text: 'Hosi yi katekise n\u2019wini wa mina swinene-nene, a hundzuka lowukulu; yi n\u2019wi nyikile tiyimpfu, ni tihomu, ni silivhere, ni nsuku, ni malandza ya xinuna, ni malandza ya xisati, ni tikamela, ni timbhongolo.' },
    { n: 36, text: 'Sara, nsati wa n\u2019wini wa mina, u tswalele n\u2019wini wa mina n\u2019wana wa xinuna evudyuhari bya yena; kutani n\u2019wini wa mina u n\u2019wi nyikile hinkwaswo leswi a nga na swona.' },
    { n: 37, text: 'N\u2019wini wa mina u ndzi hlambanyisile, a ku: \u2018U nga ka u nga tekeli n\u2019wana wa mina nsati eka vanhwanyana va Vakanana, lava ndzi tshamaka etikweni ra vona;' },
    { n: 38, text: 'kambe u ta ya endlwini ya tata wa mina ni le ka vandyangu va mina, u ya n\u2019wi tekela nsati kwalaho.\u2019' },
    { n: 39, text: 'Kuni ndzi ku eka n\u2019wini wa mina: \u2018Kumbexana wansati a nga ka a nga ndzi landzi.\u2019' },
    { n: 40, text: 'A ku eka mina: \u2018Hosi, lexi ndzi fambaka mahlweni ka xona, xi ta rhumela ntsumi ya xona na wena, xi humelerisa rhendzo ra wena; u ta tekela n\u2019wana wa mina nsati eka vandyangu va mina ni le ndluwini ya tata wa mina;' },
    { n: 41, text: 'hi kona u nga ta va u ntshunxiwile eka ku hlambanyisa loku ka mina; loko u fika eka vandyangu va mina, kutani loko va nga ku nyiki yena, u ta va u ntshunxiwile eka ku hlambanya loku ka mina.\u2019' },
    { n: 42, text: 'Kutani ndzi fikile namuntlha exihlovweni, ndzi ku: Hosi, Xikwembu xa n\u2019wini wa mina Abrahama, loko u humelerisa rhendzo leri ndzi fambaka ha rona sweswi,' },
    { n: 43, text: 'vona, ndzi yimile kusuhi ni xihlovo xa mati; ku nga va leswaku nhwanyana loyi a nga ta huma ku ka mati, loyi ndzi nga ta ku eka yena: \u2018Ndzi kombela u ndzi nyika mati matsongo ndzi nwa exihlovweni xa khuwana ra wena,\u2019' },
    { n: 44, text: 'a ku eka mina: \u2018Nwa wena, ndzi ta kela ni tikamela ta wena na tona,\u2019 a va loyi Hosi yi n\u2019wi vekeleke n\u2019wana wa n\u2019wini wa mina.' },
    { n: 45, text: 'Ndzi nga si heta ku vulavula embilu ya mina, vonani, Rebeka a huma a rhwale khuwana ra yena exirhumbini xa yena, a xika exihlovweni, a ka mati. Hiloko ndzi ku eka yena: \u2018Ndzi kombela u ndzi nwisa.\u2019' },
    { n: 46, text: 'A hatla a xikisa khuwana ra yena exirhumbini xa yena, a ku: \u2018Nwa, ndzi ta nwisa ni tikamela ta wena na tona.\u2019 Hiloko ndzi nwa, a nwisa ni tikamela na tona.' },
    { n: 47, text: 'Hiloko ndzi n\u2019wi vutisa, ndzi ku: \u2018U n\u2019wana wa mani ke?\u2019 A ku: \u2018Ndzi n\u2019wana wa Betuele n\u2019wana wa Nakore, loyi Milka a n\u2019wi tswaleleke yena.\u2019 Hiloko ndzi n\u2019wi veka ndzhengere enhompfini ya yena ni masindza emavokweni ya yena.' },
    { n: 48, text: 'Kutani ndzi korhama, ndzi gandzela Hosi, ndzi dzunisa Hosi, Xikwembu xa n\u2019wini wa mina Abrahama, lexi ndzi kongomiseke endleleni ya ntiyiso leswaku ndzi teka n\u2019wana wa makwenu wa n\u2019wini wa mina ndzi n\u2019wi nyika n\u2019wana wa yena.' },
    { n: 49, text: 'Sweswi loko mi lava ku endlela n\u2019wini wa mina tintswalo ni ntiyiso, ndzi byeleni; loko swi nga ri tano, ndzi byeleni, leswaku ndzi ya hi tlhelo ra xinene kumbe ra ximatsi.' },
    { n: 50, text: 'Hiloko Labani na Betuele va hlamula, va ku: Mhaka leyi yi huma eka Hosi; hi nga ka hi nga vuli nchumu lowo biha kumbe lowo saseka eka wena.' },
    { n: 51, text: 'Vona, Rebeka u mahlweni ka wena, n\u2019wi teke u famba, a va nsati wa n\u2019wana wa n\u2019wini wa wena, hilaha Hosi yi vuleke hakona.' },
    { n: 52, text: 'Loko nandza wa Abrahama a twa marito ya vona, a gandzela Hosi a tiandlaleka ehansi.' },
    { n: 53, text: 'Nandza a humesa swilo vya silivhere, ni swilo vya nsuku, ni swiambalo, a swi nyika Rebeka; a nyika ni makwenu wa xinuna ni mana wa yena swilo swa risima swinene.' },
    { n: 54, text: 'Va dya, va nwa, yena ni vavanuna lava a va ri na yena, va etlela kwalaho. Nimpundzu loko va pfuka, a ku: Ndzi kombeleni mi ndzi tshika ndzi vuyela eka n\u2019wini wa mina.' },
    { n: 55, text: 'Kambe makwenu wa xinuna ni mana wa yena va ku: Ndzi kombela nhwanyana a tshama na hina masiku matsongo, kumbexana khume; endzhaku ka swona a nga famba.' },
    { n: 56, text: 'A ku eka vona: Mi nga ndzi tsoni nkarhi, hikuva Hosi yi humelerisile rhendzo ra mina; ndzi tshikeni ndzi famba leswaku ndzi ya eka n\u2019wini wa mina.' },
    { n: 57, text: 'Va ku: Hi ta vitana nhwanyana, hi n\u2019wi vutisa hi nomu wa yena.' },
    { n: 58, text: 'Va vitana Rebeka, va ku eka yena: Xana u ta famba ni wanuna loyi ke? A ku: Ndzi ta famba.' },
    { n: 59, text: 'Hiloko va tshika Rebeka makwenu wa vona, ni muanwisi wa yena, ni nandza wa Abrahama ni vavanuna ya yena va famba.' },
    { n: 60, text: 'Va katekisa Rebeka, va ku eka yena: Makwerhu, u nga va gidi ra makume ya magidi, ni mbewu ya wena a yi fume nyangwa ya lava va yi vengaka.' },
    { n: 61, text: 'Rebeka a pfuka ni vanhwanyana va yena, va ghandza tikamela, va landza wanuna loyi; hiloko nandza a teka Rebeka, a famba.' },
    { n: 62, text: 'Isaka a a vuyile hi le ndleleni ya Beer-Lahai-Roi; hikuva a a tshama etikweni ra le Dzongeni.' },
    { n: 63, text: 'Isaka a huma leswaku a ya anakanya erivaleni hi nkarhi wa madyambu; a tlakusa mahlo ya yena a languta, kutani, vonani, ku ri ni tikamela leti faka ti ta.' },
    { n: 64, text: 'Rebeka na yena a tlakusa mahlo ya yena, a vona Isaka, hiloko a xika eka kamela,' },
    { n: 65, text: 'a ku eka nandza: I mani wanuna loyi a fambaka erivaleni ku ta hi hlanganisa ke? Nandza a ku: I n\u2019wini wa mina. Hiloko a teka xitshalo, a tifunengeta.' },
    { n: 66, text: 'Nandza a hlamusela Isaka swilo hinkwaswo leswi a swi endleke.' },
    { n: 67, text: 'Isaka a nghenisa Rebeka etendeni ra Sara mana wa yena; a teka Rebeka, a hundzuka nsati wa yena, a n\u2019wi rhandza swinene; kutani Isaka a chaveleriwa endzhaku ka ku fa ka mana wa yena.' },
  ],
  25: [
    { n: 1, text: 'Abrahama a tlhela a teka wansati un\u2019wana loyi vito ra yena ku nga Ketura.' },
    { n: 2, text: 'A n\u2019wi tswalela Zimrani, na Jokxani, na Medani, na Midiyani, na Jixbaki, na Suwa.' },
    { n: 3, text: 'Jokxani a tswala Sheba na Dedani. Vana va Dedani a va ri Vaasuri, ni Valetuxi, ni Valeumi.' },
    { n: 4, text: 'Vana va Midiyani a va ri Efa, na Eferi, na Hanoki, na Abida, na Eldaha. Lava hinkwavo a va ri vana va Ketura.' },
    { n: 5, text: 'Abrahama a nyika Isaka hinkwaswo leswi a a ri na swona.' },
    { n: 6, text: 'Kambe vana va swigwitsana leswi Abrahama a a ri na swona, Abrahama a va nyika tinyiko, a va hlongola mahlweni ka Isaka n\u2019wana wa yena, na a ha hanya, a va kongomisa hi tlhelo ra le Vuxeni, etikweni ra le Vuxeni.' },
    { n: 7, text: 'Lawa i malembe ya vutomi bya Abrahama lawa a ma hanyeke, dzana ni makume ntlhanu na makume mambirhi ni ntlhanu wa malembe.' },
    { n: 8, text: 'Abrahama a humesa moya, a fela evudyuhari byo saseka, na a dyuhele swinene, a tshembekile; hiloko a hlanganisiwa ni vanhu va yena.' },
    { n: 9, text: 'Isaka na Ismayele vana va yena va n\u2019wi lahla ebako ra Makpela, ensimini ya Efroni n\u2019wana wa Zohari wa Muheti, lowu nga mahlweni ka Mamre;' },
    { n: 10, text: 'nsimu leyi Abrahama a yi xaveke eka vana va Heti; hi laha Abrahama a lahliweke ha kona swin\u2019we ni Sara wansati wa yena.' },
    { n: 11, text: 'Endzhaku ka ku fa ka Abrahama, Xikwembu xi katekisa Isaka n\u2019wana wa yena; kutani Isaka a tshama kusuhi ni Beer-Lahai-Roi.' },
    { n: 12, text: 'Lawa i matimu ya Ismayele n\u2019wana wa Abrahama, loyi Agara wa le Egipta, nandza wa Sara wa xisati, a n\u2019wi tswaleleke Abrahama;' },
    { n: 13, text: 'lawa i mavito ya vana va Ismayele, hi mavito ya vona, hi ku landza ku tswariwa ka vona: Nebayoti, mativula ya Ismayele; na Kedari, na Adbele, na Mibsama,' },
    { n: 14, text: 'na Mixma, na Duma, na Masa,' },
    { n: 15, text: 'na Hadadi, na Tema, na Jeturu, na Nafixi, na Kedema.' },
    { n: 16, text: 'Lava i vana va Ismayele, kutani lawa i mavito ya vona, hi ku landza miganga ya vona ni mixaxa ya vona, tihosi ta khume na timbeu hi ku landza tinxaka ta vona.' },
    { n: 17, text: 'Lawa i malembe ya vutomi bya Ismayele: dzana ni makume manharhu na ntlhanu na mambirhi wa malembe; a humesa moya, a fa, a hlanganisiwa ni vanhu va yena.' },
    { n: 18, text: 'Va tshama ku sukela le Havila ku ya fika le Suru, lowu nga mahlweni ka Egipta, loko u ya hi tlhelo ra Asiriya; a tshama mahlweni ka vamakwenu va yena hinkwavo.' },
    { n: 19, text: 'Lawa i matimu ya Isaka n\u2019wana wa Abrahama: Abrahama a tswala Isaka.' },
    { n: 20, text: 'Isaka a a ri ni malembe ya makume mana loko a teka Rebeka, n\u2019wana wa Betuele wa Muarame wa le Padani-Aramu, makwenu wa xisati wa Labani wa Muarame, a va nsati wa yena.' },
    { n: 21, text: 'Isaka a khongelela nsati wa yena eka Hosi, hikuva a a ri ngumba; kutani Hosi yi yingisa ku khongela ka yena, hiloko Rebeka nsati wa yena a tika.' },
    { n: 22, text: 'Vana va pfapfana endzeni ka yena; hiloko a ku: Loko swi ri tano, ha yini ndzi hanya ke? A ya vutisa Hosi.' },
    { n: 23, text: 'Hosi yi ku eka yena: Tinxaka timbirhi ti le khwirini ra wena, kutani vanhu vambirhi va ta avana ku sukela endzeni ka wena; tiko rin\u2019wana ri ta va ni matimba ku tlula lerin\u2019wana, kutani lonkulukumba u ta tirhela lontsongo.' },
    { n: 24, text: 'Loko masiku ya yena ya ku tswala ya fikelele, vonani, a ku ri ni mahahlwa endzeni ka khwiri ra yena.' },
    { n: 25, text: 'Wo rhanga a huma a tshwukile, a fana ni xiambalo xa voya emirini hinkwayo; hiloko va n\u2019wi thya vito ra Esawu.' },
    { n: 26, text: 'Endzhaku ka yena, makwenu wa yena a huma, na a khome xitende xa Esawu hi voko ra yena; hiloko a thyiwa vito ra Jakobe. Isaka a a ri ni malembe ya makume tsetsene loko va tswariwa.' },
    { n: 27, text: 'Vafana va kula: Esawu a hundzuka muhloti la nga ni vutshila, wanuna wa nsimu; kambe Jakobe a a ri wanuna la rhendzelekaka, a tshama ematendeneni.' },
    { n: 28, text: 'Isaka a a rhandza Esawu, hikuva a a dya swihari leswi a swi hloteke; kambe Rebeka a a rhandza Jakobe.' },
    { n: 29, text: 'Siku rin\u2019wana Jakobe a a sweka mukapo, hiloko Esawu a fika a huma ensinwini, na a karhele swinene.' },
    { n: 30, text: 'Esawu a ku eka Jakobe: Ndzi kombela u ndzi nyika ndzi dya mukapo wolowo wo tshwuka, hikuva ndzi karhele swinene. Hikwalaho vito ra yena ri thiyiweke Edomo.' },
    { n: 31, text: 'Kambe Jakobe a ku: Ndzi xavisele mfanelo ya wena ya vutivula namuntlha.' },
    { n: 32, text: 'Esawu a ku: Vona, ndzi kusuhi ni ku fa; xana mfanelo ya vutivula yi ta ndzi pfuna ncini ke?' },
    { n: 33, text: 'Jakobe a ku: Hlambanya eka mina namuntlha. Hiloko a hlambanya eka yena, a xavisela Jakobe mfanelo ya yena ya vutivula.' },
    { n: 34, text: 'Kutani Jakobe a nyika Esawu xinkwa ni mukapo wa tinyawa; a dya, a nwa, a pfuka, a famba. Hi mukhuva wolowo Esawu a fele mfanelo ya yena ya vutivula.' },
  ],
  26: [
    { n: 1, text: 'Kutani ku va ni ndlala etikweni, handle ka ndlala leyiya yo rhanga leyi nga va kona emasikwini ya Abrahama. Hiloko Isaka a ya eka Abimeleki hosi ya Vafilisita le Gerari.' },
    { n: 2, text: 'Hosi yi humelela eka yena, yi ku: U nga xiki u ya eEgipta; tshama etikweni leri ndzi nga ta ku byela rona.' },
    { n: 3, text: 'Tshama etikweni leri u va muluveri, kutani ndzi ta va na wena, ndzi ku katekisa; hikuva ndzi ta nyika wena ni mbewu ya wena matiko lawa hinkwawo, ndzi tiyisa xihlambanyo lexi ndzi xi hlambanyeke eka Abrahama tata wa wena.' },
    { n: 4, text: 'Ndzi ta andgisa mbewu ya wena ku fana ni tinyeleti ta tilo, ndzi nyika mbewu ya wena matiko lawa hinkwawo; kutani tinxaka hinkwato ta misava ti ta tikatekisa hi mbewu ya wena;' },
    { n: 5, text: 'hikuva Abrahama u yingisile rito ra mina, a hlayisa leswi ndzi n\u2019wi leriseke swona, ni swileriso swa mina, ni milawu ya mina, ni timfanelo ta mina.' },
    { n: 6, text: 'Hiloko Isaka a tshama eGerari.' },
    { n: 7, text: 'Loko vavanuna va ndhawu yoleyo va vutisa hi ta nsati wa yena, a ku: I makwerhu wa xisati; hikuva a a chava ku ku: I nsati wa mina; a ku: Kumbexana vanhu va ndhawu leyi va nga ndzi dlaya hikwalaho ka Rebeka, hikuva a a sasekile swinene ku languteka.' },
    { n: 8, text: 'Loko a tshamile kwalaho nkarhi wo leha, Abimeleki hosi ya Vafilisita a langutela handle hi fastele, a vona Isaka a karhi a tlanga ni ku ntsgontsga Rebeka nsati wa yena.' },
    { n: 9, text: 'Abimeleki a vitana Isaka, a ku eka yena: Vona, inene i nsati wa wena; xana u vurile njhani u ku: I makwerhu wa xisati ke? Isaka a ku eka yena: Hikuva ndzi te: Ndzi nga fela yena.' },
    { n: 10, text: 'Abimeleki a ku: I yini lexi u hi endleke xona ke? Siku rin\u2019wana un\u2019we wa vanhu lava a a nga etlela ni nsati wa wena, kutani u ta va u hi tisele nandzu. ' },
    { n: 11, text: 'Hiloko Abimeleki a lerisa vanhu hinkwavo, a ku: Loyi a nga ta khumba wanuna loyi kumbe nsati wa yena, handle ku kanakana u ta dlayiwa.' },
    { n: 12, text: 'Isaka a rima etikweni rero, kutani hi lembe rero a vuyeriwa dzana ra tiyindlu; hikuva Hosi yi n\u2019wi katekisile.' },
    { n: 13, text: 'Wanuna a fuma, a ya mahlweni a kula ku fikela loko a hundzuke nkulu swinene;' },
    { n: 14, text: 'a a ri ni swifuwo swa tiyimpfu, ni swifuwo swa tihomu, ni malandza yo tala swinene; kutani Vafilisita va n\u2019wi rhandzela.' },
    { n: 15, text: 'Swihlovo hinkwaswo leswi malandza ya tata wa yena va swi kelaka emasikwini ya Abrahama tata wa wena, Vafilisita va swi pfarile, va swi tata hi misava.' },
    { n: 16, text: 'Abimeleki a ku eka Isaka: Suka eka hina, hikuva u ni matimba lamakulu ku tlula hina.' },
    { n: 17, text: 'Isaka a suka kwalaho, a dzima matende ya yena enkoveni wa Gerari, a tshama kwalaho.' },
    { n: 18, text: 'Isaka a tlhela a kela swihlovo swa mati leswi va swi kelaka emasikwini ya Abrahama tata wa yena, hikuva Vafilisita va a va swi pfarile endzhaku ka ku fa ka Abrahama; a swi thya mavito lawa tata wa yena a a swi thyile wona.' },
    { n: 19, text: 'Malandza ya Isaka ya kela enkoveni, ya kuma xihlovo xa mati lama ntsgaka.' },
    { n: 20, text: 'Kambe varisi va Gerari va holova ni varisi va Isaka, va ku: Mati lawa i ya hina! Hiloko a thya xihlovo vito ra Eseke, hikuva va holovile na yena.' },
    { n: 21, text: 'Va kela xihlovo xin\u2019wana, va holovela na xona; hiloko a xi thya vito ra Sitna.' },
    { n: 22, text: 'A suka kwalaho, a kela xihlovo xin\u2019wana, lexi va nga holovela xona; hiloko a xi thya vito ra Rehoboti, a ku: Hikuva sweswi Hosi yi hi endlele ndhawu, kutani hi ta simama etikweni.' },
    { n: 23, text: 'Ku sukela kwalaho a tlhandluka a ya eBerixeba.' },
    { n: 24, text: 'Hosi yi humelela eka yena hi vusiku byoloyo, yi ku: Hi mina Xikwembu xa Abrahama tata wa wena; u nga chavi, hikuva ndzi na wena, ndzi ta ku katekisa, ndzi andgisa mbewu ya wena hikwalaho ka Abrahama nandza wa mina.' },
    { n: 25, text: 'A aka alitari kwalaho, a vitana vito ra Hosi, a dzima tende ra yena kwalaho; kutani malandza ya Isaka ya kela xihlovo kwalaho.' },
    { n: 26, text: 'Abimeleki a fika eka yena a huma eGerari, a ri na Ahuzati munghana wa yena ni Fikolo mufambisi wa mavuthu ya yena.' },
    { n: 27, text: 'Isaka a ku eka vona: Ha yini mi ta eka mina, kasi mi ndzi vengile, mi ndzi hlongolile eka n\u2019wina ke?' },
    { n: 28, text: 'Va ku: Hi vonile swinene leswaku Hosi yi na wena; kutani hi te: A ku ve ni xihlambanyo exikarhi ka hina, exikarhi ka hina na wena, hi endla na wena ntwanano,' },
    { n: 29, text: 'leswaku u nga ka u nga hi endleli swo biha, tanihi leswi hi nga ka hi nga ku khumbangiki, ni leswi hi ku endleleke leswinene ntsena, hi ku tshika u famba hi ku rhula; sweswi u nkateko wa Hosi.' },
    { n: 30, text: 'Hiloko a va endlela nkhuvo, va dya, va nwa.' },
    { n: 31, text: 'Va pfuka nimpundzu swinene, va hlambanyisana; kutani Isaka a va tshika va famba, va suka eka yena hi ku rhula.' },
    { n: 32, text: 'Hi siku rero malandza ya Isaka ya fika, ya n\u2019wi hlamusela hi ta xihlovo lexi ya nga xi kela, ya ku eka yena: Hi kumile mati!' },
    { n: 33, text: 'A xi thya vito ra Xiba; hikwalaho vito ra muti lowu ku nga Berixeba ku fikela namuntlha.' },
    { n: 34, text: 'Esawu a a ri ni malembe ya makume mana loko a teka Yuditi n\u2019wana wa Beri wa Muheti, na Basemati n\u2019wana wa Eloni wa Muheti, va va vasati va yena;' },
    { n: 35, text: 'vona va tisele Isaka na Rebeka mbitsi swinene embilwini.' },
  ],
  27: [
    { n: 1, text: 'Loko Isaka a dyuhele, mahlo ya yena ya dgyungula a nga ha voni, a vitana Esawu n\u2019wana wa yena lonkulu, a ku eka yena: N\u2019wananga! A hlamula, a ku: Hi mina loyi.' },
    { n: 2, text: 'Isaka a ku: Vona, ndzi dyuhele; a ndzi tivi siku ra ku fa ka mina.' },
    { n: 3, text: 'Sweswi teka swilwi swa wena, nkoba wa wena ni vurha bya wena, u ya ensinwini u ya ndzi hlotela swihari;' },
    { n: 4, text: 'u ndzi swekela swakudya swo nandziha, leswi ndzi swi rhandzaka, u ndzi tisela ndzi dya, leswaku moya wa mina wu ku katekisa ndzi nga si fa.' },
    { n: 5, text: 'Rebeka a a yingisela loko Isaka a vulavula ni Esawu n\u2019wana wa yena. Esawu a ya ensinwini ku ya hlota xihari leswaku a xi tisa.' },
    { n: 6, text: 'Kutani Rebeka a vulavula ni Jakobe n\u2019wana wa yena, a ku: Vona, ndzi twile tata wa wena a vulavula ni Esawu makwenu, a ku:' },
    { n: 7, text: '\u2018Ndzi tisele xihari, u ndzi swekela swakudya swo nandziha ndzi dya, ndzi ku katekisa mahlweni ka Hosi ndzi nga si fa.\u2019' },
    { n: 8, text: 'Sweswi n\u2019wananga, yingisa rito ra mina eka leswi ndzi ku lerisaka swona.' },
    { n: 9, text: 'Yana exifuwyweni, u ndzi tekela swimbutani swimbirhi leswinene swa swimitsana, ndzi ta swi swekela tata wa wena swakudya swo nandziha, leswi a swi rhandzaka;' },
    { n: 10, text: 'u ta swi yisa eka tata wa wena leswaku a dya, a ku katekisa a nga si fa.' },
    { n: 11, text: 'Jakobe a ku eka Rebeka mana wa yena: Vona, Esawu makwerhu i wanuna wa voya, kambe mina ndzi munhu wo olova;' },
    { n: 12, text: 'kumbexana tata wa mina a nga ndzi khumba, kutani a nga ndzi vona ndzi ri mukanganyisi, ndzi tivangela rusinga handle ka nkateko.' },
    { n: 13, text: 'Mana wa yena a ku eka yena: Rusinga ra wena a ri wele eka mina, n\u2019wananga; yingisa rito ra mina ntsena, yana u ndzi tekela swona.' },
    { n: 14, text: 'A ya, a swi teka, a swi tisa eka mana wa yena; kutani mana wa yena a sweka swakudya swo nandziha, leswi tata wa yena a a swi rhandza.' },
    { n: 15, text: 'Rebeka a teka swiambalo swo saseka swa Esawu n\u2019wana wa yena lonkulu, leswi a a ri na swona endlwini, a swi ambelelisa Jakobe n\u2019wana wa yena lontsongo;' },
    { n: 16, text: 'a funengeta mavoko ya yena ni ndhawu yo olova ya nhlongo ya yena hi madzovo ya swimbutani;' },
    { n: 17, text: 'a nyika Jakobe n\u2019wana wa yena swakudya swo nandziha ni xinkwa lexi a xi lulamiseke.' },
    { n: 18, text: 'Jakobe a nghena eka tata wa yena, a ku: Tatana! A hlamula, a ku: Hi mina loyi; u mani wena n\u2019wananga ke?' },
    { n: 19, text: 'Jakobe a ku eka tata wa yena: Hi mina Esawu mativula ya wena; ndzi endlile hilaha u ndzi byeleke hakona; ndzi kombela u pfuka, u tshama u dya xihari xa mina, leswaku moya wa wena wu ndzi katekisa.' },
    { n: 20, text: 'Isaka a ku eka n\u2019wana wa yena: U hatlise njhani ku xi kuma, n\u2019wananga? A ku: Hikuva Hosi, Xikwembu xa wena, xi ndzi endlerile leswaku xi hatla xi humelela.' },
    { n: 21, text: 'Isaka a ku eka Jakobe: Ndzi kombela u tshinela kusuhi, ndzi ku khumba, n\u2019wananga, ndzi tiva loko u ri Esawu n\u2019wananga hakunene kumbe e-e.' },
    { n: 22, text: 'Jakobe a tshinela kusuhi ni Isaka tata wa yena; a n\u2019wi khumba, a ku: Rito i rito ra Jakobe, kambe mavoko i mavoko ya Esawu.' },
    { n: 23, text: 'A nga n\u2019wi tivanga, hikuva mavoko ya yena a a ri ni voya ku fana ni mavoko ya Esawu makwenu; hiloko a n\u2019wi katekisa.' },
    { n: 24, text: 'A vutisa, a ku: U Esawu n\u2019wananga hakunene ke? A hlamula, a ku: Hi mina.' },
    { n: 25, text: 'Isaka a ku: Ndzi tisele, ndzi dya xihari xa n\u2019wananga, leswaku moya wa mina wu ku katekisa. A n\u2019wi tisela, a dya; a n\u2019wi tisela ni vhinyo, a nwa.' },
    { n: 26, text: 'Isaka tata wa yena a ku eka yena: Ndzi kombela u tshinela kusuhi u ndzi ntsgontsga, n\u2019wananga.' },
    { n: 27, text: 'A tshinela, a n\u2019wi ntsgontsga; Isaka a nunhwela ku nunhwerila ka swiambalo xa yena, a n\u2019wi katekisa, a ku: Vona, ku nunhwela ka n\u2019wananga ku fana ni ku nunhwela ka nsimu leyi Hosi yi yi katekiseke.' },
    { n: 28, text: 'Xikwembu a xi ku nyike mberha ya tilo, ni ku nona ka misava, ni mavele yo tala swinene ni vhinyo leyintshwa.' },
    { n: 29, text: 'Matiko a ma ku tirhele, tinxaka ti ku nkhinsamela; u va hosi ya vamakwenu, vana va mana wa wena va ku korhamela; lava ku dgyungetaka va ku dgyungetiwa, kutani lava ku katekisaka va katekisiwa.' },
    { n: 30, text: 'Loko Isaka a hete ku katekisa Jakobe, Jakobe a nga si huma mahlweni ka Isaka tata wa yena, Esawu makwenu a fika a huma ku hloteni.' },
    { n: 31, text: 'A sweka na yena swakudya swo nandziha, a swi tisa eka tata wa yena, a ku: Tata wa mina a a pfuke, a dya xihari xa n\u2019wana wa yena, leswaku moya wa wena wu ndzi katekisa.' },
    { n: 32, text: 'Isaka tata wa yena a ku eka yena: U mani wena? A ku: Hi mina n\u2019wana wa wena, mativula ya wena Esawu.' },
    { n: 33, text: 'Isaka a rhendzeka swinene hi ku chava lokukulu, a ku: I mani loyi a hloteke xihari a ndzi tisela xona, ndzi dyeke hinkwaswo u nga si fika, ndzi n\u2019wi katekisa ke? Inene, u ta va la katekisiweke!' },
    { n: 34, text: 'Loko Esawu a twa marito ya tata wa yena, a rila hi ku rila lokukulu ni ko bava swinene, a ku eka tata wa yena: Ndzi katekise na mina, tatana!' },
    { n: 35, text: 'Isaka a ku: Makwenu u tile hi vukanganyisi, a teka nkateko wa wena.' },
    { n: 36, text: 'Esawu a ku: Xana a hi yona mhaka leyi a thyiweke vito ra Jakobe ke? Hikuva u ndzi kanganyisile kambirhi: u tekile vutivula bya mina, kutani sweswi u tekile nkateko wa mina! A tlhela a ku: Xana a ku ndzi sielanga nkateko ke?' },
    { n: 37, text: 'Isaka a hlamula, a ku eka Esawu: Vona, ndzi n\u2019wi endlile hosi ya wena, ndzi n\u2019wi nyika vamakwenu hinkwavo va va malandza ya yena; ndzi n\u2019wi nyikile mavele ni vhinyo; sweswi xana ndzi nga ku endlela yini wena n\u2019wananga ke?' },
    { n: 38, text: 'Esawu a ku eka tata wa yena: Xana u ni nkateko wun\u2019we ntsena, tatana? Ndzi katekise na mina, tatana! Hiloko Esawu a tlimba rito, a rila swinene.' },
    { n: 39, text: 'Isaka tata wa yena a hlamula, a ku eka yena: Vona, vutshamo bya wena byi ta va kule ni ku nona ka misava, ni kule ni mberha ya tilo leyi humaka ehenhla.' },
    { n: 40, text: 'U ta hanya hi banga ra wena, u tirhela makwenu; kambe ku ta fika nkarhi lowu u nga ta thlavula joko ra yena enhan\u2019wini wa wena.' },
    { n: 41, text: 'Esawu a fambisa rivengo eka Jakobe hikwalaho ka nkateko lowu tata wa yena a n\u2019wi katekiseke ha wona; Esawu a ku embilwini ya yena: Masiku ya ku rila tata wa mina ya kusuhi; hi kona ndzi nga ta dlaya Jakobe makwerhu.' },
    { n: 42, text: 'Va hlamusela Rebeka marito ya Esawu n\u2019wana wa yena lonkulu; hiloko a rhumela ku ya vitana Jakobe n\u2019wana wa yena lontsongo, a ku eka yena: Vona, Esawu makwenu wa chaveleleka hi ku lava ku ku dlaya.' },
    { n: 43, text: 'Sweswi n\u2019wananga, yingisa rito ra mina: pfuka, u balekela eka Labani makwerhu le Harani;' },
    { n: 44, text: 'u tshama na yena masiku matsongo, ku fikela loko mbitsi wa makwenu wu hlaheka;' },
    { n: 45, text: 'ku fikela loko ku hlundguka ka makwenu ku suka eka wena, a rivala leswi u n\u2019wi endleke swona; hi kona ndzi nga ta rhumela vanhu va ya ku teka kwalaho; ha yini ndzi ferwa hi n\u2019wina hinkwenu hi siku rin\u2019wana ke?' },
    { n: 46, text: 'Rebeka a ku eka Isaka: Ndzi dgyungule vutomi bya mina hikwalaho ka vana va Heti va vavasati; loko Jakobe a teka nsati eka vana va Heti, lava fanyaka ni lava va tiko leri, vutomi bya mina byi ta va ni dgyondzo yihi ke?' },
  ],
  28: [
    { n: 1, text: 'Isaka a vitana Jakobe, a n\u2019wi katekisa, a n\u2019wi lerisa, a ku: U nga ka u nga teki nsati eka vanhwanyana va Vakanana.' },
    { n: 2, text: 'Pfuka, u ya ePadani-Aramu endlwini ya Betuele tata wa mana wa wena, u ya titekela nsati kwalaho eka vanhwanyana va Labani makwenu wa mana wa wena.' },
    { n: 3, text: 'Xikwembu xa Matimba Hinkwato a xi ku katekise, xi ku andgisa, xi ku tswalisa, u hundzuka nhlengeletano ya vanhu;' },
    { n: 4, text: 'a xi ku nyike nkateko wa Abrahama, wena ni mbewu ya wena na wena, leswaku u dgya tiko ra vuluveri bya wena, leri Xikwembu xi nga xi nyika Abrahama.' },
    { n: 5, text: 'Isaka a fambisa Jakobe, kutani a ya ePadani-Aramu eka Labani n\u2019wana wa Betuele wa Muarame, makwenu wa Rebeka, mana wa Jakobe na Esawu.' },
    { n: 6, text: 'Esawu a vona leswaku Isaka u katekisile Jakobe, a n\u2019wi fambisile ePadani-Aramu leswaku a ya teka nsati kwalaho, ni leswaku, loko a n\u2019wi katekisa, a n\u2019wi lerisile a ku: \u2018U nga teki nsati eka vanhwanyana va Vakanana,\u2019' },
    { n: 7, text: 'ni leswaku Jakobe u yingisile tata wa yena ni mana wa yena, a famba ePadani-Aramu;' },
    { n: 8, text: 'Esawu a vona ni leswaku vanhwanyana va Vakanana a va nga tsakisi Isaka tata wa yena.' },
    { n: 9, text: 'Hiloko Esawu a ya eka Ismayele, a teka Mahalati, n\u2019wana wa Ismayele n\u2019wana wa Abrahama, makwerhu wa xisati wa Nebayoti, a va nsati wa yena, handle ka lava a a ri na vona.' },
    { n: 10, text: 'Jakobe a suka eBerixeba, a kongoma eHarani.' },
    { n: 11, text: 'A fika endhawini yo karhi, a etlela kwalaho hikuva dyambu a dyi pelerile; a teka rin\u2019we ra maribye ya ndhawu yoleyo, a ri veka ehansi ka nhloko ya yena, a etlela kwalaho.' },
    { n: 12, text: 'A lora, kutani vonani, ku ri ni xitepisi lexi yimiyeke ehansi, nhloko ya xona yi fika etilweni; kutani ntsumi ta Xikwembu a ti tlhandluka ni ku xika ha xona.' },
    { n: 13, text: 'Kuni vonani, Hosi a yi yimile ehenhla ka xona, yi ku: Hi mina Hosi, Xikwembu xa Abrahama tata wa wena, ni Xikwembu xa Isaka; tiko leri u etleleke eka rona, ndzi ta ku nyika rona ni mbewu ya wena;' },
    { n: 14, text: 'mbewu ya wena yi ta fana ni ntshuri wa misava, u ta hangalaka hi tlhelo ra le Vuxeni, ra le handle, ra le n\u2019walungwini ni ra le dzongeni; kutani tinxaka hinkwato ta misava ti ta katekisiwa eka wena ni le ka mbewu ya wena.' },
    { n: 15, text: 'Vona, ndzi na wena, ndzi ta ku hlayisa hinkwako lomu u nga ta ya kona, ndzi ku vuyisela etikweni leri; hikuva ndzi nga ka ndzi nga ku tshiki ndzi nga si endla leswi ndzi ku byeleke swona.' },
    { n: 16, text: 'Jakobe a pfuka exirhwini xa yena, a ku: Inene, Hosi yi le ndhawini leyi, kasi mina a ndzi nga swi tivi!' },
    { n: 17, text: 'A khomiwa hi ku chava, a ku: Ndhawu leyi yi chavisa swonghasi! Leyi a hi yin\u2019wana handle ka yindlu ya Xikwembu, kutani leyi i nyangwa ya tilo.' },
    { n: 18, text: 'Jakobe a pfuka swinene nimpundzu, a teka ribye leri a a ri vekile ehansi ka nhloko ya yena, a xi yimisa xi va phuphu, a chulula mafurha ehenhla ka xona.' },
    { n: 19, text: 'A thya ndhawu yoleyo vito ra Betele; kambe vito ra muti lowu a ku ri Luzi mahlweni.' },
    { n: 20, text: 'Jakobe a endla xihlambanyo, a ku: Loko Xikwembu xi ta va na mina, xi ndzi hlayisa endleleni leyi ndzi fambaka ha yona, xi ndzi nyika xinkwa ndzi dya ni swiambalo ndzi ambala,' },
    { n: 21, text: 'ndzi vuyela endlwini ya tata wa mina hi ku rhula, hi kona Hosi yi nga ta va Xikwembu xa mina;' },
    { n: 22, text: 'kutani ribye leri ndzi nga ri yimisa ri va phuphu ri ta va yindlu ya Xikwembu; eka hinkwaswo leswi u nga ta ndzi nyika swona, ndzi ta ku nyika khume ra swona.' },
  ],
  29: [
    { n: 1, text: 'Jakobe a nkhinsama a famba, a fika etikweni ra vana va le Vuxeni.' },
    { n: 2, text: 'A languta, a vona xihlovo erivaleni, na ku ri ni mintlhambi minharhu ya tiyimpfu leyi tshamaka kusuhi na xona; hikuva va nwisa mintlhambi exihlovweni xexo; kutani ribye leri pfaraka xihlovo a ri ri rikulu.' },
    { n: 3, text: 'Loko mintlhambi hinkwayo yi hlengeletana kwalaho, varisi va khunguluxa ribye enonwini wa xihlovo, va nwisa tiyimpfu, va tlhela va vuyisela ribye endhawini ya rona enonwini wa xihlovo.' },
    { n: 4, text: 'Jakobe a vutisa varisi, a ku: Vamakwerhu, mi huma kwihi ke? Va ku: Hi huma le Harani.' },
    { n: 5, text: 'A ku eka vona: Xana ma n\u2019wi tiva Labani n\u2019wana wa Nakore ke? Va ku: Ha n\u2019wi tiva.' },
    { n: 6, text: 'A ku eka vona: Xana u hanyi hinkwaswo ke? Va ku: U hanyi; kutani vona, Rahele n\u2019wana wa yena wa xisati u karhi u ta ni tiyimpfu.' },
    { n: 7, text: 'Jakobe a ku: Vona, dyambu ra ha ri ehenhla, a hi nkarhi wa ku hlengeletana ka swifuwo; nwisani tiyimpfu, mi ya ti dyisa.' },
    { n: 8, text: 'Kambe va ku: Hi nga ka hi nga endli tano ku fikela loko mintlhambi hinkwayo yi hlengeletana, va khunguluxa ribye enonwini wa xihlovo; hi kona hi nga ta nwisa tiyimpfu.' },
    { n: 9, text: 'A nga si heta ku vulavula na vona, Rahele a fika ni tiyimpfu ta tata wa yena, hikuva a a ri murisi.' },
    { n: 10, text: 'Loko Jakobe a vona Rahele n\u2019wana wa Labani makwenu wa mana wa yena, ni tiyimpfu ta Labani, Jakobe a tshinela, a khunguluxa ribye enonwini wa xihlovo, a nwisa tiyimpfu ta Labani.' },
    { n: 11, text: 'Jakobe a ntsgontsga Rahele, a tlimba rito, a rila.' },
    { n: 12, text: 'Jakobe a hlamusela Rahele leswaku i makwenu wa tata wa yena, ni leswaku i n\u2019wana wa Rebeka; hiloko Rahele a tsutsuma, a ya hlamusela tata wa yena.' },
    { n: 13, text: 'Loko Labani a twa swiviko hi ta Jakobe n\u2019wana wa makwenu wa yena, a tsutsuma a ya n\u2019wi hlanganisa, a n\u2019wi tlimba, a n\u2019wi ntsgontsga, a n\u2019wi nghenisa endlwini ya yena. Kutani Jakobe a hlamusela Labani swilo leswi hinkwaswo.' },
    { n: 14, text: 'Labani a ku eka yena: Inene, u rhandza ra mina ni nyama ya mina. Kutani Jakobe a tshama na yena nkarhi wa n\u2019weti hinkwawo.' },
    { n: 15, text: 'Labani a ku eka Jakobe: Xana u ta ndzi tirhela mahala hikwalaho ka leswi u nga makwerhu ke? Ndzi byele, hakelo ya wena yi ta va yini ke?' },
    { n: 16, text: 'Labani a a ri ni vana vambirhi va vanhwanyana: vito ra lonkulu a ku ri Leya, kutani vito ra lontsongo a ku ri Rahele.' },
    { n: 17, text: 'Leya a a ri ni mahlo yo tsana, kambe Rahele a a sasekile swinene hi xivumbeko ni ku languteka.' },
    { n: 18, text: 'Jakobe a a rhandza Rahele, hiloko a ku: Ndzi ta ku tirhela ntlhanu na mambirhi wa malembe hikwalaho ka Rahele n\u2019wana wa wena lontsongo.' },
    { n: 19, text: 'Labani a ku: Swi nene ku n\u2019wi nyika wena ku tlula ku n\u2019wi nyika wanuna un\u2019wana; tshama na mina.' },
    { n: 20, text: 'Kutani Jakobe a tirha malembe ya ntlhanu na mambirhi hikwalaho ka Rahele; kambe eka yena a ma fana ni masiku matsongo ntsena hikwalaho ka rhandzu leri a a ri na rona eka yena.' },
    { n: 21, text: 'Kutani Jakobe a ku eka Labani: Ndzi nyike nsati wa mina, hikuva masiku ya mina ya fikelele leswaku ndzi nghena eka yena.' },
    { n: 22, text: 'Labani a hlengeleta vavanuna hinkwavo va ndhawu yoleyo, a endla nkhuvo.' },
    { n: 23, text: 'Nimpundzu ni madyambu, a teka Leya n\u2019wana wa yena, a n\u2019wi tisa eka Jakobe; kutani Jakobe a nghena eka yena.' },
    { n: 24, text: 'Labani a nyika Silipa nandza wa yena wa xisati eka Leya n\u2019wana wa yena leswaku a va nandza wa yena.' },
    { n: 25, text: 'Nimpundzu, vonani, a ku ri Leya! Hiloko Jakobe a ku eka Labani: I yini lexi u ndzi endleke xona ke? Xana a ndzi ku tirhelanga hikwalaho ka Rahele ke? Ha yini u ndzi kanganyisile ke?' },
    { n: 26, text: 'Labani a ku: A hi mukhuva wa ndhawu ya hina ku nyika lontsongo mahlweni ka lonkulu.' },
    { n: 27, text: 'Heleleta vhiki leri ra nkhuvo wa loyi, kutani hi ta ku nyika ni loyi un\u2019wana hikwalaho ka ntirho lowu u nga ta ndzi tirhela wona malembe man\u2019wana ya ntlhanu na mambirhi.' },
    { n: 28, text: 'Jakobe a endla tano, a heleleta vhiki ra nkhuvo; hiloko Labani a n\u2019wi nyika Rahele n\u2019wana wa yena ku va nsati wa yena.' },
    { n: 29, text: 'Labani a nyika Bila nandza wa yena wa xisati eka Rahele n\u2019wana wa yena leswaku a va nandza wa yena.' },
    { n: 30, text: 'Jakobe a nghena na eka Rahele, a rhandza Rahele ku tlula Leya; a tlhela a tirhela Labani malembe man\u2019wana ya ntlhanu na mambirhi.' },
    { n: 31, text: 'Loko Hosi yi vona leswaku Leya a a vengiwa, yi pfula khwiri ra yena, kambe Rahele a a ri ngumba.' },
    { n: 32, text: 'Leya a tika, a tswala n\u2019wana wa xinuna, a n\u2019wi thya vito ra Rubeni, hikuva a ku: Hosi yi vonile khombo ra mina; sweswi nuna wa mina u ta ndzi rhandza.' },
    { n: 33, text: 'A tlhela a tika, a tswala n\u2019wana wa xinuna, a ku: Hikuva Hosi yi twile leswaku ndzi vengiwa, yi ndzi nyikile ni loyi na yena; hiloko a n\u2019wi thya vito ra Simiyoni.' },
    { n: 34, text: 'A tlhela a tika, a tswala n\u2019wana wa xinuna, a ku: Sweswi nuna wa mina u ta namarhela eka mina, hikuva ndzi n\u2019wi tswalele vana vanharhu va xinuna; hikwalaho vito ra yena ri thiyiweke Levhi.' },
    { n: 35, text: 'A tlhela a tika, a tswala n\u2019wana wa xinuna, a ku: Khari leri ndzi ta dzunisa Hosi; hikwalaho a n\u2019wi thyeke vito ra Yuda. Kutani a nyima ku tswala.' },
  ],
  30: [
    { n: 1, text: 'Loko Rahele a vona leswaku a nga n\u2019wi tswaleli Jakobe vana, Rahele a rhandzela makwenu wa yena, a ku eka Jakobe: Ndzi nyike vana, loko swi nga ri tano ndzi ta fa!' },
    { n: 2, text: 'Ku hlundguka ka Jakobe ku pfuka eka Rahele, a ku: Xana ndzi le ndhawini ya Xikwembu, lexi nga ku tsona mbhandzu wa khwiri ke?' },
    { n: 3, text: 'Rahele a ku: Vona, Bila nandza wa mina wa xisati; nghena eka yena, leswaku a tswalla emavokweni ya mina, na mina ndzi kuma vana ha yena.' },
    { n: 4, text: 'Hiloko a n\u2019wi nyika Bila nandza wa yena ku va nsati, kutani Jakobe a nghena eka yena.' },
    { n: 5, text: 'Bila a tika, a tswalela Jakobe n\u2019wana wa xinuna.' },
    { n: 6, text: 'Rahele a ku: Xikwembu xi ndzi avanyisile, xi twile ni rito ra mina, xi ndzi nyika n\u2019wana wa xinuna; hikwalaho a n\u2019wi thyeke vito ra Dani.' },
    { n: 7, text: 'Bila nandza wa Rahele a tlhela a tika, a tswalela Jakobe n\u2019wana wa vumbirhi wa xinuna.' },
    { n: 8, text: 'Rahele a ku: Ndzi luvile ku lwa lokukulu ni makwerhu, kutani ndzi hlurile; hiloko a n\u2019wi thya vito ra Neftali.' },
    { n: 9, text: 'Loko Leya a vona leswaku u nyimile ku tswala, a teka Silipa nandza wa yena wa xisati, a n\u2019wi nyika Jakobe ku va nsati.' },
    { n: 10, text: 'Silipa nandza wa Leya a tswalela Jakobe n\u2019wana wa xinuna.' },
    { n: 11, text: 'Leya a ku: Nkateko wu tile! Hiloko a n\u2019wi thya vito ra Gadi.' },
    { n: 12, text: 'Silipa nandza wa Leya a tswalela Jakobe n\u2019wana wa vumbirhi wa xinuna.' },
    { n: 13, text: 'Leya a ku: Ndzi ntsako! Hikuva vanyana va xisati va ta ndzi vula la ntsakeke; hiloko a n\u2019wi thya vito ra Axere.' },
    { n: 14, text: 'Rubeni a ya ensinwini hi masiku ya ku tsemela mavele, a kuma timandragora, a ti tisa eka Leya mana wa yena. Rahele a ku eka Leya: Ndzi kombela u ndzi nyika timandragora ta n\u2019wana wa wena.' },
    { n: 15, text: 'Kambe Leya a ku eka yena: Xana i ntsongo ku teka nuna wa mina, lerova u lava ni ku teka timandragora ta n\u2019wana wa mina ke? Rahele a ku: Swi nene, u ta etlela na wena vusiku bya namuntlha hikwalaho ka timandragora ta n\u2019wana wa wena.' },
    { n: 16, text: 'Madyambu, loko Jakobe a vuye hi le nsinwini, Leya a huma ku ya n\u2019wi hlanganisa, a ku: U fanele ku nghena eka mina, hikuva ndzi ku xavile hakunene hi timandragora ta n\u2019wana wa mina. Hiloko a etlela na yena hi vusiku byoloyo.' },
    { n: 17, text: 'Xikwembu xi yingisa Leya, a tika, a tswalela Jakobe n\u2019wana wa vuntlhanu wa xinuna.' },
    { n: 18, text: 'Leya a ku: Xikwembu xi ndzi nyikile hakelo ya mina, hikuva ndzi nyike nuna wa mina nandza wa mina wa xisati; hiloko a n\u2019wi thya vito ra Isakara.' },
    { n: 19, text: 'Leya a tlhela a tika, a tswalela Jakobe n\u2019wana wa vutsetsene wa xinuna.' },
    { n: 20, text: 'Leya a ku: Xikwembu xi ndzi nyikile nyiko leyinene; sweswi nuna wa mina u ta tshama na mina, hikuva ndzi n\u2019wi tswalele vana va xinuna va tsetsene; hiloko a n\u2019wi thya vito ra Zebuloni.' },
    { n: 21, text: 'Endzhaku ka swona a tswala n\u2019wana wa xisati, a n\u2019wi thya vito ra Dina.' },
    { n: 22, text: 'Xikwembu xi tsundguka Rahele, xi n\u2019wi yingisela, xi pfula khwiri ra yena.' },
    { n: 23, text: 'A tika, a tswala n\u2019wana wa xinuna, a ku: Xikwembu xi herise xisandzu xa mina.' },
    { n: 24, text: 'A n\u2019wi thya vito ra Josefa, a ku: Hosi a yi ndzi engetelele n\u2019wana un\u2019wana wa xinuna.' },
    { n: 25, text: 'Loko Rahele a tswale Josefa, Jakobe a ku eka Labani: Ndzi fambise ndzi ya endhawini ya mina ni le tikweni ra mina.' },
    { n: 26, text: 'Ndzi nyike vasati va mina ni vana va mina, lava ndzi ku tirheleke hikwalaho ka vona, ndzi famba; hikuva u ntsengo wa ntirho lowu ndzi ku endleleke wona.' },
    { n: 27, text: 'Labani a ku eka yena: Loko ndzi kumile tintswalo mahlweni ka wena, ndzi kombela u tshama; ndzi vone hi ku vhumbha leswaku Hosi yi ndzi katekise hikwalaho ka wena.' },
    { n: 28, text: 'A tlhela a ku: Ndzi byele hakelo ya wena, kutani ndzi ta ku nyika yona.' },
    { n: 29, text: 'Jakobe a ku eka yena: Wa swi tiva lesvi ndzi ku tirheleke hakona, ni lesvi swifuwo swa wena swi nga va xiswona ehansi ka mina;' },
    { n: 30, text: 'hikuva switsongo leswi u nga va na swona ndzi nga si fika swi andgise swinene, kutani Hosi yi ku katekise hinkwako lomu ndzi kandziyeke kona; sweswi xana ndzi ta lulamisela yindlu ya mina rini ke?' },
    { n: 31, text: 'Labani a ku: Ndzi ta ku nyika yini ke? Jakobe a ku: U nga ndzi nyiki nchumu; loko u ndzi endlela mhaka leyi, ndzi ta tlhela ndzi risa ni ku hlayisa swifuwo swa wena:' },
    { n: 32, text: 'Ndzi ta hundza exikarhi ka swifuwo swa wena hinkwaswo namuntlha, ndzi hambanisa kwalaho tiyimpfu hinkwato leti nga ni mavala ni leti nga ni swivati, ni tiyimpfu hinkwato leti ntshuku exikarhi ka tiyimpfu letitsongo, ni timbuti leti nga ni swivati ni leti nga ni mavala; yoleyo yi ta va hakelo ya mina.' },
    { n: 33, text: 'Kutani ku lulama ka mina ku ta ndzi hlamulela mundzuku, loko u fika ku ta kambela hakelo ya mina: hinkwato leti nga riki na mavala ni swivati exikarhi ka timbuti, ni leti nga riki ntshuku exikarhi ka tiyimpfu letitsongo, ti ta va leti yiviweke hi mina.' },
    { n: 34, text: 'Labani a ku: Swi nene, a ku ve hilaha u vuleke hakona.' },
    { n: 35, text: 'Hi siku rero Labani a hambanisa swiphongo leswi nga ni mikondzo ni leswi nga ni mavala, ni timbuti hinkwato leti nga ni swivati ni leti nga ni mavala, hinkwato leti nga ni swontshuka, ni leti ntshuku exikarhi ka tiyimpfu, a swi nyika emavokweni ya vana va yena;' },
    { n: 36, text: 'a veka mpfhuka wa masiku manharhu exikarhi ka yena na Jakobe; kutani Jakobe a risa swifuwo swa Labani leswi saleke.' },
    { n: 37, text: 'Jakobe a teka rhavi ra ntsgandza lowu ntsaka, ni ra alimondi, ni ra plane, a tsemeta mahlongo ya swirhavi leswaku ku humelela swo tshwuka endzeni ka swona.' },
    { n: 38, text: 'A veka swirhavi leswi a nga swi tsemeta mahlweni ka swifuwo etshalweni ra mati lomu swifuwo swi taka nwela kona, leswaku swi pfapfana loko swi ta nwela mati.' },
    { n: 39, text: 'Swifuwo swi pfapfana mahlweni ka swirhavi, kutani swi tswala swifuwo leswi nga ni mikondzo, ni swivati, ni mavala.' },
    { n: 40, text: 'Jakobe a hambanisa swinyimpfana, a kongomisa swikandza xa swifuwo eka leswi nga ni mikondzo ni swifuwo hinkwaswo swa Labani; a veka swifuwo swa yena swi ri swoxe, a nga swi veki ni swifuwo swa Labani.' },
    { n: 41, text: 'Kuni ku nga va leswaku loko swifuwo leswi nga ni matimba swi lava ku pfapfana, Jakobe a veka swirhavi mahlweni ka swifuwo etshalweni ra mati, leswaku swi pfapfana exikarhi ka swirhavi;' },
    { n: 42, text: 'kambe loko swifuwo swi nga ri na matimba, a nga swi veki; hiloko leswo tsana swi va swa Labani, kutani leswo tiya swi va swa Jakobe.' },
    { n: 43, text: 'Wanuna a fuma swinene-nene, a va ni swifuwo swo tala swinene, ni malandza ya xisati, ni malandza ya xinuna, ni tikamela, ni timbhongolo.' },
  ],
  31: [
    { n: 1, text: 'Jakobe a twa marito ya vana va Labani, va ku: Jakobe u tekile hinkwaswo leswi a swi ri swa tata wa hina, kutani hi swilo swa tata wa hina u kumile ku fuma loku hinkwako.' },
    { n: 2, text: 'Jakobe a languta xikandza xa Labani, a vona leswaku a xi nga ha ri eka yena ku fana ni le mahlweni.' },
    { n: 3, text: 'Hosi yi ku eka Jakobe: Vuyela etikweni ra vatata wa wena ni le ka vaka n\u2019wina, kutani ndzi ta va na wena.' },
    { n: 4, text: 'Jakobe a rhumela ku ya vitana Rahele na Leya leswaku va ta nsinwini eka swifuwo wa yena,' },
    { n: 5, text: 'a ku eka vona: Ndzi vona xikandza xa tata wa n\u2019wina, xi nga ha ri eka mina ku fana ni le mahlweni; kambe Xikwembu xa tata wa mina xi na mina.' },
    { n: 6, text: 'Kutani n\u2019wina ma swi tiva leswaku ndzi tirhele tata wa n\u2019wina hi matimba ya mina hinkwaswo;' },
    { n: 7, text: 'kambe tata wa n\u2019wina u ndzi kanganyisile, a hundgula hakelo ya mina ka khume; kambe Xikwembu a xi n\u2019wi pfumelelangi ku ndzi endlela swo biha.' },
    { n: 8, text: 'Loko a vurile a ku: \u2018Leswi nga ni mavala swi ta va hakelo ya wena,\u2019 kutani swifuwo hinkwaswo swi tswala leswi nga ni mavala; loko a vurile a ku: \u2018Leswi nga ni mikondzo swi ta va hakelo ya wena,\u2019 kutani swifuwo hinkwaswo swi tswala leswi nga ni mikondzo.' },
    { n: 9, text: 'Hi mukhuva wolowo Xikwembu xi tekile swifuwo swa tata wa n\u2019wina, xi ndzi nyika swona.' },
    { n: 10, text: 'Ku nga va leswaku hi nkarhi lowu swifuwo swi pfapfanaka, ndzi tlakusa mahlo ya mina ndzi lora, ndzi vona swiphongo leswi pfapfanaka ni swifuwo swi ri ni mikondzo, ni swivati, ni mavala.' },
    { n: 11, text: 'Ntsumi ya Xikwembu yi ku eka mina emilorweni: Jakobe! Ndzi ku: Hi mina loyi.' },
    { n: 12, text: 'Yi ku: Tlakusa mahlo ya wena u languta, swiphongo hinkwaswo leswi pfapfanaka ni swifuwo swi ni mikondzo, ni swivati, ni mavala; hikuva ndzi vonile hinkwaswo leswi Labani a ku endlelaka swona.' },
    { n: 13, text: 'Hi mina Xikwembu xa Betele, lomu u nga tota phuphu hi mafurha, lomu u nga endla xihlambanyo eka mina; sweswi pfuka, u suka etikweni leri, u vuyela etikweni ra vutswari ra wena.' },
    { n: 14, text: 'Rahele na Leya va hlamula, va ku eka yena: Xana ka ha ri ni xiavelana kumbe ndzhaka ya hina endlwini ya tata wa hina ke?' },
    { n: 15, text: 'Xana a hi vuriwi vahlapfa eka yena ke? Hikuva u hi xavisile, a tlhela a dya mali ya hina hi ku helela.' },
    { n: 16, text: 'Hinkwaswo swilo leswi Xikwembu xi swi tekeke eka tata wa hina i swa hina ni swa vana va hina; sweswi, hinkwaswo leswi Xikwembu xi ku byeleke swona, swi endle.' },
    { n: 17, text: 'Hiloko Jakobe a pfuka, a palamisa vana va yena ni vasati va yena eka tikamela;' },
    { n: 18, text: 'a fambisa swifuwo wa yena hinkwaswo ni swilo swa yena hinkwaswo leswi a nga swi kuma, swifuwo swa ndzhaka ya yena leswi a nga swi kuma ePadani-Aramu, leswaku a ya eka Isaka tata wa yena etikweni ra Kanana.' },
    { n: 19, text: 'Loko Labani a yile ku tsemeta voya bya tiyimpfu ta yena, Rahele a yiva swifaniso swa swikwembu swa yindlu ya tata wa yena.' },
    { n: 20, text: 'Jakobe a kanganyisa Labani wa Muarame hi ku nga n\u2019wi hlamuseli leswaku u karhi u baleka.' },
    { n: 21, text: 'Hiloko a baleka ni hinkwaswo leswi a a ri na swona; a pfuka, a tsemakanya Nambu, a kongoma eka tintshava ta Giliyadi.' },
    { n: 22, text: 'Hi siku ra vunharhu va hlamusela Labani leswaku Jakobe u balekile.' },
    { n: 23, text: 'A teka vandyangu va yena na yena, a n\u2019wi landza mpfhuka wa masiku manharhu, a n\u2019wi kuma eka tintshava ta Giliyadi.' },
    { n: 24, text: 'Kambe Xikwembu xi ta eka Labani wa Muarame emilorweni ya vusiku, xi ku eka yena: Tivonele leswaku u nga vuli nchumu lowo biha kumbe lowo saseka eka Jakobe.' },
    { n: 25, text: 'Labani a fika eka Jakobe. Jakobe a a dzimile tende ra yena entshaveni; kutani Labani a dzima tende ra yena ni vandyangu va yena entshaveni ya Giliyadi.' },
    { n: 26, text: 'Labani a ku eka Jakobe: I yini lexi u xi endleke ke? U ndzi kanganyisile, u teka vana va mina va vanhwanyana ku fana ni lava khomiweke hi banga!' },
    { n: 27, text: 'Ha yini u balekile hi ku tinyentele, u ndzi yiva, u nga ndzi byeli, leswaku ndzi ku fambisa hi ku tsaka, ni hi tinsimu, ni hi swingomana ni hi haripa ke?' },
    { n: 28, text: 'U nga ndzi pfumelelangi ni ku ntsgontsga vana va mina ni vana va mina va vanhwanyana! Sweswi u endlile hi vuhunguki swinene.' },
    { n: 29, text: 'Swi le matimbeni ya voko ra mina ku mi endlela swo biha; kambe Xikwembu xa tata wa n\u2019wina xi vulavurile na mina vusiku, xi ku: \u2018Tivonele leswaku u nga vuli nchumu lowo biha kumbe lowo saseka eka Jakobe.\u2019' },
    { n: 30, text: 'Sweswi u fambile hikuva u na torha swinene ra yindlu ya tata wa wena; kambe ha yini u yiveke swikwembu swa mina ke?' },
    { n: 31, text: 'Jakobe a hlamula, a ku eka Labani: Hikuva ndzi te: Ndzi nga chava, hikuva ndzi te: Kumbexana u nga ndzi tekela vana va wena va vanhwanyana hi matimba.' },
    { n: 32, text: 'Kambe loyi u nga ta n\u2019wi kuma ni swikwembu swa wena a nga ka a nga hanyiswi; mahlweni ka vandyangu va hina kambela leswi ndzi nga na swona eka wena, u swi teka. Jakobe a a nga tivi leswaku Rahele u swi yivile.' },
    { n: 33, text: 'Labani a nghena etendeni ra Jakobe, ni le tendeni ra Leya, ni le tendeni ra malandza mambirhi ya vavasati, kambe a nga swi kumanga. A huma etendeni ra Leya, a nghena etendeni ra Rahele.' },
    { n: 34, text: 'Rahele a a tekile swikwembu swa yindlu, a swi veka ehansi ka xitshalo xa kamela, a tshama ehenhla ka swona; kutani Labani a kambela tende hinkwaro, kambe a nga swi kumanga.' },
    { n: 35, text: 'Rahele a ku eka tata wa yena: Swi nga ku hlundguki, hosi ya mina, hikuva ndzi nga ka ndzi nga pfuki mahlweni ka wena, hikuva ndzi ni mukhuva wa vavasati. Hiloko a lavisisa, kambe a nga swi kumanga swikwembu swa yindlu.' },
    { n: 36, text: 'Jakobe a hlundguka, a holovela Labani, a ku: I yini xidyoho xa mina, kumbe nandzu wa mina, lerova u ndzi landza hi ku hisa swonghasi ke?' },
    { n: 37, text: 'Loko u kambele swilo swa mina hinkwaswo, u kume yini xa yindlu ya wena ke? Xi veke kwala mahlweni ka vandyangu va mina ni vandyangu va wena, leswaku va avanyisa exikarhi ka hina vambirhi.' },
    { n: 38, text: 'Malembe lawa ya makume mambirhi ndzi na wena, tiyimpfu ta wena ni timbuti ta wena a ti nga tswali swikundzu, kutani swiphongo swa swifuwo xa wena a ndzi swi dyanga.' },
    { n: 39, text: 'Leswi nga dlayiwa hi swihari a ndzi nga ku tiselanga swona; mina ndzi hakele khombo ra swona; u swi dgyondzile emavokweni ya mina, leswi yiviweke hi nhlikanhi ni leswi yiviweke hi vusiku.' },
    { n: 40, text: 'Ndzi dgyonziwile hi ku hisa hi nhlikanhi, ni hi xirhami hi vusiku, kutani vurhongo byi balekile emahlweni ya mina.' },
    { n: 41, text: 'Hi mukhuva wolowo ndzi tshamile malembe ya makume mambirhi endlwini ya wena: ndzi ku tirhele malembe ya ntlhanu na mambirhi hikwalaho ka vana va wena vambirhi va vanhwanyana, ni malembe ya tsetsene hikwalaho ka swifuwo wa wena; kutani u hundgurile hakelo ya mina ka khume.' },
    { n: 42, text: 'Loko Xikwembu xa tata wa mina, Xikwembu xa Abrahama ni ku Chava ka Isaka, xi nga vanga na mina, inene sweswi u ndzi fambisile ndzi nga ri na nchumu; kambe Xikwembu xi vonile khombo ra mina ni ntirho wa mavoko ya mina, kutani xi ku tshinyele vusiku.' },
    { n: 43, text: 'Labani a hlamula, a ku eka Jakobe: Vanhwanyana lava i vana va mina, ni vana lava i vana va mina, ni swifuwo lewi i swifuwo swa mina, ni hinkwaswo leswi u swi vonaka i swa mina; xana ndzi nga endla yini namuntlha eka vana va mina lava, kumbe eka vana va vona lava va nga va tswala ke?' },
    { n: 44, text: 'Sweswi, tana, hi endla ntwanano, mina na wena, wu va mbhoni exikarhi ka mina na wena.' },
    { n: 45, text: 'Jakobe a teka ribye, a xi yimisa xi va phuphu.' },
    { n: 46, text: 'Jakobe a ku eka vandyangu va yena: Hlengeletani maribye! Hiloko va teka maribye, va endla nhulu; va dya kwalaho ehenhla ka nhulu.' },
    { n: 47, text: 'Labani a yi thya vito ra Jegar-Sahaduta, kambe Jakobe a yi thya vito ra Galeed.' },
    { n: 48, text: 'Labani a ku: Nhulu leyi i mbhoni exikarhi ka mina na wena namuntlha; hikwalaho vito ra yona ri thiyiweke Galeed,' },
    { n: 49, text: 'ni Mizpa, hikuva a ku: Hosi a yi langutele exikarhi ka mina na wena loko hi nga ha vonani.' },
    { n: 50, text: 'Loko u nga ta xanisa vana va mina, kumbe loko u nga ta teka vasati van\u2019wana handle ka vana va mina, ku nga na munhu na un\u2019we na hina, vona, Xikwembu i mbhoni exikarhi ka mina na wena.' },
    { n: 51, text: 'Labani a ku eka Jakobe: Vona nhulu leyi, ni phuphu leyi ndzi yi yimiseke exikarhi ka mina na wena;' },
    { n: 52, text: 'nhulu leyi i mbhoni, ni phuphu leyi i mbhoni, leswaku ndzi nga ka ndzi nga hundzi enhulu leyi ndzi fika eka wena, ni leswaku u nga ka u nga hundzi enhulu leyi ni phuphu leyi u fika eka mina ku ndzi endlela swo biha.' },
    { n: 53, text: 'Xikwembu xa Abrahama ni Xikwembu xa Nakore, Xikwembu xa vatata wa vona, a xi avanyise exikarhi ka hina. Kutani Jakobe a hlambanya hi ku Chava ka Isaka tata wa yena.' },
    { n: 54, text: 'Jakobe a endla ntlhanela entshaveni, a vitana vandyangu va yena ku ta dya xinkwa; va dya xinkwa, va etlela kwalaho entshaveni.' },
    { n: 55, text: 'Labani a pfuka nimpundzu swinene, a ntsgontsga vana va yena ni vana va yena va vanhwanyana, a va katekisa; hiloko Labani a suka, a vuyela etikweni ra yena.' },
  ],
  32: [
    { n: 1, text: 'Jakobe a famba hi ndlela ya yena, kutani tintsumi ta Xikwembu ti n\u2019wi hlanganisa.' },
    { n: 2, text: 'Loko Jakobe a ti vona, a ku: Leyi i makhampa ya Xikwembu; hiloko a thya ndhawu yoleyo vito ra Mahanayimi.' },
    { n: 3, text: 'Jakobe a rhuma varhumi mahlweni ka yena eka Esawu makwerhu wa yena etikweni ra Seyire, emugangeni wa Edomu.' },
    { n: 4, text: 'A va lerisa, a ku: Mi ta vula sweswo eka hosi ya mina Esawu: \u2018Nandza wa wena Jakobe u vula leswi: Ndzi tshamile na Labani, ndzi hlwela kona ku fikela sweswi;' },
    { n: 5, text: 'ndzi ni tihomu, ni timbhongolo, ni swifuwo letitsongo, ni malandza ya xinuna ni ya xisati; kutani ndzi rhumile ku ta tivisa hosi ya mina, leswaku ndzi kuma tintswalo mahlweni ka wena.\u2019' },
    { n: 6, text: 'Varhumi va vuyela eka Jakobe, va ku: Hi fikile eka makwenu Esawu, kutani na yena u karhi u ta ku ku hlanganisa, a ri ni vavanuna va makume manharhu ni khume.' },
    { n: 7, text: 'Jakobe a chava swinene, a karhateka; hiloko a hambanisa vanhu lava a a ri na vona, ni swifuwo letitsongo, ni tihomu, ni tikamela, a swi endla mintlhambi mambirhi;' },
    { n: 8, text: 'a ku: Loko Esawu a ta eka ntlhambi wo sungula a wu dlayetela, ntlhambi lowu saleke wu ta pona.' },
    { n: 9, text: 'Jakobe a khongela, a ku: O Xikwembu xa tata wa mina Abrahama, ni Xikwembu xa tata wa mina Isaka, Hosi leyi nga ku eka mina: \u2018Vuyela etikweni ra wena ni le ka vaka n\u2019wina, kutani ndzi ta ku endlela swo saseka,\u2019' },
    { n: 10, text: 'ndzi ntsongo eka tintswalo hinkwato ni ku tshembeka hinkwako loku u ku kombiseke nandza wa wena; hikuva ndzi tsemakanyile Yordani lowu ndzi ri ni nhonga ya mina ntsena, kutani sweswi ndzi fikele ku va mintlhambi mambirhi.' },
    { n: 11, text: 'Ndzi ponise, ndzi kombela wena, emavokweni ya makwerhu, emavokweni ya Esawu; hikuva ndzi n\u2019wi chavela, leswaku a nga fiki a ndzi dlaya, ni vamanana ni vana.' },
    { n: 12, text: 'Kambe u vurorile u ku: \u2018Inene, ndzi ta ku endlela swo saseka, ndzi andgisa kuxaka ka wena ku fana ni sava ra lwandle, leri nga pimekiki hikwalaho ka ku tala ka rona.\u2019' },
    { n: 13, text: 'A etlela kwalaho vusiku byoloyo; eka leswi a a ri na swona a teka nyiko a nyika Esawu makwerhu wa yena:' },
    { n: 14, text: 'timbuti ta titsgongo ta makume mambirhi ni khume, ni swiphongo swa makume mambirhi, tiyimpfu ta titsgongo ta makume mambirhi ni khume, ni swiphongo swa makume mambirhi,' },
    { n: 15, text: 'tikamela ta makume manharhu leti nwisaka ni vana va tona, tihomu ta makume mambirhi ni mambirhi, ni makhunzi ya khume, timbhongolo ta titsgongo ta makume mambirhi ni swingana swa khume.' },
    { n: 16, text: 'A swi nyika emavokweni ya malandza ya yena, ntlhambi ha ntlhambi wu ri woxe, a ku eka malandza ya yena: Tsemakanyani mahlweni ka mina, mi siya mpfhuka exikarhi ka ntlhambi ni ntlhambi.' },
    { n: 17, text: 'A lerisa lowo sungula, a ku: Loko Esawu makwerhu a ku hlanganisa, a ku vutisa a ku: \u2018U wa mani ke? U ya kwihi ke? I swa mani leswi swi nga mahlweni ka wena ke?\u2019' },
    { n: 18, text: 'u ta ku: \u2018I swa nandza wa wena Jakobe; i nyiko leyi rhumeriweke hosi ya mina Esawu; kutani vona, na yena u le ndzhaku ka hina.\u2019' },
    { n: 19, text: 'A lerisa ni wa vumbirhi, ni wa vunharhu, ni hinkwavo lava landzelaka mintlhambi, a ku: Mi ta vulavula ni Esawu hi marito wolawo loko mi n\u2019wi kuma;' },
    { n: 20, text: 'mi ta ku na: \u2018Vona, nandza wa wena Jakobe u le ndzhaku ka hina.\u2019 Hikuva a a ku: Ndzi ta n\u2019wi mbyonisa mbilu hi nyiko leyi yaka mahlweni ka mina, endzhaku ndzi ta vona xikandza xa yena; kumbexana u ta ndzi amukela.' },
    { n: 21, text: 'Hiloko nyiko yi tsemakanya mahlweni ka yena, kambe yena a etlela vusiku byoloyo ekhampeni.' },
    { n: 22, text: 'A pfuka vusiku byoloyo, a teka vasati va yena vambirhi, ni malandza ya yena ya xisati mambirhi, ni vana va yena va khume na un\u2019we, a tsemakanya patu ra Yaboko.' },
    { n: 23, text: 'A va teka, a va tsemakanyisa nambu, a tsemakanyisa ni hinkwaswo leswi a a ri na swona.' },
    { n: 24, text: 'Jakobe a sala a ri yexe; kutani wanuna un\u2019wana a lwa na yena ku fikela loko ku tsuvuka rika.' },
    { n: 25, text: 'Loko wanuna loyi a vona leswaku a nga n\u2019wi hluri, a n\u2019wi khumba ekhonon\u2019wini ra nenge; kutani khonon\u2019wi ra Jakobe ri konyoloka a karhi a lwa na yena.' },
    { n: 26, text: 'Wanuna a ku: Ndzi tshike ndzi famba, hikuva ri tsuvukile. Kambe Jakobe a ku: Ndzi nga ka ndzi nga ku tshiki u famba handle kokuba u ndzi katekisa.' },
    { n: 27, text: 'A ku eka yena: Vito ra wena u mani ke? A ku: Hi mina Jakobe.' },
    { n: 28, text: 'Wanuna a ku: Vito ra wena a ri nga ha vuriwi Jakobe, kambe ri ta va Israyele; hikuva u lwile ni Xikwembu ni vavanuna, kutani u hlurile.' },
    { n: 29, text: 'Jakobe a n\u2019wi vutisa, a ku: Ndzi byele vito ra wena, ndzi kombela wena. Kambe a ku: Ha yini u vutisa vito ra mina ke? Hiloko a n\u2019wi katekisa kwalaho.' },
    { n: 30, text: 'Jakobe a thya ndhawu yoleyo vito ra Peniyeli, hikuva a ku: Ndzi vonile Xikwembu xikandza ni xikandza, kutani moya wa mina wu ponisiwile.' },
    { n: 31, text: 'Dyambu ri n\u2019wi tsuvukela loko a hundza hi le Peniyeli, a karhi a khwita hi nenge wa yena.' },
    { n: 32, text: 'Hikwalaho ka swona vana va Israyele a va dyi ntsambu wa khonon\u2019wi lowu nga ehenhla ka khonon\u2019wi ra nenge ku fikela namuntlha, hikuva a khumbile khonon\u2019wi ra nenge wa Jakobe entsambyini wa khonon\u2019wi.' },
  ],
  33: [
    { n: 1, text: 'Jakobe a tlakusa mahlo, a languta, a vona Esawu a karhi a ta, a ri ni vavanuna va makume manharhu ni khume. Hiloko a hambanisela vana eka Leya, na Rahele, ni le ka malandza mambirhi ya vavasati.' },
    { n: 2, text: 'A veka malandza ya vavasati ni vana va vona mahlweni, Leya ni vana va yena endzhaku ka vona, kutani Rahele na Josefa va va endzhaku-ndzhaku.' },
    { n: 3, text: 'Yena hi xiviri a tsemakanya mahlweni ka vona, a khinsama hansi ka ntlhanu na kambirhi ku fikela loko a tshinela kusuhi ni makwerhu wa yena.' },
    { n: 4, text: 'Kambe Esawu a tsutsuma a ya n\u2019wi hlanganisa, a n\u2019wi tlimba, a n\u2019wi koxon\u2019wini, a n\u2019wi ntsgontsga; hiloko va rila.' },
    { n: 5, text: 'Esawu a tlakusa mahlo, a vona vavasati ni vana, a ku: I vamaniki lava u nga na vona lava ke? Jakobe a ku: I vana lava Xikwembu xi nga nyika nandza wa wena hi tintswalo.' },
    { n: 6, text: 'Hiloko malandza ya vavasati ma tshinela, vona ni vana va vona, va khinsama.' },
    { n: 7, text: 'Leya na yena a tshinela ni vana va yena, va khinsama; endzhaku Josefa na Rahele va tshinela, va khinsama.' },
    { n: 8, text: 'Esawu a ku: Xana u lava ku endla yini hi ntlhambi lowu hinkwaswo lowu ndzi nga hlangana na wona ke? Jakobe a ku: I ku kuma tintswalo mahlweni ka hosi ya mina.' },
    { n: 9, text: 'Kambe Esawu a ku: Ndzi ni swo tala, makwerhu; leswi u nga na swona a swi ve swa wena.' },
    { n: 10, text: 'Jakobe a ku: E-e, ndzi kombela wena, loko ndzi kumile tintswalo mahlweni ka wena, amukela nyiko ya mina emavokweni ya mina; hikuva ndzi vonile xikandza xa wena ku fana ni la vonaka xikandza xa Xikwembu, hikuva u ndzi amukerile hi ku tsaka.' },
    { n: 11, text: 'Ndzi kombela u amukela nyiko ya mina leyi tisiweke eka wena; hikuva Xikwembu xi ndzi kombisile tintswalo, kutani ndzi ni swilo hinkwaswo. A n\u2019wi sindgisa, hiloko a yi amukela.' },
    { n: 12, text: 'Esawu a ku: A hi suke hi famba, ndzi ta famba mahlweni ka wena.' },
    { n: 13, text: 'Kambe Jakobe a ku eka yena: Hosi ya mina ya swi tiva leswaku vana va ha ri vatsongo, ni leswaku ndzi ni tiyimpfu ni tihomu leti amusaka; loko va swi sindgisa ku famba siku na rin\u2019we, ntlhambi hinkwawo wu ta fa.' },
    { n: 14, text: 'Hosi ya mina a yi hundze mahlweni ka nandza wa yena; mina ndzi ta famba katsongo-katsongo, hi ku landza ku famba ka swifuwo leswi nga mahlweni ka mina ni ku famba ka vana, ku fikela loko ndzi fika eka hosi ya mina le Seyire.' },
    { n: 15, text: 'Esawu a ku: Ndzi kombela ku ku siyela vanhu van\u2019wana lava ndzi nga na vona. Kambe Jakobe a ku: Swi pfuna yini ke? Ndzi kombela ntsena ku kuma tintswalo mahlweni ka hosi ya mina.' },
    { n: 16, text: 'Hi siku rero Esawu a vuyela endleleni ya yena eSeyire.' },
    { n: 17, text: 'Kambe Jakobe a famba a ya eSukoti, a tiakela yindlu, a endlela swifuwo swa yena matshalo; hikwalaho ndhawu yoleyo yi thyiyiweke vito ra Sukoti.' },
    { n: 18, text: 'Jakobe a fika a hlayisekile emutini wa Sikeme, lowu nga etikweni ra Kanana, loko a huma ePadani-Aramu; a dzima tende ra yena mahlweni ka muti.' },
    { n: 19, text: 'A xava xiphemu xa nsinu lomu a nga dzima tende ra yena emavokweni ya vana va Hamore, tata wa Sikeme, hi madgana ya timali ta silivhere.' },
    { n: 20, text: 'A aka alitari kwalaho, a yi thya vito ra El-Elohe-Israyele.' },
  ],
  34: [
    { n: 1, text: 'Dina, n\u2019wana wa xisati wa Leya, loyi a a n\u2019wi tswalele Jakobe, a huma ku ya vona vanhwanyana va tiko rero.' },
    { n: 2, text: 'Loko Sikeme, n\u2019wana wa Hamore wa Muhivi, loyi a a ri hosi ya tiko rero, a n\u2019wi vona, a n\u2019wi teka, a etlela na yena hi matimba, a n\u2019wi mbyonisa mbilu.' },
    { n: 3, text: 'Moya wa yena wu namarhela eka Dina n\u2019wana wa Jakobe, a rhandza nhwanyana loyi, a vulavula ni nhwanyana hi rirhandzu.' },
    { n: 4, text: 'Sikeme a vulavula ni Hamore tata wa yena, a ku: Ndzi kumele nhwanyana loyi ku va nsati wa mina.' },
    { n: 5, text: 'Jakobe a twa leswaku Sikeme u nyemisile Dina n\u2019wana wa yena wa xisati; kambe vana va yena va xinuna a va ri ni swifuwo swa yena ensinwini; hiloko Jakobe a miyela ku fikela loko va vuya.' },
    { n: 6, text: 'Hamore tata wa Sikeme a huma ku ya vulavula na Jakobe.' },
    { n: 7, text: 'Vana va Jakobe va vuye hi le nsinwini loko va twa mhaka leyi; vavanuna va vaviseka swinene va hlundguka, hikuva u endle mhaka yo biha swinene eIsrayele hi ku etlela ni n\u2019wana wa Jakobe wa xisati; mhaka leyi a yi nga fanelanga ku endliwa.' },
    { n: 8, text: 'Hamore a vulavula na vona, a ku: Moya wa n\u2019wana wa mina Sikeme wu namarhele eka n\u2019wana wa n\u2019wina wa xisati; ndzi kombela mi n\u2019wi nyika yena ku va nsati wa yena.' },
    { n: 9, text: 'Andgisani vukati na hina; hi nyikeni vana va n\u2019wina va vanhwanyana, kutani na n\u2019wina mi teka vana va hina va vanhwanyana.' },
    { n: 10, text: 'Mi ta tshama na hina, kutani tiko ri ta va mahlweni ka n\u2019wina; tshamani, mi xava ni ku xavisa kwala, mi tithyela ntsengo kwala.' },
    { n: 11, text: 'Sikeme a ku eka tata wa yena ni le ka vamakwenu va nhwanyana: Ndzi kombela ku kuma tintswalo mahlweni ka n\u2019wina, kutani lesvi mi nga ta ndzi byela swona ndzi ta swi nyika.' },
    { n: 12, text: 'Ngetelani ntsengo wa ndzovolo ni nyiko hi ku rhandza ka n\u2019wina, ndzi ta nyika lesvi mi nga ta ndzi byela swona; kambe ndzi nyikeni nhwanyana loyi ku va nsati wa mina.' },
    { n: 13, text: 'Vana va Jakobe va hlamula Sikeme na Hamore tata wa yena hi vukanganyisi, hikuva u nyemisile Dina makwerhu wa vona;' },
    { n: 14, text: 'va ku eka vona: Hi nga ka hi nga endli mhaka leyi, ku nyika makwerhu eka wanuna loyi a nga yimbisiwangiki; hikuva xolexo i xisandzu eka hina.' },
    { n: 15, text: 'Hi ta pfumela ntsena eka n\u2019wina hi mukhuva lowu: Loko mi fana na hina, vavanuna hinkwavo va n\u2019wina va yimbisiwa;' },
    { n: 16, text: 'hi kona hi nga ta mi nyika vana va hina va vanhwanyana, ni ku teka vana va n\u2019wina va vanhwanyana, hi tshama na n\u2019wina, hi va vanhu van\u2019we.' },
    { n: 17, text: 'Kambe loko mi nga hi yingiseli ku yimbisiwa, hi ta teka n\u2019wana wa hina, hi famba.' },
    { n: 18, text: 'Marito ya vona ya tsakisa Hamore na Sikeme n\u2019wana wa Hamore.' },
    { n: 19, text: 'Jaha leri a ri hlwelanga ku endla mhaka leyi, hikuva a ri rhandza n\u2019wana wa Jakobe; kutani yena a a ri loyi a xiximiwaka ku tlula hinkwavo endlwini ya tata wa yena.' },
    { n: 20, text: 'Hamore na Sikeme n\u2019wana wa yena va ya enonwini wa muti wa vona, va vulavula ni vavanuna va muti wa vona, va ku:' },
    { n: 21, text: 'Vavanuna lava va ni ku rhula na hina; hikwalaho a va tshame etikweni, va xava ni ku xavisa; hikuva tiko i rikulu swinene, ri nga va amukela; hi ta teka vana va vona va vanhwanyana va va vasati va hina, hi va nyika ni va hina va vanhwanyana.' },
    { n: 22, text: 'Kambe vavanuna lava va ta pfumela ku tshama na hina ku va vanhu van\u2019we hi mukhuva lowu ntsena: Loko vavanuna hinkwavo exikarhi ka hina va yimbisiwa, ku fana na vona loko va yimbisiwa.' },
    { n: 23, text: 'Xana swifuwo swa vona, ni swilo swa vona, ni swifuwo swa vona hinkwaswo swa tihomu a swi nga va swa hina ke? A hi pfumeleni ntsena eka vona, kutani va ta tshama na hina.' },
    { n: 24, text: 'Hinkwavo lava humaka enonwini wa muti va yingisela Hamore na Sikeme n\u2019wana wa yena; kutani vavanuna hinkwavo va yimbisiwa, hinkwavo lava humaka enonwini wa muti wa yena.' },
    { n: 25, text: 'Hi siku ra vunharhu, loko va ha vava swinene, vana vambirhi va Jakobe, Simiyoni na Levhi, vamakwenu va Dina, va teka banga ra vona, va nghena emutini lowu a wu tiyisele, va dlaya vavanuna hinkwavo.' },
    { n: 26, text: 'Va dlaya na Hamore na Sikeme n\u2019wana wa yena hi banga; va teka Dina endlwini ya Sikeme, va famba.' },
    { n: 27, text: 'Vana va Jakobe va tshinela eka lava dlayiweke, va phangha muti, hikuva va nyemisile makwerhu wa vona.' },
    { n: 28, text: 'Va teka swifuwo swa vona letitsongo, ni tihomu ta vona, ni timbhongolo ta vona, ni leswi nga emutini ni leswi nga ensinwini;' },
    { n: 29, text: 'va teka ni swilo swa vona hinkwaswo, ni vana va vona hinkwavo, ni vasati va vona va va mikhumbi, va phangha ni hinkwaswo leswi nga tindlwini.' },
    { n: 30, text: 'Jakobe a ku eka Simiyoni na Levhi: Mi ndzi vangele khombo rikulu hi ku ndzi endla la nyenyekaka exikarhi ka vaaki va tiko leri, exikarhi ka Vakanana ni Vaperizi; hikuva ndzi ni vanhu vatsongo ntsena; loko va hlengeletana ku lwa na mina, va ta ndzi dlaya, ndzi herisiwa, mina ni yindlu ya mina.' },
    { n: 31, text: 'Kambe va ku: Xana a a fanele ku endla makwerhu ku fana ni nghwavava ke?' },
  ],
  35: [
    { n: 1, text: 'Xikwembu xi ku eka Jakobe: Pfuka u ya eBetele, u ya tshama kona; u akela Xikwembu alitari kwalaho, xona lexi nga humelela eka wena loko u baleka Esawu makwerhu wa wena.' },
    { n: 2, text: 'Hiloko Jakobe a ku eka vandyangu va yena ni le ka hinkwavo lava a a ri na vona: Sukanisani swikwembu swa vahlapfa leswi nga exikarhi ka n\u2019wina, mi tibasisa, mi hundgula ni tinguvu ta n\u2019wina.' },
    { n: 3, text: 'A hi pfukeni hi ya eBetele; ndzi ta akela Xikwembu alitari kwalaho, xona lexi nga ndzi hlamula hi siku ra mahlomulo ya mina, xi va na mina endleleni leyi ndzi nga famba ha yona.' },
    { n: 4, text: 'Hiloko va nyika Jakobe swikwembu hinkwaswo swa vahlapfa leswi a va ri na vona emavokweni ya vona, ni swin\u2019wetsin\u2019wetsi leswi a swi ri etindleveni ta vona; kutani Jakobe a swi lahla ehansi ka ntsgandza wa oki lowu nga kusuhi na Sikeme.' },
    { n: 5, text: 'Va famba; kutani ku chava lokukulu loku humaka eka Xikwembu ku wela miti hinkwayo leyi va rhendzeleke, va nga landzi vana va Jakobe.' },
    { n: 6, text: 'Jakobe a fika eLuza (ndhawu leyi i Betele), etikweni ra Kanana, yena ni vanhu hinkwavo lava a a ri na vona.' },
    { n: 7, text: 'A aka alitari kwalaho, a thya ndhawu yoleyo vito ra El-Betele, hikuva hi kona lomu Xikwembu xi nga n\u2019wi humelela loko a baleka makwerhu wa yena.' },
    { n: 8, text: 'Debora, n\u2019wanyana la nga risa Rebeka, a fa, a lahliwa ehansi ka Betele, ehansi ka ntsgandza wa oki; hiloko wu thyiwa vito ra Aloni-Bakuti.' },
    { n: 9, text: 'Xikwembu xi tlhela xi humelela eka Jakobe loko a huma ePadani-Aramu, xi n\u2019wi katekisa.' },
    { n: 10, text: 'Xikwembu xi ku eka yena: Vito ra wena u Jakobe; vito ra wena a ri nga ha vuriwi Jakobe, kambe vito ra wena ri ta va Israyele. Hiloko xi n\u2019wi thya vito ra Israyele.' },
    { n: 11, text: 'Xikwembu xi ku eka yena: Hi mina Xikwembu xa Matimba hinkwawo; tswala u andza; tiko ni nhlengeletano ya matiko swi ta huma eka wena, ni tihosi ti ta huma esviongolweni swa wena;' },
    { n: 12, text: 'kutani tiko leri ndzi nga nyika Abrahama na Isaka ndzi ta ku nyika rona, ni kuxaka ka wena endzhaku ka wena ndzi ta ku nyika tiko leri.' },
    { n: 13, text: 'Xikwembu xi tlhandluka xi suka eka yena endhawini lomu xi nga vulavula na yena.' },
    { n: 14, text: 'Jakobe a yimisa phuphu ya ribye endhawini lomu xi nga vulavula na yena; a chela nyiko ya vhinyo ehenhla ka yona, a yi chela ni mafurha.' },
    { n: 15, text: 'Jakobe a thya ndhawu yoleyo lomu Xikwembu xi nga vulavula na yena vito ra Betele.' },
    { n: 16, text: 'Va suka eBetele; kutani loko ka ha ri ni mpfhuka lowutsongo ku fika eEfrata, Rahele a sungula ku ku lumva hi ku tswala, a tswala hi ku nonon\u2019hweriwa lokukulu.' },
    { n: 17, text: 'Loko a ha karhateka swinene hi ku tswala, mupsanyani a ku eka yena: Unga chavi, hikuva u ni n\u2019wana un\u2019wana wa xinuna.' },
    { n: 18, text: 'Loko moya wa yena wu suka (hikuva u file), a n\u2019wi thya vito ra Ben-Oni; kambe tata wa yena a n\u2019wi thya vito ra Benjamini.' },
    { n: 19, text: 'Rahele a fa, a lahliwa endleleni ya Efrata (leyi nga Betelehema).' },
    { n: 20, text: 'Jakobe a yimisa phuphu ehenhla ka sirha ra yena; yoleyo i phuphu ya sirha ra Rahele ku fikela namuntlha.' },
    { n: 21, text: 'Israyele a famba, a dzima tende ra yena endzhaku ka xihondzo xa Ederi.' },
    { n: 22, text: 'Loko Israyele a tshama etikweni rero, Rubeni a ya etlela ni Bila nsati wa khale wa tata wa yena; kutani Israyele a swi twa. Vana va xinuna va Jakobe a va ri khume na vambirhi.' },
    { n: 23, text: 'Vana va Leya: Rubeni, mativula ya Jakobe, ni Simiyoni, ni Levhi, ni Yuda, ni Isakara, ni Zebuloni.' },
    { n: 24, text: 'Vana va Rahele: Josefa na Benjamini.' },
    { n: 25, text: 'Vana va Bila, nandza wa Rahele: Dani na Neftali.' },
    { n: 26, text: 'Vana va Silipa, nandza wa Leya: Gadi na Axere. Lava i vana va Jakobe lava va nga tswariwa ePadani-Aramu.' },
    { n: 27, text: 'Jakobe a fika eka Isaka tata wa yena eMamre, emutini wa Kiriyata-Arba (lowu nga Hebroni), lomu Abrahama na Isaka va nga tshama kona va ri vahlapfa.' },
    { n: 28, text: 'Masiku ya Isaka a ku ri dzana ni makume ya nhungu ya malembe.' },
    { n: 29, text: 'Isaka a huma moya, a fa, a hlengeletana ni vaka vona, a dyuharile a tshembekile hi masiku; hiloko Esawu na Jakobe vana va yena va n\u2019wi lahla.' },
  ],
  36: [
    { n: 1, text: 'Leyi i ndzhaka ya Esawu (lowu nga Edomu).' },
    { n: 2, text: 'Esawu a teka vasati va yena exikarhi ka vanhwanyana va Kanana: Ada n\u2019wana wa Eloni wa Muhiti, na Oholibama n\u2019wana wa Ana, n\u2019wana wa Sibeoni wa Muhivi,' },
    { n: 3, text: 'ni Basemati n\u2019wana wa Iximaele, makwerhu wa Nebayoti.' },
    { n: 4, text: 'Ada a tswalela Esawu Elifazi; kutani Basemati a tswala Reuwela;' },
    { n: 5, text: 'Oholibama a tswala Yeyuxi, na Yalame, na Kora. Lava i vana va Esawu lava va nga tswariwa etikweni ra Kanana.' },
    { n: 6, text: 'Esawu a teka vasati va yena, ni vana va yena va xinuna, ni vana va yena va vanhwanyana, ni vanhu hinkwavo va yindlu ya yena, ni swifuwo swa yena, ni swilo swa yena hinkwaswo leswi a nga swi kuma etikweni ra Kanana, a famba etikweni rin\u2019wana kule ni Jakobe makwerhu wa yena.' },
    { n: 7, text: 'Hikuva swilo swa vona a swi ri switsongo leswaku va tshama swin\u2019we, kutani tiko lomu a va ri vahlapfa a ri nga va ringani hikwalaho ka swifuwo swa vona.' },
    { n: 8, text: 'Hiloko Esawu a tshama entshaveni ya Seyire (Esawu i Edomu).' },
    { n: 9, text: 'Leyi i ndzhaka ya Esawu, tata wa Vaedoma, entshaveni ya Seyire.' },
    { n: 10, text: 'Mavito ya vana va Esawu hi lawa: Elifazi n\u2019wana wa Ada nsati wa Esawu, na Reuwela n\u2019wana wa Basemati nsati wa Esawu.' },
    { n: 11, text: 'Vana va Elifazi a ku ri Temane, na Omari, na Sefo, na Gatame, ni Kenazi.' },
    { n: 12, text: 'Timna a a ri nsati wa khale wa Elifazi n\u2019wana wa Esawu, kutani a tswalela Elifazi Amaleke. Lava i vana va Ada nsati wa Esawu.' },
    { n: 13, text: 'Vana va Reuwela hi lawa: Nahate, na Zera, na Xama, ni Miza. Lava i vana va Basemati nsati wa Esawu.' },
    { n: 14, text: 'Vana va Oholibama nsati wa Esawu, n\u2019wana wa Ana n\u2019wana wa Sibeoni, hi lava a nga va tswalela Esawu: Yeyuxi, na Yalame, ni Kora.' },
    { n: 15, text: 'Tihosi ta vana va Esawu hi leti: vana va Elifazi mativula ya Esawu: hosi Temane, hosi Omari, hosi Sefo, hosi Kenazi,' },
    { n: 16, text: 'hosi Kora, hosi Gatame, hosi Amaleke. Tihosi leti ti huma eka Elifazi etikweni ra Edomu; lava i vana va Ada.' },
    { n: 17, text: 'Vana va Reuwela n\u2019wana wa Esawu hi lava: hosi Nahate, hosi Zera, hosi Xama, hosi Miza. Tihosi leti ti huma eka Reuwela etikweni ra Edomu; lava i vana va Basemati.' },
    { n: 18, text: 'Vana va Oholibama nsati wa Esawu hi lava: hosi Yeyuxi, hosi Yalame, hosi Kora. Tihosi leti ti huma eka Oholibama n\u2019wana wa Ana nsati wa Esawu.' },
    { n: 19, text: 'Lava i vana va Esawu (lowu nga Edomu), kutani leti i tihosi ta vona.' },
    { n: 20, text: 'Vana va Seyire wa Muhori, vaaki va tiko, hi lava: Lotane, na Xobale, na Sibeoni, na Ana,' },
    { n: 21, text: 'na Dixone, na Ezere, ni Dixane. Leti i tihosi ta Vahori, vana va Seyire, etikweni ra Edomu.' },
    { n: 22, text: 'Vana va Lotane a ku ri Hori ni Hemami; kutani makwerhu wa Lotane a ku ri Timna.' },
    { n: 23, text: 'Vana va Xobale hi lava: Alvhane, na Manahate, na Ebale, na Xefo, na Oname.' },
    { n: 24, text: 'Vana va Sibeoni hi lava: Aya na Ana. Hi yena Ana loyi a nga kuma mati yo hisa emananga loko a karhi a risa timbhongolo ta Sibeoni tata wa yena.' },
    { n: 25, text: 'Vana va Ana hi lava: Dixone ni Oholibama n\u2019wana wa xisati wa Ana.' },
    { n: 26, text: 'Vana va Dixone hi lava: Hemdane, na Exbane, na Itrane, ni Kerane.' },
    { n: 27, text: 'Vana va Ezere hi lava: Bilhane, na Zaavane, ni Akane.' },
    { n: 28, text: 'Vana va Dixane hi lava: Uzi na Arane.' },
    { n: 29, text: 'Tihosi ta Vahori hi leti: hosi Lotane, hosi Xobale, hosi Sibeoni, hosi Ana,' },
    { n: 30, text: 'hosi Dixone, hosi Ezere, hosi Dixane. Leti i tihosi ta Vahori, hi ku landza vuhosi bya tona etikweni ra Seyire.' },
    { n: 31, text: 'Tihosi leti nga fuma etikweni ra Edomu loko ku nga si fuma hosi ni yin\u2019we eka vana va Israyele hi leti:' },
    { n: 32, text: 'Bela n\u2019wana wa Beore a fuma eEdomu; kutani vito ra muti wa yena a ku ri Dinhaba.' },
    { n: 33, text: 'Bela a fa, kutani Yobabe n\u2019wana wa Zera wa le Bozra a fuma ematshan\u2019wini ya yena.' },
    { n: 34, text: 'Yobabe a fa, kutani Huxame wa tiko ra Vatemane a fuma ematshan\u2019wini ya yena.' },
    { n: 35, text: 'Huxame a fa, kutani Hadade n\u2019wana wa Bedade, loyi a nga dlaya Vamidiyana emasinwini ya Mowabu, a fuma ematshan\u2019wini ya yena; vito ra muti wa yena a ku ri Aviti.' },
    { n: 36, text: 'Hadade a fa, kutani Samla wa le Masreka a fuma ematshan\u2019wini ya yena.' },
    { n: 37, text: 'Samla a fa, kutani Xawulo wa le Rehobote kusuhi ni Nambu a fuma ematshan\u2019wini ya yena.' },
    { n: 38, text: 'Xawulo a fa, kutani Baale-Hanane n\u2019wana wa Akbore a fuma ematshan\u2019wini ya yena.' },
    { n: 39, text: 'Baale-Hanane n\u2019wana wa Akbore a fa, kutani Hadara a fuma ematshan\u2019wini ya yena; vito ra muti wa yena a ku ri Pau, kutani vito ra nsati wa yena a ku ri Mehetabele, n\u2019wana wa Matrede n\u2019wana wa Mezahabe.' },
    { n: 40, text: 'Mavito ya tihosi leti humaka eka Esawu, hi ku landza mindyangu ya tona, ni tindhawu ta tona, hi mavito ya tona, hi lawa: hosi Timna, hosi Alvha, hosi Yete,' },
    { n: 41, text: 'hosi Oholibama, hosi Ela, hosi Pinone,' },
    { n: 42, text: 'hosi Kenazi, hosi Temane, hosi Mibzari,' },
    { n: 43, text: 'hosi Magadiyeli, hosi Iramu. Leti i tihosi ta Edomu, hi ku landza maako ya tona etikweni ra ndzhaka ya tona. Esawu i tata wa Vaedoma.' },
  ],
  37: [
    { n: 1, text: 'Jakobe a tshama etikweni lomu tata wa yena a a ri muhlapfa kona, etikweni ra Kanana.' },
    { n: 2, text: 'Leyi i timhaka ta kuxaka ka Jakobe: Josefa, loko a ri ni malembe ya khume ni ntlhanu na mambirhi, a a risa swifuwo ni vamakwerhu wa yena; jaha leri a ri ri ni vana va Bila ni vana va Silipa, vasati va tata wa yena; kutani Josefa a tisa swiviko swo biha hi vona eka tata wa vona.' },
    { n: 3, text: 'Israyele a a rhandza Josefa ku tlula vana va yena hinkwavo, hikuva a a ri n\u2019wana wa vudyuhari bya yena; a n\u2019wi endlela jasi ro saseka ra mihlovo-hlovo.' },
    { n: 4, text: 'Loko vamakwerhu wa yena va vona leswaku tata wa vona u n\u2019wi rhandza ku tlula vamakwerhu hinkwavo, va n\u2019wi venga, va nga koti ku vulavula na yena hi ku rhula.' },
    { n: 5, text: 'Josefa a lora miloro, a yi hlamusela vamakwerhu wa yena; hiloko va n\u2019wi venga swinene ku tlula mahlweni.' },
    { n: 6, text: 'A ku eka vona: Yingisani, ndzi kombela n\u2019wina, miloro leyi ndzi nga yi lora:' },
    { n: 7, text: 'Vona, a hi boha mavele ensinwini, kutani qulu ra mina ri pfuka, ri yima; kutani maqulu ya n\u2019wina ma rhendzela, ma khinsamela qulu ra mina.' },
    { n: 8, text: 'Vamakwerhu va ku eka yena: Xana u ta fuma ehenhla ka hina hakunene ke? Kumbe u ta hi fuma hakunene ke? Hiloko va n\u2019wi venga swinene hikwalaho ka miloro ya yena ni hikwalaho ka marito ya yena.' },
    { n: 9, text: 'A tlhela a lora un\u2019wana miloro, a wu hlamusela vamakwerhu, a ku: Vona, ndzi lorile miloro un\u2019wana; dyambu, ni n\u2019weti, ni tinyeleti ta khume na yin\u2019we a swi ndzi khinsamela.' },
    { n: 10, text: 'A wu hlamusela tata wa yena ni vamakwerhu; kutani tata wa yena a n\u2019wi tshinya, a ku eka yena: I miloro muni lowu u nga wu lora ke? Xana mina, ni mana wa wena, ni vamakwerhu hi ta fika hakunene hi ku khinsamela hansi ke?' },
    { n: 11, text: 'Vamakwerhu wa yena va n\u2019wi rhandzela, kambe tata wa yena a hlayisa mhaka leyi embilwini ya yena.' },
    { n: 12, text: 'Vamakwerhu wa yena va ya ku riseni ka swifuwo swa tata wa vona eSikeme.' },
    { n: 13, text: 'Israyele a ku eka Josefa: Xana vamakwerhu a va risi swifuwo eSikeme ke? Tana, ndzi ku rhuma eka vona. Josefa a ku: Ndzi kombela wena.' },
    { n: 14, text: 'A ku eka yena: Famba sweswi, u ya vona loko vamakwerhu va hlayisekile, ni loko swifuwo swi hlayisekile, u ndzi tisa xiviko. Hiloko a n\u2019wi rhuma eku rhandzeni ka Hebroni, a fika eSikeme.' },
    { n: 15, text: 'Wanuna un\u2019wana a n\u2019wi kuma a karhi a lahleka ensinwini; kutani wanuna a n\u2019wi vutisa, a ku: U lava yini ke?' },
    { n: 16, text: 'A ku: Ndzi lava vamakwerhu; ndzi kombela u ndzi byela lomu va risaka kona ke?' },
    { n: 17, text: 'Wanuna a ku: Va sukile kwala; hikuva ndzi va twile va ku: \u2018A hi fambeni eDotani.\u2019 Hiloko Josefa a landzelerisisa vamakwerhu, a va kuma eDotani.' },
    { n: 18, text: 'Loko va n\u2019wi vona a ha ri kule, loko a nga si tshinela kusuhi na vona, va lulamisela ku n\u2019wi dlaya.' },
    { n: 19, text: 'Va vulavurisana va ku: Vona, mulori loyi u karhi u ta!' },
    { n: 20, text: 'Sweswi, tana, hi n\u2019wi dlaya, hi n\u2019wi lahlela exihlobyeni xin\u2019wana lexi nga riki na mati, hi ta ku: \u2018Xihari xo biha xi n\u2019wi dlayile\u2019; hi ta vona leswaku miloro ya yena yi ta va yini.' },
    { n: 21, text: 'Kambe Rubeni a swi twa, a n\u2019wi ponisa emavokweni ya vona, a ku: Ndzi kombela hi nga dlayi moya wa yena.' },
    { n: 22, text: 'Rubeni a ku eka vona: Swi nga halati ngati; n\u2019wi lahleleni exihlobyeni lexi nga emananga, kambe mi nga veki voko eka yena. A a vula sweswo leswaku a n\u2019wi ponisa emavokweni ya vona, a n\u2019wi vuyisela eka tata wa yena.' },
    { n: 23, text: 'Loko Josefa a fika eka vamakwerhu wa yena, va n\u2019wi hluvula jasi ra yena, jasi ro saseka ra mihlovo-hlovo leri a a ri na rona;' },
    { n: 24, text: 'va n\u2019wi teka, va n\u2019wi lahlela exihlobyeni. Xihlovo a xi nga ri na nchumu, a ku nga ri na mati endzeni ka xona.' },
    { n: 25, text: 'Va tshama hansi ku dya xinkwa; va tlakusa mahlo, va languta, va vona ntlhambi wa Vaiximaele va huma eGiliyadi, tikamela ta vona ti rhwarile mafurha ya risuna, ni balm, ni myrrh, va kongoma ku ya rhelela eEgipta.' },
    { n: 26, text: 'Yuda a ku eka vamakwerhu wa yena: Ku pfuna yini ku dlaya makwerhu hi fihla ngati ya yena ke?' },
    { n: 27, text: 'Tana, a hi n\u2019wi xaviseni eka Vaiximaele, kutani voko ra hina ri nga vi eka yena; hikuva i makwerhu ni nyama ya hina. Vamakwerhu va pfumela.' },
    { n: 28, text: 'Kutani ku hundza vaxavi va Vamidiyana; va kokela Josefa ehandle exihlobyeni, va n\u2019wi xavisa eka Vaiximaele hi makume mambirhi ya timali ta silivhere; kutani va nghenisa Josefa eEgipta.' },
    { n: 29, text: 'Rubeni a vuyela exihlobyeni, kutani, vonani, Josefa a a nga ha ri exihlobyeni; hiloko a handgula tinguvu ta yena.' },
    { n: 30, text: 'A vuyela eka vamakwerhu wa yena, a ku: Jaha leri a ri kona! Kutani mina, ndzi ta ya kwihi ke?' },
    { n: 31, text: 'Va teka jasi ra Josefa, va dlaya mbuti ya xinuna, va thapisa jasi emgatingi;' },
    { n: 32, text: 'va rhumela jasi ro saseka ra mihlovo-hlovo eka tata wa vona, va ku: Hi kume leri; kambela loko ku ri jasi ra n\u2019wana wa wena kumbe e-e.' },
    { n: 33, text: 'A ri tiva, a ku: I jasi ra n\u2019wana wa mina! Xihari xo biha xi n\u2019wi dlayile; inene Josefa u handguriwe hi ku helela!' },
    { n: 34, text: 'Jakobe a handgula tinguvu ta yena, a veka nguvu yo rila esviongolweni swa yena, a rila n\u2019wana wa yena masiku yo tala.' },
    { n: 35, text: 'Vana va yena hinkwavo va xinuna ni va vanhwanyana va pfuka ku ta n\u2019wi chavela; kambe a ala ku chavelwa, a ku: Ndzi ta rhelela exitsgongolweni ndzi karhi ndzi rila n\u2019wana wa mina. Hiloko tata wa yena a n\u2019wi rila.' },
    { n: 36, text: 'Kutani Vamidiyana va n\u2019wi xavisa eEgipta eka Potifaro, nandza wa Faro, mulanguteri wa masocha.' },
  ],
  38: [
    { n: 1, text: 'Hi nkarhi woloyo Yuda a rhelela, a suka eka vamakwerhu wa yena, a ya lahla tende kusuhi ni wanuna wa Muadulami, loyi vito ra yena a ku ri Hira.' },
    { n: 2, text: 'Yuda a vona kwalaho n\u2019wana wa xisati wa wanuna wa Mukanana, loyi vito ra yena a ku ri Xuwa; a n\u2019wi teka, a nghena eka yena.' },
    { n: 3, text: 'A tika, a tswala n\u2019wana wa xinuna; a n\u2019wi thya vito ra Eri.' },
    { n: 4, text: 'A tlhela a tika, a tswala n\u2019wana wa xinuna; a n\u2019wi thya vito ra Onani.' },
    { n: 5, text: 'A tlhela a tswala un\u2019wana n\u2019wana wa xinuna, a n\u2019wi thya vito ra Xela. Yuda a a ri eKezibi loko a n\u2019wi tswala.' },
    { n: 6, text: 'Yuda a kumele Eri mativula ya yena nsati, vito ra yena a ku ri Tamari.' },
    { n: 7, text: 'Kambe Eri, mativula ya Yuda, a a ri lowo biha mahlweni ka Hosi; hiloko Hosi yi n\u2019wi dlaya.' },
    { n: 8, text: 'Yuda a ku eka Onani: Nghena eka nsati wa makwerhu, u endla ntirho wa n\u2019wingi, u tswalela makwerhu kuxaka.' },
    { n: 9, text: 'Kambe Onani a a tiva leswaku kuxaka a ku nga ta va ka yena; hikwalaho, loko a nghena eka nsati wa makwerhu, a halatela mbewu hansi, leswaku a nga nyiki makwerhu kuxaka.' },
    { n: 10, text: 'Mhaka leyi a nga yi endla yi ve yo biha mahlweni ka Hosi; hiloko yi n\u2019wi dlaya na yena.' },
    { n: 11, text: 'Yuda a ku eka Tamari n\u2019wingi wa yena: Tshama u ri mfelwa endlwini ya tata wa wena ku fikela loko Xela n\u2019wana wa mina a kula; hikuva a a ku: \u2018Kumbexana na yena u ta fa ku fana ni vamakwerhu wa yena.\u2019 Hiloko Tamari a ya tshama endlwini ya tata wa yena.' },
    { n: 12, text: 'Ku hundza masiku yo tala, n\u2019wana wa Xuwa nsati wa Yuda a fa. Loko Yuda a miyerile, a ya eTimna eka vatsemati va voya bya tiyimpfu ta yena, yena ni munghana wa yena Hira wa Muadulami.' },
    { n: 13, text: 'Va hlamusela Tamari, va ku: Vona, tatana wa nuna wa wena u karhi u ya eTimna ku ya tsemeta voya bya tiyimpfu ta yena.' },
    { n: 14, text: 'Hiloko a hluvula tinguvu ta vufelwa bya yena, a tifunengetela hi nguvu yo khubumeta, a tipfala xikandza, a tshama enonwini wa Enaimi, leyi nga endleleni ya Timna; hikuva a a vona leswaku Xela u kurile, kambe yena a nga nyikiwanga eka yena ku va nsati.' },
    { n: 15, text: 'Loko Yuda a n\u2019wi vona, a ku i nghwavava, hikuva a a tifunengeterile xikandza.' },
    { n: 16, text: 'A hambukela eka yena endleleni, a ku: Ndzi kombela u ndzi pfumelela ndzi nghena eka wena; hikuva a a nga tivi leswaku i n\u2019wingi wa yena. Tamari a ku: U ta ndzi nyika yini leswaku u nghena eka mina ke?' },
    { n: 17, text: 'A ku: Ndzi ta ku rhumela ximbutana xa xinuna xi huma exifuwenini. Tamari a ku: Xana u ta ndzi nyika xitshembiso ku fikela loko u xi rhumela ke?' },
    { n: 18, text: 'A ku: Ndzi ta ku nyika xitshembiso muni ke? A ku: Mfungho wa wena, ni ntsambu wa wena, ni nhonga leyi nga evokweni ra wena. Hiloko a n\u2019wi nyika swona, a nghena eka yena; kutani a tika hi yena.' },
    { n: 19, text: 'Tamari a pfuka, a famba, a humesa nguvu yo khubumeta, a ambala tinguvu ta vufelwa bya yena.' },
    { n: 20, text: 'Yuda a rhumela ximbutana hi voko ra munghana wa yena wa Muadulami ku ya teka xitshembiso emavokweni ya mhani loyi, kambe a nga n\u2019wi kumanga.' },
    { n: 21, text: 'A vutisa vavanuna va ndhawu yoleyo, a ku: I kwihi nghwavava ya le tempeleni leyi a yi ri enonwini wa Enaimi endleleni ke? Va ku: A ku nga ri na nghwavava kwala.' },
    { n: 22, text: 'A vuyela eka Yuda, a ku: A ndzi n\u2019wi kumanga; kutani na vona vavanuna va ndhawu yoleyo va vurile va ku: \u2018A ku nga ri na nghwavava kwala.\u2019' },
    { n: 23, text: 'Yuda a ku: A a ti tikele swilo swoleswo, leswaku hi nga va xihlekiso; vona, ndzi rhumile ximbutana lexi, kambe wena a wu n\u2019wi kumanga.' },
    { n: 24, text: 'Endzhaku ka tin\u2019weti tinharhu va hlamusela Yuda, va ku: Tamari n\u2019wingi wa wena u endlile vugangari; kutani vona, u ni khwiri ra vugangari. Yuda a ku: N\u2019wi humeseni, a tisiwa ku ta tshikiwa hi ndzilo!' },
    { n: 25, text: 'Loko a tisiwa, a rhumela eka tatana wa nuna wa yena, a ku: Ndzi ni khwiri ra wanuna loyi swilo leswi swi nga swa yena; languta sweswi, mfungho lowu, ni ntsambu lowu, ni nhonga leyi, i swa mani ke?' },
    { n: 26, text: 'Yuda a swi tiva, a ku: U lulamile ku tlula mina, hikuva a ndzi n\u2019wi nyikanga Xela n\u2019wana wa mina. Kutani a nga ha n\u2019wi tivanga mahlweni.' },
    { n: 27, text: 'Nkarhi wa ku tswala wa yena wu fika, kutani vonani, a ku ri ni mahahla ekhwirini ra yena.' },
    { n: 28, text: 'Loko a ha tswala, un\u2019wana a humesa voko; mupsanyani a n\u2019wi khoma voko, a n\u2019wi boha ntsambu wo tshwuka, a ku: Loyi u humile mahlweni.' },
    { n: 29, text: 'Kambe loko a tlherisile voko, makwerhu wa yena a huma; hiloko mupsanyani a ku: Ha yini u tsemakanyile hi matimba ke? Hikwalaho vito ra yena ri thiyiweke Peresi.' },
    { n: 30, text: 'Endzhaku makwerhu wa yena loyi a a bohiwe ntsambu wo tshwuka evokweni a huma, hiloko a thyiwa vito ra Zera.' },
  ],
  39: [
    { n: 1, text: 'Josefa a nghenisiwa eEgipta; kutani Potifaro, nandza wa Faro, mulanguteri wa masocha, wanuna wa Muegipta, a n\u2019wi xava emavokweni ya Vaiximaele lava va nga n\u2019wi rhelerisa kwalaho.' },
    { n: 2, text: 'Hosi a yi ri na Josefa, a fuma swinene; a a tshama endlwini ya n\u2019wini wa yena wa Muegipta.' },
    { n: 3, text: 'N\u2019wini wa yena a vona leswaku Hosi yi na yena, ni leswaku Hosi yi katekisa hinkwaswo leswi a nga swi endla evokweni ra yena.' },
    { n: 4, text: 'Josefa a kuma tintswalo mahlweni ka yena, a n\u2019wi tirhela; hiloko a n\u2019wi veka mulanguteri wa yindlu ya yena, a veka hinkwaswo leswi a a ri na swona emavokweni ya Josefa.' },
    { n: 5, text: 'Ku sukela nkarhi lowu a nga n\u2019wi veka mulanguteri wa yindlu ya yena ni hinkwaswo leswi a a ri na swona, Hosi yi katekisa yindlu ya Muegipta hikwalaho ka Josefa; kutani nkateko wa Hosi wu va ehenhla ka hinkwaswo leswi a a ri na swona endlwini ni le nsinwini.' },
    { n: 6, text: 'A siya hinkwaswo leswi a a ri na swona emavokweni ya Josefa; a nga ha tivi nchumu handle ka xinkwa lexi a a xi dya. Josefa a a sasekile swinene hi xivumbeko ni ku languteka.' },
    { n: 7, text: 'Endzhaku ka swilo leswi, nsati wa n\u2019wini wa yena a veka mahlo ya yena eka Josefa, a ku: Etlela na mina!' },
    { n: 8, text: 'Kambe a ala, a ku eka nsati wa n\u2019wini wa yena: Vona, n\u2019wini wa mina a nga tivi nchumu endlwini loko ndzi ri kona, kutani u vekile hinkwaswo leswi a a ri na swona emavokweni ya mina.' },
    { n: 9, text: 'A ku na munhu loyi a nga n\u2019wi tlula hi matimba endlwini leyi; a nga ndzi tsonanga nchumu handle ka wena ntsena, hikuva u nsati wa yena; xana ndzi nga endlisa ku yini vuhunguki lebyi byikulu, ndzi dyohela Xikwembu ke?' },
    { n: 10, text: 'Hambileswi a a vulavula na Josefa siku na siku, a nga n\u2019wi yingiselanga ku etlela na yena kumbe ku va na yena.' },
    { n: 11, text: 'Hi siku rin\u2019wana a nghena endlwini ku ya endla ntirho wa yena, kutani a ku nga ri na munhu na un\u2019we wa vanhu va yindlu endzeni.' },
    { n: 12, text: 'Hiloko nsati a n\u2019wi khoma hi nguvu ya yena, a ku: Etlela na mina! Kambe Josefa a siya nguvu ya yena evokweni ra yena, a tsutsuma, a humela ehandle.' },
    { n: 13, text: 'Loko nsati a vona leswaku u siye nguvu ya yena evokweni ra yena, a tsutsuma a ya ehandle,' },
    { n: 14, text: 'a vitana vavanuna va yindlu ya yena, a ku eka vona: Vonani, u hi tisele wanuna wa Muheveru ku ta hi tlhantla; u nghenile eka mina ku ta etlela na mina, kambe ndzi tlimbe rito ndzi rila;' },
    { n: 15, text: 'kutani loko a twile leswaku ndzi tlakusile rito ra mina ndzi rila, u siye nguvu ya yena kusuhi na mina, a tsutsuma, a humela ehandle.' },
    { n: 16, text: 'Nsati a veka nguvu ya Josefa kusuhi na yena ku fikela loko n\u2019wini wa yena a vuye endlwini.' },
    { n: 17, text: 'Hiloko a n\u2019wi hlamusela hi marito wolawo, a ku: Nandza wa Muheveru loyi u nga hi tisa yena u nghenile eka mina ku ta ndzi tlhantla;' },
    { n: 18, text: 'kambe loko ndzi tlakusile rito ra mina ndzi rila, u siye nguvu ya yena kusuhi na mina, a tsutsumela ehandle.' },
    { n: 19, text: 'Loko n\u2019wini wa yena a twile marito ya nsati wa yena, lawa a nga vulavula na yena, a ku: \u2018Nandza wa wena u ndzi endlerile sweswo,\u2019 ku hlundguka ka yena ku pfuka swinene.' },
    { n: 20, text: 'N\u2019wini wa Josefa a n\u2019wi teka, a n\u2019wi nghenisa khotsweni, ndhawu lomu vakhotsi va hosi va nga bohiwa kona; kutani a tshama kwalaho khotsweni.' },
    { n: 21, text: 'Kambe Hosi a yi ri na Josefa, yi n\u2019wi kombisa tintswalo, yi n\u2019wi nyika ku rhandzeka mahlweni ka mulanguteri wa khotso.' },
    { n: 22, text: 'Mulanguteri wa khotso a veka emavokweni ya Josefa vakhotsi hinkwavo lava a va ri khotsweni; kutani hinkwaswo leswi a swi endliwa kwalaho, a ku ri yena la swi endlisaka.' },
    { n: 23, text: 'Mulanguteri wa khotso a a nga ha kambeli nchumu lowu a wu ri evokweni ra Josefa, hikuva Hosi a yi ri na yena; kutani lesvi a a swi endla, Hosi a yi swi katekisa.' },
  ],
  40: [
    { n: 1, text: 'Endzhaku ka swilo leswi, mulandza la phamelaka vhinyo wa hosi ya Egipta, ni mubaki va dyohela hosi ya vona, hosi ya Egipta.' },
    { n: 2, text: 'Faro a hlundgukela vaphamele va yena vambirhi lavakulu: mulanguteri wa vaphamele va vhinyo ni mulanguteri wa vabaki.' },
    { n: 3, text: 'A va nghenisa khotsweni endlwini ya mulanguteri wa masocha, endhawini lomu Josefa a a bohiwe kona.' },
    { n: 4, text: 'Mulanguteri wa masocha a veka Josefa ku va na vona, a va tirhela; va tshama khotsweni nkarhi wo leha.' },
    { n: 5, text: 'Vambirhi va vona va lora miloro hi vusiku na vusiku, un\u2019wana ni un\u2019wana miloro ya yena hi ku hlamusela ka yona: muphamele wa vhinyo ni mubaki va hosi ya Egipta, lava a va bohiwe khotsweni.' },
    { n: 6, text: 'Nimpundzu, Josefa a nghena eka vona, a va languta, a vona va karhateka swinene.' },
    { n: 7, text: 'A vutisa vaphamele va Faro lava a va ri na yena khotsweni endlwini ya n\u2019wini wa yena, a ku: Ha yini swikandza swa n\u2019wina swi tsunyile namuntlha ke?' },
    { n: 8, text: 'Va ku eka yena: Hi lorile miloro, kambe a ku na munhu la nga yi hlamuselaka. Josefa a ku eka vona: Xana ku hlamusela a hi ka Xikwembu ke? Ndzi kombela mi ndzi hlamusela yona.' },
    { n: 9, text: 'Mulanguteri wa vaphamele va vhinyo a hlamusela Josefa miloro ya yena, a ku: Emilorweni ya mina, vonani, a ku ri ni murhi wa vhinyo mahlweni ka mina;' },
    { n: 10, text: 'ehenhla ka murhi wa vhinyo a ku ri ni marhavi manharhu; kutani loko wu karhi wu pfula swiluva, swandza swa wena swi vupfa madgandza ya vhinyo;' },
    { n: 11, text: 'xin\u2019welo xa Faro a xi ri evokweni ra mina; ndzi teka madgandza ya vhinyo, ndzi ma kamela exin\u2019welweni xa Faro, ndzi nyika xin\u2019welo evokweni ra Faro.' },
    { n: 12, text: 'Josefa a ku eka yena: Ku hlamusela ka yona hi loku: Marhavi manharhu i masiku manharhu;' },
    { n: 13, text: 'emasinwini manharhu lama taka Faro u ta ku tlakusa nhloko, a ku vuyisela endhawini ya wena ya ntirho; u ta nyika xin\u2019welo xa Faro evokweni ra yena, hi ku landza mukhuva wa wena wa khale loko wa ha ri muphamele wa yena.' },
    { n: 14, text: 'Kambe u ndzi tsundguka loko u humile, u ndzi kombisa tintswalo, u vulavula hi mina eka Faro, leswaku u ndzi humesa endlwini leyi;' },
    { n: 15, text: 'hikuva inene, ndzi yiviwile etikweni ra Vaheveru; kutani na kwala a ndzi endlangi nchumu lowu fanelaka ku ndzi nghenisa khotsweni leli.' },
    { n: 16, text: 'Loko mulanguteri wa vabaki a vona leswaku ku hlamusela ku sasekile, a ku eka Josefa: Na mina emilorweni ya mina, vonani, a ku ri ni swirhundgu swanharhu swa swinkwa swo basa ehenhla ka nhloko ya mina;' },
    { n: 17, text: 'exirhundguni xa le henhla-henhla a ku ri ni mixaka-xaka ya swakudya swo bakiwa swa Faro; kambe tinyanyana a ti swi dya exirhundguni ehenhla ka nhloko ya mina.' },
    { n: 18, text: 'Josefa a hlamula, a ku: Ku hlamusela ka yona hi loku: Swirhundgu swanharhu i masiku manharhu;' },
    { n: 19, text: 'emasinwini manharhu lama taka Faro u ta ku tlakusela nhloko, a ku tsemeta yona, a ku hayeka entsgandzeni; kutani tinyanyana ti ta dya nyama ya wena ehenhla ka wena.' },
    { n: 20, text: 'Hi siku ra vunharhu, leri a ku ri siku ra ku tswariwa ka Faro, a endlela malandza ya yena hinkwaswo nkhuvo; a tlakusa nhloko ya mulanguteri wa vaphamele va vhinyo ni nhloko ya mulanguteri wa vabaki exikarhi ka malandza ya yena.' },
    { n: 21, text: 'A vuyisela mulanguteri wa vaphamele va vhinyo emutirhwini wa yena wa ku phamela vhinyo, a nyika xin\u2019welo evokweni ra Faro;' },
    { n: 22, text: 'kambe a hayeka mulanguteri wa vabaki entsgandzeni, hi ku landza ku hlamusela loku Josefa a nga va nyika kona.' },
    { n: 23, text: 'Kambe mulanguteri wa vaphamele va vhinyo a nga n\u2019wi tsundgukanga Josefa, a n\u2019wi rivala swoneri.' },
  ],
  41: [
    { n: 1, text: 'Endzhaku ka malembe mambirhi lamene, Faro a lora miloro: a a yimile kusuhi ni nambu wa Nile.' },
    { n: 2, text: 'Kutani ku huma enambyeni tihomu ta ntsandza-vahlayi ta nkombo leti sasekeke ni ku nona; ti dya byanyi ematleleni.' },
    { n: 3, text: 'Endzhaku ka tona, ku huma tin\u2019wana tihomu ta nkombo enambyeni, leti langutekaka hi ndlela yo biha ni ku lova; ti yima kusuhi ni tihomu leti noneke eribuweni ra nambu.' },
    { n: 4, text: 'Tihomu leti langutekaka hi ndlela yo biha ni ku lova ti dya tihomu ta nkombo leti sasekeke ni ku nona. Hiloko Faro a pfuka.' },
    { n: 5, text: 'A tlhela a etlela, a lora miloro ya vumbirhi: tinhloko ta nkombo ta mavele, leti teleke ni ku saseka, ti mila entiyeni yin\u2019we.' },
    { n: 6, text: 'Endzhaku ka tona, ku mila tinhloko ta nkombo ta mavele leti voneke ni ku tsemetiwa hi mheho ya le vuxeni.' },
    { n: 7, text: 'Tinhloko leti voneke ti mita tinhloko ta nkombo leti teleke ni ku nona. Faro a pfuka, a vona leswaku a ku ri miloro.' },
    { n: 8, text: 'Nimpundzu mbilu ya yena yi karhateka swinene; a rhumela ku ya vitana tin\u2019anga hinkwato ta Egipta ni tintlhari hinkwato ta rona. Faro a va hlamusela miloro ya yena, kambe a ku nga ri na munhu la nga yi hlamuselaka eka Faro.' },
    { n: 9, text: 'Hiloko mulanguteri wa vaphamele va vhinyo a vulavula na Faro, a ku: Ndzi tsundguka swidyoho bya mina namuntlha.' },
    { n: 10, text: 'Faro a a hlundgukele malandza ya yena, a ndzi nghenisa khotsweni endlwini ya mulanguteri wa masocha, mina ni mulanguteri wa vabaki.' },
    { n: 11, text: 'Hi lore miloro hi vusiku na vusiku, mina na yena; un\u2019wana ni un\u2019wana a lora miloro hi ku landza ku hlamusela ka yona.' },
    { n: 12, text: 'A ku ri na jaha ra Muheveru kwalaho na hina, nandza wa mulanguteri wa masocha; hi n\u2019wi hlamusela miloro ya hina, kutani a hi hlamusela yona, un\u2019wana ni un\u2019wana hi ku landza miloro ya yena.' },
    { n: 13, text: 'Kutani swi endlekile hilaha a nga hi hlamusela hakona: mina ndzi vuyiseriwile emutirhwini wa mina, kambe un\u2019wana a hayekiwa.' },
    { n: 14, text: 'Faro a rhumela ku ya vitana Josefa, va n\u2019wi humesa hi ku tsutsuma khotsweni; a tsemeta misisi, a cinca tinguvu, a nghena emahlweni ka Faro.' },
    { n: 15, text: 'Faro a ku eka Josefa: Ndzi lorile miloro, kambe a ku na munhu la nga yi hlamuselaka; kutani ndzi twile hi wena va ku: \u2018Loko u twa miloro, u nga yi hlamusela.\u2019' },
    { n: 16, text: 'Josefa a hlamula Faro, a ku: A hi mina; Xikwembu hi xona xi nga ta nyika Faro hlamulo wa ku rhula.' },
    { n: 17, text: 'Faro a hlamusela Josefa, a ku: Emilorweni ya mina, a ndzi yimile eribuweni ra nambu wa Nile;' },
    { n: 18, text: 'kutani enambyeni ku huma tihomu ta nkombo leti noneke ni ku saseka, ti dya byanyi ematleleni;' },
    { n: 19, text: 'endzhaku ka tona ku huma tin\u2019wana tihomu ta nkombo leti omeke, leti langutekaka hi ndlela yo biha ni ku lova, leti ndzi nga siki ku vona leti faka ni ku biha tano etikweni hinkwaro la Egipta;' },
    { n: 20, text: 'tihomu leti ovaka ni ku biha ti dya tihomu to sungula ta nkombo leti noneke;' },
    { n: 21, text: 'kambe loko ti ti miterile, a ku nga ri na mfungho lowu kombisaka leswaku ti ti miterile, hikuva ku languteka ka tona a ku bihile ku fana ni le ku sunguleni. Hiloko ndzi pfuka.' },
    { n: 22, text: 'Ndzi tlhela ndzi vona emilorweni ya mina tinhloko ta nkombo ta mavele, leti teleke ni ku saseka, ti mila entiyeni yin\u2019we;' },
    { n: 23, text: 'endzhaku ka tona ku mila tinhloko ta nkombo ta mavele leti tsemetiweke hi mheho ya le vuxeni, leti voneke ni ku lova;' },
    { n: 24, text: 'tinhloko leti ovaka ti mita tinhloko ta nkombo leti sasekeke. Ndzi hlamusele tin\u2019anga leti, kambe a ku na un\u2019we loyi a nga ndzi hlamusela.' },
    { n: 25, text: 'Josefa a ku eka Faro: Miloro ya Faro i yin\u2019we ntsena; leswi Xikwembu xi nga ta swi endla, xi swi hlamuserile Faro.' },
    { n: 26, text: 'Tihomu ta nkombo leti sasekeke i malembe ya nkombo, ni tinhloko ta nkombo leti sasekeke i malembe ya nkombo; miloro i yin\u2019we.' },
    { n: 27, text: 'Tihomu ta nkombo leti landzeleke, leti lova-ke ni ku biha, i malembe ya nkombo, ni tinhloko ta nkombo leti nga riki na nchumu, leti tsemetiweke hi mheho ya le vuxeni, ti ta va malembe ya nkombo ya ndlala.' },
    { n: 28, text: 'I mhaka leyi ndzi nga yi vula eka Faro: leswi Xikwembu xi nga ta swi endla, xi swi kombisile Faro.' },
    { n: 29, text: 'Ku ta fika malembe ya nkombo ya ku fuma lokukulu etikweni hinkwaro la Egipta;' },
    { n: 30, text: 'endzhaku ka wona ku ta fika malembe ya nkombo ya ndlala, kutani ku fuma hinkwako ku ta rivaliwa etikweni la Egipta, ndlala yi ta herisa tiko;' },
    { n: 31, text: 'ku fuma a ku nga ha tsundgukiwi etikweni hikwalaho ka ndlala leyi yi nga ta landzela, hikuva yi ta va leyi tlimbaka swinene.' },
    { n: 32, text: 'Loko miloro yi phindhiwile eka Faro kambirhi, swi vula leswaku mhaka leyi yi tiyisiwile hi Xikwembu, ni leswaku Xikwembu xi ta yi endla hi ku hatlisa.' },
    { n: 33, text: 'Hikwalaho Faro a a lave wanuna wa vutlhari ni wa ku twisisela, a n\u2019wi veka ehenhla ka tiko la Egipta.' },
    { n: 34, text: 'Faro a a endle leswi, a veka valanguteri ehenhla ka tiko, va hlengeleta xiphemu xa vuntlhanu xa leswi humesiwaka hi tiko la Egipta emalembeni ya nkombo ya ku fuma.' },
    { n: 35, text: 'Va hlengeleta swakudya hinkwaswo swa malembe lawa ya manene lama taka, va rhandzela mavele ehansi ka voko ra Faro ku va swakudya emitini, va swi hlayisa.' },
    { n: 36, text: 'Swakudya leswi swi ta va switshembiso swa tiko emalembeni ya nkombo ya ndlala, lawa ya nga ta va etikweni la Egipta, leswaku tiko xi nga herisiwi hi ndlala.' },
    { n: 37, text: 'Mhaka leyi yi tsakisa Faro ni malandza ya yena hinkwavo.' },
    { n: 38, text: 'Faro a ku eka malandza ya yena: Xana hi nga kuma wanuna la fanaka ni loyi, loyi ku nga na Moya wa Xikwembu eka yena ke?' },
    { n: 39, text: 'Faro a ku eka Josefa: Loko Xikwembu xi ku tivisile hinkwaswo leswi, a ku na munhu wa vutlhari ni wa ku twisisela ku fana na wena.' },
    { n: 40, text: 'Wena u ta va ehenhla ka yindlu ya mina, ni vanhu va mina hinkwavo va ta yingisela nawu wa wena; ndzi ta ku tlula hi xiluvelo ntsena.' },
    { n: 41, text: 'Faro a tlhela a ku eka Josefa: Vona, ndzi ku vekile ehenhla ka tiko hinkwaro la Egipta.' },
    { n: 42, text: 'Faro a humesa ringi ya mfungho evokweni ra yena, a yi nghenisa evokweni ra Josefa, a n\u2019wi ambarisa tinguvu ta linyo ro saseka, a n\u2019wi namathelisa ntsambu wa nsuku enon\u2019wini.' },
    { n: 43, text: 'A n\u2019wi fambisa hi kalichi ya vumbirhi leyi a a ri na yona; va huvelela emahlweni ka yena, va ku: Khinsamani! Hiloko a n\u2019wi veka ehenhla ka tiko hinkwaro la Egipta.' },
    { n: 44, text: 'Faro a ku eka Josefa: Ndzi Faro, kambe handle ka ku pfumela ka wena a ku na munhu loyi a nga ta tlakusa voko ra yena kumbe nenge ra yena etikweni hinkwaro la Egipta.' },
    { n: 45, text: 'Faro a thya Josefa vito ra Zafenati-Paneha; a n\u2019wi nyika Asenati, n\u2019wana wa Potifera muprista wa Oni, ku va nsati wa yena. Josefa a famba-famba etikweni la Egipta.' },
    { n: 46, text: 'Josefa a a ri ni malembe ya mune-khume (30) loko a yima mahlweni ka Faro hosi ya Egipta. Josefa a suka mahlweni ka Faro, a tsemakanya tiko hinkwaro la Egipta.' },
    { n: 47, text: 'Emalembeni ya nkombo ya ku fuma tiko ri humesa mavele hi vutalo byo tala.' },
    { n: 48, text: 'A hlengeleta swakudya hinkwaswo swa malembe ya nkombo lawa a ya ri kona etikweni la Egipta, a swi veka emitini; swakudya swa masimu lama a ya rhandzele muti un\u2019wana ni un\u2019wana a swi veka endzeni ka wona.' },
    { n: 49, text: 'Josefa a hlengeleta mavele yo tala swinene ku fana ni sava ra lwandle, ku fikela loko a tshika ku pima, hikuva a ku nga ha ri na mpimo.' },
    { n: 50, text: 'Loko lembe ra ndlala ri nga si fika, Josefa a tswalerila vana vambirhi va xinuna hi Asenati, n\u2019wana wa Potifera muprista wa Oni.' },
    { n: 51, text: 'Josefa a thya mativula vito ra Manase, hikuva a a ku: \u2018Xikwembu xi ndzi endlile ndzi rivala ku karhateka ka mina hinkwako ni yindlu hinkwayo ya tatana.\u2019' },
    { n: 52, text: 'A thya wa vumbirhi vito ra Efraimi, hikuva a a ku: \u2018Xikwembu xi ndzi endlile ndzi tswala etikweni ra ku karhateka ka mina.\u2019' },
    { n: 53, text: 'Malembe ya nkombo ya ku fuma lawa a ya ri kona etikweni la Egipta ya hela.' },
    { n: 54, text: 'Kutani malembe ya nkombo ya ndlala ya sungula ku fika, hilaha Josefa a nga vula hakona; ku ve ni ndlala ematikweni hinkwako, kambe etikweni hinkwaro la Egipta a ku ri ni swakudya.' },
    { n: 55, text: 'Loko tiko hinkwaro la Egipta ri sungula ku twa ndlala, vanhu va rila eka Faro va kombela xinkwa; Faro a ku eka Vaegipta hinkwavo: Yanani eka Josefa; leswi a nga ta mi byela swona, swiendleni.' },
    { n: 56, text: 'Ndlala a yi ri ehenhla ka tiko hinkwaro; Josefa a pfula swiphala hinkwaswo, a xavisela Vaegipta mavele; ndlala yi tlimba swinene etikweni la Egipta.' },
    { n: 57, text: 'Kutani vanhu va matiko hinkwako va fika eEgipta ku ya xava mavele eka Josefa, hikuva ndlala a yi tlimba swinene ematikweni hinkwako.' },
  ],
  42: [
    { n: 1, text: 'Akobo a twa leswaku ku ni mavele eEgipta, hiloko Akobo a ku eka vana va yena: Ha yini mi langutanaka ntsena ke?' },
    { n: 2, text: 'A ku: Vonani, ndzi twile leswaku ku ni mavele eEgipta; rhelelani kwalaho, mi ya hi xavela mavele, leswaku hi hanya, hi nga fi.' },
    { n: 3, text: 'Vamakwerhu va Josefa va khume va rhelela ku ya xava mavele eEgipta.' },
    { n: 4, text: 'Kambe Akobo a nga rhumanga Benjamini, makwerhu wa Josefa, na vamakwerhu va yena; hikuva a a ku: \u2018Kumbexana khombo ri nga n\u2019wi kela.\u2019' },
    { n: 5, text: 'Vana va Israyele va fika ku ya xava mavele xikan\u2019we ni lava a va fika, hikuva ndlala a yi ri etikweni ra Kanana.' },
    { n: 6, text: 'Josefa a a ri mulanguteri wa tiko; hi yena loyi a a xavisela vanhu hinkwavo va tiko mavele. Vamakwerhu va Josefa va fika, va n\u2019wi khinsamela swikandza swa vona swi khumba hansi.' },
    { n: 7, text: 'Loko Josefa a vona vamakwerhu va yena, a va tiva, kambe a tiendla un\u2019wana eka vona, a vulavula na vona hi rito ra ku nonon\u2019hwa, a ku: Mi huma kwihi ke? Va ku: Hi huma etikweni ra Kanana ku ya xava swakudya.' },
    { n: 8, text: 'Josefa a a tiva vamakwerhu va yena, kambe vona a va nga n\u2019wi tivi.' },
    { n: 9, text: 'Josefa a tsundguka miloro leyi a nga yi lora hi vona, a ku eka vona: Mi tinhlori; mi fikele ku ta vona vusweti bya tiko.' },
    { n: 10, text: 'Va ku eka yena: E-e, n\u2019wini wa mina, malandza ya wena ma fikele ku ya xava swakudya ntsena.' },
    { n: 11, text: 'Hina hinkwerhu hi vana va wanuna un\u2019we; hi vanhu lava lulameke, malandza ya wena a hi tinhlori.' },
    { n: 12, text: 'A ku eka vona: E-e, mi fikele ku ta vona vusweti bya tiko.' },
    { n: 13, text: 'Va ku: Malandza ya wena hi vamakwerhu va khume-mbirhi (12), vana va wanuna un\u2019we etikweni ra Kanana; un\u2019wana lontsongo sweswi u na tata wa hina, kasi un\u2019wana a nga ha ri kona.' },
    { n: 14, text: 'Josefa a ku eka vona: Hi swona lesvi ndzi nga mi byela swona, ndzi ku: \u2018Mi tinhlori.\u2019' },
    { n: 15, text: 'Hi leswi mi nga ta kamberiwa ha swona: hi vutomi bya Faro, mi nga ka mi nga humi kwala handle loko makwerhu wa n\u2019wina lontsongo a nga fikanga kwala.' },
    { n: 16, text: 'Rhumelani un\u2019wana wa n\u2019wina ku ya teka makwerhu wa n\u2019wina, kutani n\u2019wina mi ta tshama khotsweni, leswaku marito ya n\u2019wina ma kamberiwa, ku vona loko ku ri ni ntiyiso eka n\u2019wina; loko ku nga ri tano, hi vutomi bya Faro, hakunene mi tinhlori.' },
    { n: 17, text: 'A va nghenisa hinkwavo khotsweni masiku manharhu.' },
    { n: 18, text: 'Hi siku ra vunharhu Josefa a ku eka vona: Endlani leswi, mi hanya, hikuva ndzi chava Xikwembu.' },
    { n: 19, text: 'Loko mi ri vanhu lava lulameke, un\u2019wana wa vamakwerhu va n\u2019wina a a sale khotsweni lomu mi nga bohiwa kona; kutani n\u2019wina van\u2019wana fambani, mi yisa mavele ya ndlala ya tindlu ta n\u2019wina;' },
    { n: 20, text: 'kambe mi ndzi tisele makwerhu wa n\u2019wina lontsongo, leswaku marito ya n\u2019wina ma tiyisiwa, mi nga fi. Kutani va endla tano.' },
    { n: 21, text: 'Va vula un\u2019wana ni un\u2019wana, va ku: Hakunene hi na nandzu hikwalaho ka makwerhu wa hina, loyi hi nga vona ku karhateka ka mbilu ya yena loko a hi kombela tintswalo, kambe a hi n\u2019wi yingiselanga; hikwalaho ku karhateka loku ku hi kela.' },
    { n: 22, text: 'Rubeni a va hlamula, a ku: Xana a ndzi mi byelanga ndzi ku: \u2018Mi nga dyoheli jaha leri ke?\u2019 Kambe a mi ndzi yingiselanga; kutani langutani, ngati ya yena ya vutisiwa.' },
    { n: 23, text: 'A va nga tivi leswaku Josefa wa va twisisa, hikuva a ku ri na muhundzuluxi wa ririmi exikarhi ka vona.' },
    { n: 24, text: 'Josefa a va hundzulukela, a rila; a tlhela a vuyela eka vona, a vulavula na vona, a teka Simiyoni exikarhi ka vona, a n\u2019wi boha mahlweni ka mahlo ya vona.' },
    { n: 25, text: 'Josefa a lerisa leswaku va tata swikhwama va vona hi mavele, va tlherisela mali ya un\u2019wana ni un\u2019wana exikhwameni xa yena, ni ku va nyika swakudya swa ndlela. Kutani va va endlerila tano.' },
    { n: 26, text: 'Va rhandzela mavele ya vona ehenhla ka timbanga ta vona, va famba.' },
    { n: 27, text: 'Loko un\u2019wana a pfula xikhwama xa yena ku ya nyika mbanga ya yena swakudya endhawini ya ku etlela, a vona mali ya yena kusuhi ni nonu wa xikhwama xa yena.' },
    { n: 28, text: 'A ku eka vamakwerhu va yena: Mali ya mina yi tlheriseriwile; vonani, yi le xikhwameni xa mina! Hiloko timbilu ta vona ti tsana, va tsemeka rito va langutana, va ku: I yini lexi Xikwembu xi nga hi endla xona ke?' },
    { n: 29, text: 'Va fika eka Akobo tata wa vona etikweni ra Kanana, va n\u2019wi hlamusela hinkwaswo leswi nga va kela, va ku:' },
    { n: 30, text: 'Wanuna, mulanguteri wa tiko, u vulavurile na hina hi rito ra ku nonon\u2019hwa, a ku i tinhlori leti fikeleke ku ta vona tiko.' },
    { n: 31, text: 'Hi ku eka yena: \u2018Hi vanhu lava lulameke, a hi tinhlori.' },
    { n: 32, text: 'Hi vamakwerhu va khume-mbirhi (12), vana va tata wa hina; un\u2019wana a nga ha ri kona, kutani lontsongo sweswi u na tata wa hina etikweni ra Kanana.\u2019' },
    { n: 33, text: 'Wanuna, mulanguteri wa tiko, a ku eka hina: \u2018Hi lesvi ndzi nga ta tiva ha swona leswaku mi vanhu lava lulameke: siyani un\u2019wana wa vamakwerhu va n\u2019wina na mina, mi teka swakudya swa ndlala ya tindlu ta n\u2019wina, mi famba;' },
    { n: 34, text: 'ndzi tiseleni makwerhu wa n\u2019wina lontsongo, leswaku ndzi tiva leswaku a mi tinhlori, kambe mi vanhu lava lulameke; kutani ndzi ta mi nyika makwerhu wa n\u2019wina, mi nga famba-famba etikweni.\u2019' },
    { n: 35, text: 'Loko va ha humesa mavele eswikhwameni va vona, vonani, ntsengo wa mali ya un\u2019wana ni un\u2019wana a u ri exikhwameni xa yena; loko vona ni tata wa vona va vona mitsengo ya mali ya vona, va chava swinene.' },
    { n: 36, text: 'Akobo tata wa vona a ku eka vona: Mi ndzi herisile vana: Josefa a nga ha ri kona, Simiyoni a nga ha ri kona, kutani mi lava ku teka na Benjamini! Swilo leswi hinkwaswo swi lwa na mina.' },
    { n: 37, text: 'Rubeni a vulavula na tata wa yena, a ku: Dlayani vana va mina vambirhi va xinuna loko ndzi nga vuyi na yena eka wena; n\u2019wi veke emavokweni ya mina, ndzi ta vuya na yena eka wena.' },
    { n: 38, text: 'Kambe a ku: N\u2019wana wa mina a nga ka a nga rheleli na n\u2019wina, hikuva makwerhu wa yena u file, kutani yena u sele a ri yexe; loko khombo ri nga n\u2019wi kela endleleni leyi mi yaka ha yona, mi ta rhelerisa misisi ya mina ya vupfari hi ku karhateka esirheni.' },
  ],
  43: [
    { n: 1, text: 'Ndlala a yi ri leyi tlimbaka swinene etikweni.' },
    { n: 2, text: 'Loko va dyile va heta mavele lawa va nga ya teka eEgipta, tata wa vona a ku eka vona: Tlhelelani, mi ya hi xavela swakudya swintsongo.' },
    { n: 3, text: 'Kambe Yuda a vulavula na yena, a ku: Wanuna loyi u hi tiyisela swinene, a ku: \u2018Mi nga ka mi nga voni xikandza xa mina loko makwerhu wa n\u2019wina a nga ri na n\u2019wina.\u2019' },
    { n: 4, text: 'Loko u rhumela makwerhu wa hina na hina, hi ta rhelela, hi ya ku xavela swakudya;' },
    { n: 5, text: 'kambe loko u nga n\u2019wi rhumeli, a hi nga rheleli, hikuva wanuna loyi u hi byerile a ku: \u2018Mi nga ka mi nga voni xikandza xa mina loko makwerhu wa n\u2019wina a nga ri na n\u2019wina.\u2019' },
    { n: 6, text: 'Israyele a ku: Ha yini mi ndzi endlerile vubihi lebyi, hi ku hlamusela wanuna loyi leswaku mi ni un\u2019wana makwerhu ke?' },
    { n: 7, text: 'Va ku: Wanuna loyi u hi vutisise swinene hi hina ni hi kuxaka ka hina, a ku: \u2018Xana tata wa n\u2019wina wa ha hanya ke? Xana mi ni un\u2019wana makwerhu ke?\u2019 Kutani hi n\u2019wi hlamuserile hi ku landza marito lawa. Xana a hi nga tivi leswaku u ta ku: \u2018Rhelelerisani makwerhu wa n\u2019wina kwala ke?\u2019' },
    { n: 8, text: 'Yuda a ku eka Israyele tata wa yena: Rhumela jaha leri na mina, hi ta pfuka hi famba, leswaku hi hanya, hi nga fi, hina ni wena ni vana va hina.' },
    { n: 9, text: 'Ndzi ta tiyisa vutomi bya yena; u ta n\u2019wi vutisa emavokweni ya mina; loko ndzi nga vuyi na yena eka wena, ndzi n\u2019wi yimisa mahlweni ka wena, ndzi ta va ni nandzu eka wena masiku hinkwako.' },
    { n: 10, text: 'Hikuva loko hi nga hlwelanga, hakunene sweswi a hi ta va hi vuyile kambirhi.' },
    { n: 11, text: 'Israyele tata wa vona a ku eka vona: Loko swi ri tano, endlani leswi: tekani swilo swo saseka swa tiko eswikhwameni swa n\u2019wina, mi rhelerisa nyiko eka wanuna loyi: balsama swintsongo, ni vulombe swintsongo, ni swinun\u2019hweriso, ni myra, ni timanga ta nhova, ni timanga ta alandza;' },
    { n: 12, text: 'tekani mali leyi phindhiweke emavokweni ya n\u2019wina, ni mali leyi nga tlherisiwa kusuhi ni nonu wa swikhwama swa n\u2019wina mi famba na yona emavokweni ya n\u2019wina; kumbexana a ku ri xihoxo;' },
    { n: 13, text: 'tekani ni makwerhu wa n\u2019wina, mi pfuka mi tlhelela eka wanuna loyi.' },
    { n: 14, text: 'Xikwembu xa Matimba Hinkwako xi mi nyike tintswalo mahlweni ka wanuna loyi, leswaku a mi ntshunxela makwerhu wa n\u2019wina un\u2019wana ni Benjamini. Loko ndzi fanela ku heriseriwa vana, a ndzi heriseriwe ntsena.' },
    { n: 15, text: 'Hiloko vavanuna va teka nyiko leyi, va teka ni mali leyi phindhiweke emavokweni ya vona xikan\u2019we ni Benjamini; va pfuka va rhelela eEgipta, va ya yima mahlweni ka Josefa.' },
    { n: 16, text: 'Loko Josefa a vona Benjamini a ri na vona, a ku eka mulanguteri wa yindlu ya yena: Nghenisa vavanuna lava endlwini, u tlhava swifuwo, u swi lunghiselela; hikuva vavanuna lava va ta dya na mina nhlikanhi.' },
    { n: 17, text: 'Wanuna loyi a endla hilaha Josefa a nga vula hakona, a nghenisa vavanuna lava endlwini ya Josefa.' },
    { n: 18, text: 'Vavanuna lava va chava loko va nghenisiwa endlwini ya Josefa, va ku: Hi nghenisela hikwalaho ka mali leyi nga tlherisiwa eswikhwameni swa hina eku sunguleni, leswaku va hi lundza, va hi kela, va hi teka hi va mahlonga xikan\u2019we ni timbanga ta hina.' },
    { n: 19, text: 'Va tshinela kusuhi ni mulanguteri wa yindlu ya Josefa, va vulavula na yena enonwini wa yindlu,' },
    { n: 20, text: 'va ku: Ndzi kombela u hi yingisela, n\u2019wini wa mina; hakunene hi rhelerile eku sunguleni ku ya xava swakudya;' },
    { n: 21, text: 'kutani loko hi fikele endhawini ya ku etlela, hi pfula swikhwama swa hina, kutani vona, mali ya un\u2019wana ni un\u2019wana a yi ri enonwini wa xikhwama xa yena, mali ya hina hi ku pima ka yona; sweswi hi vuye na yona emavokweni ya hina.' },
    { n: 22, text: 'Hi rhelerise ni yin\u2019wana mali emavokweni ya hina ku ya xava swakudya; a hi tivi loyi a nga veka mali ya hina eswikhwameni swa hina.' },
    { n: 23, text: 'A ku: Ku rhula a ku ve na n\u2019wina, mi nga chavi; Xikwembu xa n\u2019wina ni Xikwembu xa tata wa n\u2019wina xi mi nyikile xuma eswikhwameni swa n\u2019wina; mali ya n\u2019wina yi fikele eka mina. Hiloko a va humesela Simiyoni.' },
    { n: 24, text: 'Wanuna loyi a nghenisa vavanuna lava endlwini ya Josefa, a va nyika mati va hlamba milenge, a nyika ni timbanga ta vona swakudya.' },
    { n: 25, text: 'Va lunghisa nyiko ya vona ku yimela Josefa a fika nhlikanhi, hikuva va twile leswaku va ta dya xinkwa kwalaho.' },
    { n: 26, text: 'Loko Josefa a nghena endlwini, va n\u2019wi yisela nyiko leyi a yi ri emavokweni ya vona endzeni ka yindlu, va n\u2019wi khinsamela hansi.' },
    { n: 27, text: 'A va vutisa leswaku va njhani, a ku: Xana tata wa n\u2019wina, mukhalabye loyi mi nga vulavula hi yena, wa ha hanya ke? Wa ha hanya ke?' },
    { n: 28, text: 'Va ku: Nandza wa wena, tata wa hina, wa ha hanya, u hlayisekile. Hiloko va khinsama, va n\u2019wi tlhantla.' },
    { n: 29, text: 'A tlakusa mahlo ya yena, a vona Benjamini makwerhu wa yena, n\u2019wana wa mhani wa yena, a ku: Xana loyi i makwerhu wa n\u2019wina lontsongo, loyi mi nga vulavula hi yena eka mina ke? A ku: Xikwembu a xi ku nyike tintswalo, n\u2019wana wa mina.' },
    { n: 30, text: 'Josefa a tsutsuma ku huma, hikuva mbilu ya yena a yi n\u2019wi tlimba hikwalaho ka makwerhu wa yena, a lava ndhawu yo rila; a nghena ekamareni ra yena, a rila kwalaho.' },
    { n: 31, text: 'A hlamba xikandza, a huma; a tikhoma, a ku: Phamela swakudya!' },
    { n: 32, text: 'Va n\u2019wi phamela a ri yexe, va phamela na vona va ri voxe, ni Vaegipta lava a va dya na yena va ri voxe; hikuva Vaegipta a va nga fanelanga ku dya xinkwa ni Vaheveru, hikuva i nchumu lowu nyenyetsaka eka Vaegipta.' },
    { n: 33, text: 'Va tshama emahlweni ka yena: mativula hi ku landza vutivula bya yena, ni lontsongo hi ku landza vuntsongo wa yena; vavanuna lava va hlamalana swinene xikarhi ka vona.' },
    { n: 34, text: 'A va nyika swiphemu swa swakudya leswi humaka emahlweni ka yena; kambe xiphemu xa Benjamini a xi tlula swiphemu swa van\u2019wana hinkwavo hi ka ntlhanu. Va nwa, va tsaka swinene na yena.' },
  ],

  44: [
    { n: 1, text: 'Josefa a lerisa mulanguteri wa yindlu ya yena, a ku: Tata swikhwama swa vavanuna lava hi swakudya sweswi va nga swi rwalaka, u veka ni mali ya un\u2019wana ni un\u2019wana enonwini wa xikhwama xa yena.' },
    { n: 2, text: 'Kutani u nghenisa xinwelo xa mina, xinwelo xa silivhere, enonwini wa xikhwama xa lontsongo xikan\u2019we ni mali ya mavele ya yena. A endla hilaha Josefa a nga vula hakona.' },
    { n: 3, text: 'Nimpundzu, loko ri xa, vavanuna va fambisiwa xikan\u2019we ni timbanga ta vona.' },
    { n: 4, text: 'Loko va humile emutini kambe va nga si ya kule, Josefa a ku eka mulanguteri wa yindlu ya yena: Pfuka, landzelela vavanuna lava; loko u va kuma, u ta ku eka vona: \u2018Ha yini mi tlheriseleke vubihi eka leswo saseka ke?' },
    { n: 5, text: 'Xana lexi a hi xona xinwelo lexi n\u2019wini wa mina a nwelaka eka xona, lexi a xi tirhisaka ku hlahluva ha xona ke? Mi endle leswo biha swinene hi ku endla leswi.\u2019' },
    { n: 6, text: 'A va kuma, a va byela marito lawa.' },
    { n: 7, text: 'Va ku eka yena: Ha yini n\u2019wini wa mina a vulavula marito yo tano ke? Swi le kule ni malandza ya wena ku endla nchumu wa ku fana ni lowu.' },
    { n: 8, text: 'Vona, mali leyi hi nga yi kuma enonwini wa swikhwama swa hina, hi yi tlherisile eka wena yi huma etikweni ra Kanana; xana hi nga yiva njhani silivhere kumbe nsuku endlwini ya n\u2019wini wa wena ke?' },
    { n: 9, text: 'Loyisaka malandza ya wena a nga ta kumiwa na xona, a a fe, kutani hina hi ta va mahlonga ya n\u2019wini wa hina.' },
    { n: 10, text: 'A ku: Sweswi a ku ve hilaha mi nga vula hakona: loyi a nga ta kumiwa na xona u ta va hlonga ra mina, kambe n\u2019wina van\u2019wana mi ta va lava nga riki na nandzu.' },
    { n: 11, text: 'Hiloko va hatlisa ku rhelerisa un\u2019wana ni un\u2019wana xikhwama xa yena hansi, un\u2019wana ni un\u2019wana a pfula xikhwama xa yena.' },
    { n: 12, text: 'A lavisisa, a sungula hi mativula a hetelela hi lontsongo; kutani xinwelo xi kumiwa exikhwameni xa Benjamini.' },
    { n: 13, text: 'Hiloko va handzula tinguvu ta vona, va rhandzela un\u2019wana ni un\u2019wana mbanga ya yena, va tlhelela emutini.' },
    { n: 14, text: 'Yuda ni vamakwerhu va yena va nghena endlwini ya Josefa, hikuva a a ha ri kwalaho; va n\u2019wi khinsamela hansi.' },
    { n: 15, text: 'Josefa a ku eka vona: I yini lexi mi nga xi endla lexi ke? Xana a mi swi tivi leswaku wanuna la fanaka na mina a nga hlahluva hakunene ke?' },
    { n: 16, text: 'Yuda a ku: Xana hi nga vula yini eka n\u2019wini wa mina ke? Hi nga vulavula yini ke? Hi nga kombisisa njhani ku lulama ka hina ke? Xikwembu xi kumile vubihi bya malandza ya wena; vona, hi mahlonga ya n\u2019wini wa mina, hina ni loyi xinwelo xi nga kumiwa evokweni ra yena.' },
    { n: 17, text: 'Kambe a ku: Swi le kule na mina ku endla leswi; wanuna loyi xinwelo xi nga kumiwa evokweni ra yena hi yena loyi a nga ta va hlonga ra mina; kambe n\u2019wina tlhelelani hi ku rhula eka tata wa n\u2019wina.' },
    { n: 18, text: 'Yuda a tshinela kusuhi na yena, a ku: Ndzi kombela u ndzi yingisela, n\u2019wini wa mina, ndzi pfumelele ndzi vulavula rito un\u2019we etindleveni ta n\u2019wini wa mina, u nga hlundgukeli nandza wa wena, hikuva u fana na Faro hi xiviri.' },
    { n: 19, text: 'N\u2019wini wa mina u vutisile malandza ya wena, a ku: \u2018Xana mi ni tata kumbe makwerhu ke?\u2019' },
    { n: 20, text: 'Kutani hi ku eka n\u2019wini wa mina: \u2018Hi ni tata la nga mukhalabye, ni n\u2019wana wa vuntshwa bya yena la nga lontsongo; makwerhu wa yena u file, kutani yena a ri yexe u sele eka mhani wa yena, ni tata wa yena wa n\u2019wi rhandza.\u2019' },
    { n: 21, text: 'Kutani u ku eka malandza ya wena: \u2018N\u2019wi rheleriseni kwala eka mina, leswaku ndzi n\u2019wi vona hi mahlo ya mina.\u2019' },
    { n: 22, text: 'Kambe hi ku eka n\u2019wini wa mina: \u2018Jaha leri a ri nga ka ri nga siyi tata wa rona; loko ri siya tata wa rona, tata wa rona a nga fa.\u2019' },
    { n: 23, text: 'Kambe u ku eka malandza ya wena: \u2018Loko makwerhu wa n\u2019wina lontsongo a nga rheleli na n\u2019wina, mi nga ka mi nga ha voni xikandza xa mina.\u2019' },
    { n: 24, text: 'Loko hi tlhelele eka nandza wa wena tata wa hina, hi n\u2019wi hlamuserile marito ya n\u2019wini wa mina.' },
    { n: 25, text: 'Kutani tata wa hina a ku: \u2018Tlhelelani, mi ya hi xavela swakudya swintsongo.\u2019' },
    { n: 26, text: 'Kambe hi ku: \u2018A hi nga rheleli; loko makwerhu lontsongo a ri na hina, hi ta rhelela; hikuva a hi nga ka hi nga voni xikandza xa wanuna loyi loko makwerhu wa hina lontsongo a nga ri na hina.\u2019' },
    { n: 27, text: 'Nandza wa wena tata wa hina a ku eka hina: \u2018Mi swi tiva leswaku nsati wa mina u ndzi tswalerile vana vambirhi;' },
    { n: 28, text: 'un\u2019wana u humile eka mina, kutani ndzi ku: \u201cHakunene u handzuriwile hi swifuwo ta nhova,\u201d naswona a ndzi nga siki ku n\u2019wi vona ku fikela namuntlha;' },
    { n: 29, text: 'loko mi teka ni loyi eka mina, kutani khombo ri n\u2019wi kela, mi ta rhelerisa misisi ya mina ya vupfari hi ku karhateka esirheni.\u2019' },
    { n: 30, text: 'Sweswi, loko ndzi fika eka nandza wa wena tata wa hina, jaha leri ri nga ri na hina, hikuva vutomi bya yena byi namarhele vutomi bya jaha leri,' },
    { n: 31, text: 'loko a vona leswaku jaha leri a ri kona, u ta fa; kutani malandza ya wena ma ta rhelerisa misisi ya vupfari ya nandza wa wena tata wa hina hi ku karhateka esirheni.' },
    { n: 32, text: 'Hikuva nandza wa wena u tiyisile vutomi bya jaha leri eka tata wa mina, ndzi ku: \u2018Loko ndzi nga vuyi na yena eka wena, ndzi ta va ni nandzu eka tata wa mina masiku hinkwako.\u2019' },
    { n: 33, text: 'Sweswi, ndzi kombela leswaku nandza wa wena a sala ku va hlonga ra n\u2019wini wa mina exihundleni xa jaha leri, kutani jaha ri famba na vamakwerhu va rona.' },
    { n: 34, text: 'Hikuva ndzi nga tlhelela njhani eka tata wa mina loko jaha leri ri nga ri na mina ke? Ndzi chava ku vona vubihi lebyi nga taka eka tata wa mina.' },
  ],
  45: [
    { n: 1, text: 'Josefa a a nga ha swi koti ku tikhoma mahlweni ka hinkwavo lava a va yimile kusuhi na yena, a huvelela, a ku: Humesani vanhu hinkwavo eka mina! A ku nga ri na munhu kusuhi na yena loko Josefa a tiyisa vutivi eka vamakwerhu va yena.' },
    { n: 2, text: 'A rila hi rito ro tlakuka swinene, Vaegipta va n\u2019wi twa, ni yindlu ya Faro yi twa.' },
    { n: 3, text: 'Josefa a ku eka vamakwerhu va yena: Hi mina Josefa; xana tata wa mina wa ha hanya ke? Kambe vamakwerhu va yena a va nga swi koti ku n\u2019wi hlamula, hikuva a va chava swinene mahlweni ka yena.' },
    { n: 4, text: 'Josefa a ku eka vamakwerhu va yena: Tshinela kusuhi na mina. Va tshinela kusuhi. A ku: Hi mina Josefa makwerhu wa n\u2019wina, loyi mi nga n\u2019wi xavisa eEgipta.' },
    { n: 5, text: 'Sweswi, mi nga karhateki kumbe ku tivona mi dyohe mbilwini hikuva mi ndzi xavisele kwala; hikuva Xikwembu xi ndzi rhumile emahlweni ka n\u2019wina ku va muponisi wa vutomi.' },
    { n: 6, text: 'Hikuva se i malembe mambirhi ndlala yi ri etikweni, naswona ka ha sale malembe ya nkombo lawa ku nga ta va na ku rima kumbe ku tshovela.' },
    { n: 7, text: 'Xikwembu xi ndzi rhumile emahlweni ka n\u2019wina ku mi vekela ntsengo etikweni, ni ku mi ponisa hi kuponisiwa lokukulu.' },
    { n: 8, text: 'Kutani a hi n\u2019wina mi nga ndzi rhuma kwala, kambe i Xikwembu; xi ndzi endlile tatana eka Faro, ni n\u2019wini wa yindlu ya yena hinkwayo, ni mulanguteri wa tiko hinkwaro la Egipta.' },
    { n: 9, text: 'Hatlisani mi tlhelela eka tata wa mina, mi ku eka yena: \u2018Hi lesvi n\u2019wana wa wena Josefa a nga vula, a ku: Xikwembu xi ndzi endlile n\u2019wini wa Egipta hinkwaro; rhelela u fika eka mina, u nga hlweli;' },
    { n: 10, text: 'u ta tshama etikweni ra Goxeni, u ta va kusuhi na mina, wena ni vana va wena, ni vana va vana va wena, ni swifuwo swa wena swa titsongo ni swa tinhulu, ni hinkwaswo leswi u nga na swona;' },
    { n: 11, text: 'ndzi ta ku hlayisa kwalaho, hikuva ka ha sale malembe ya ntlhanu ya ndlala, leswaku wena ni yindlu ya wena ni hinkwaswo leswi u nga na swona mi nga wupfeli vusiwana.\u2019' },
    { n: 12, text: 'Vona, mahlo ya n\u2019wina ma vona, ni mahlo ya makwerhu Benjamini ma vona, leswaku i nonu wa mina lowu vulavulaka na n\u2019wina.' },
    { n: 13, text: 'Hlamuselani tata wa mina ku kwetsima hinkwako loku ndzi nga na kona eEgipta, ni hinkwaswo leswi mi nga swi vona; hatlisani mi rhelerisa tata wa mina kwala.' },
    { n: 14, text: 'Hiloko a wela enon\u2019wini wa Benjamini makwerhu wa yena, a rila, na Benjamini a rila enon\u2019wini wa yena.' },
    { n: 15, text: 'A ntswontswa vamakwerhu va yena hinkwavo, a va rila ehenhla ka vona; endzhaku ka sweswo vamakwerhu va yena va vulavula na yena.' },
    { n: 16, text: 'Mhaka leyi yi twala endlwini ya Faro, va ku: Vamakwerhu va Josefa va fikile. Swi tsakisa Faro ni malandza ya yena.' },
    { n: 17, text: 'Faro a ku eka Josefa: Byela vamakwerhu va wena, u ku: \u2018Endlani leswi: rhandzelani swifuwo swa n\u2019wina, mi famba mi ya etikweni ra Kanana;' },
    { n: 18, text: 'tekani tata wa n\u2019wina ni tindlu ta n\u2019wina, mi fika eka mina, ndzi ta mi nyika leswo saseka swa tiko la Egipta, kutani mi ta dya mafurha ya tiko.\u2019' },
    { n: 19, text: 'Sweswi u lerisiwile ku va byela, u ku: \u2018Endlani leswi: tekani ticalichi etikweni la Egipta hikwalaho ka vana va n\u2019wina ni vasati va n\u2019wina, mi teka tata wa n\u2019wina mi fika na yena.' },
    { n: 20, text: 'Mi nga vileli hi swibya swa n\u2019wina, hikuva leswo saseka swa tiko hinkwaro la Egipta i swa n\u2019wina.\u2019' },
    { n: 21, text: 'Vana va Israyele va endla tano; Josefa a va nyika ticalichi hi ku landza xileriso xa Faro, a va nyika ni swakudya swa ndlela.' },
    { n: 22, text: 'Un\u2019wana ni un\u2019wana a n\u2019wi nyika tinguvu ta ku cinca; kambe Benjamini a n\u2019wi nyika dzenge ra silivhere ta ntsandza-vahlayi wa tikhume-nharhu (300) ni tinguvu ta ntlhanu ta ku cinca.' },
    { n: 23, text: 'A rhumela eka tata wa yena swilo leswi: timbanga ta khume leti rhandzeleke swilo swo saseka swa Egipta, ni timbanga ta khume ta xisati leti rhandzeleke mavele, ni xinkwa, ni swakudya swa tata wa yena swa ndlela.' },
    { n: 24, text: 'A fambisa vamakwerhu va yena, va famba; a ku eka vona: Mi nga holovi endleleni.' },
    { n: 25, text: 'Va suka eEgipta, va fika etikweni ra Kanana eka Akobo tata wa vona.' },
    { n: 26, text: 'Va n\u2019wi hlamusela, va ku: Josefa wa ha hanya, naswona hi yena mulanguteri wa tiko hinkwaro la Egipta. Kutani mbilu ya yena yi tsana, hikuva a a nga va kholwi.' },
    { n: 27, text: 'Kambe loko va n\u2019wi hlamuserile marito hinkwaswo ya Josefa lawa a nga va byela wona, ni loko a vonile ticalichi leti Josefa a nga ti rhumela ku ya n\u2019wi teka, moya wa Akobo tata wa vona wu hanye.' },
    { n: 28, text: 'Israyele a ku: Swi ringene! Josefa n\u2019wana wa mina wa ha hanya; ndzi ta famba ndzi ya n\u2019wi vona ndzi nga si fa.' },
  ],
  46: [
    { n: 1, text: 'Israyele a famba ni hinkwaswo leswi a a ri na swona, a fika eBerixeba, a tlhabela Xikwembu xa tata wa yena Isaka switlhavelo.' },
    { n: 2, text: 'Xikwembu xi vulavula na Israyele emiloringi ya vusiku, xi ku: Akobo! Akobo! A ku: Ndzi kwala.' },
    { n: 3, text: 'Xi ku: Hi mina Xikwembu, Xikwembu xa tata wa wena; u nga chavi ku rhelela eEgipta, hikuva ndzi ta ku endla tiko lera kulu kwalaho.' },
    { n: 4, text: 'Ndzi ta rhelela na wena eEgipta, naswona hakunene ndzi ta ku vuyisa kwala; kutani Josefa u ta pfala mahlo ya wena hi voko ra yena.' },
    { n: 5, text: 'Akobo a pfuka eBerixeba; vana va Israyele va teka Akobo tata wa vona, ni vana va vona va titsongo, ni vasati va vona, eticalichini leti Faro a nga ti rhumela ku ya n\u2019wi teka.' },
    { n: 6, text: 'Va teka ni swifuwo swa vona ni xuma xa vona lexi va nga xi kuma etikweni ra Kanana, va fika eEgipta, Akobo ni vana va yena hinkwavo na yena;' },
    { n: 7, text: 'vana va yena va xinuna, ni vana va vana va yena na yena, vana va yena va xisati, ni vana va vana va yena va xisati, ni vana va yena hinkwavo a fika na vona eEgipta.' },
    { n: 8, text: 'Lawa i mavito ya vana va Israyele lava nga fika eEgipta, Akobo ni vana va yena: Rubeni, mativula ya Akobo.' },
    { n: 9, text: 'Vana va Rubeni: Hanoki, Palu, Hezroni, ni Karmi.' },
    { n: 10, text: 'Vana va Simiyoni: Yemuwela, Yamini, Ohada, Yakini, Zohara, ni Xawulo n\u2019wana wa mu-Kanana.' },
    { n: 11, text: 'Vana va Levi: Gerxoni, Kohata, ni Merari.' },
    { n: 12, text: 'Vana va Yuda: Ere, Onani, Xela, Perezi, ni Zera (kambe Ere na Onani va ferile etikweni ra Kanana). Vana va Perezi ku ve Hezroni na Hamula.' },
    { n: 13, text: 'Vana va Isakara: Tola, Puva, Yobu, ni Ximroni.' },
    { n: 14, text: 'Vana va Zebuloni: Seredi, Eloni, ni Yalele.' },
    { n: 15, text: 'Lawa i vana va Liyaha, lava a nga va tswalela Akobo ePadani-Arami, xikan\u2019we ni n\u2019wana wa yena wa xisati Dina; vutomi hinkwabyo bya vana va yena va xinuna ni va xisati a va ri makume-nharhu na nharhu (33).' },
    { n: 16, text: 'Vana va Gadi: Sifiyoni, Hagi, Xuni, Ezboni, Eri, Arodi, ni Areli.' },
    { n: 17, text: 'Vana va Axere: Imna, Ixva, Ixvi, Beriya, ni makwerhu wa vona wa xisati Sera. Vana va Beriya: Hebere ni Malkiyela.' },
    { n: 18, text: 'Lawa i vana va Zilpa, loyi Labani a nga n\u2019wi nyika Liyaha n\u2019wana wa yena, loyi a nga tswalela Akobo vana lava: vanhu va khume-ntsevu (16).' },
    { n: 19, text: 'Vana va Rahele, nsati wa Akobo: Josefa na Benjamini.' },
    { n: 20, text: 'Josefa a tswalerila vana eEgipta, lava a nga va tswaleriwa hi Asenati n\u2019wana wa Potifera muprista wa Oni: Manase na Efraimi.' },
    { n: 21, text: 'Vana va Benjamini: Bela, Bekere, Axbele, Gera, Namani, Ehi, Roxi, Mupimi, Hupimi, ni Ardi.' },
    { n: 22, text: 'Lawa i vana va Rahele, lava a nga va tswalela Akobo; vanhu hinkwavo a va ri khume-mune (14).' },
    { n: 23, text: 'N\u2019wana wa Dani: Huximi.' },
    { n: 24, text: 'Vana va Neftali: Yayitsela, Guni, Yesere, ni Silemu.' },
    { n: 25, text: 'Lawa i vana va Bilha, loyi Labani a nga n\u2019wi nyika Rahele n\u2019wana wa yena, loyi a nga tswalela Akobo vana lava; vanhu hinkwavo a va ri nkombo (7).' },
    { n: 26, text: 'Vanhu hinkwavo lava nga fika na Akobo eEgipta, lava humaka eka yena, handle va vasati va vana va Akobo, vanhu hinkwavo a va ri makume-ntandathu na tsevu (66).' },
    { n: 27, text: 'Vana va Josefa lava a nga tswalerila vana eEgipta a va ri vambirhi. Vanhu hinkwavo va yindlu ya Akobo lava nga fika eEgipta a va ri makume-nkombo (70).' },
    { n: 28, text: 'Akobo a rhumela Yuda emahlweni ka yena eka Josefa, ku ya kombisa ndlela eGoxeni; hiloko va fika etikweni ra Goxeni.' },
    { n: 29, text: 'Josefa a lunghisa kalichi ya yena, a ya eGoxeni ku ya hlangana na Israyele tata wa yena; a tiyisa vutivi eka yena, a wela enon\u2019wini wa yena, a rila enon\u2019wini wa yena nkarhi wo leha.' },
    { n: 30, text: 'Israyele a ku eka Josefa: Sweswi ndzi nga fa, hikuva ndzi vonile xikandza xa wena, leswaku wa ha hanya.' },
    { n: 31, text: 'Josefa a ku eka vamakwerhu va yena ni le ka yindlu ya tata wa yena: Ndzi ta tlhandluka ndzi ya hlamusela Faro, ndzi ku eka yena: \u2018Vamakwerhu va mina ni yindlu ya tata wa mina, lava a va ri etikweni ra Kanana, va fikile eka mina.' },
    { n: 32, text: 'Vavanuna lava i varisi, hikuva a va ri na swifuwo; va tisele swifuwo swa vona swa titsongo ni swa tinhulu, ni hinkwaswo leswi va nga na swona.\u2019' },
    { n: 33, text: 'Loko Faro a mi vitana, a ku: \u2018I yini mutirho wa n\u2019wina ke?\u2019' },
    { n: 34, text: 'Mi ta ku: \u2018Malandza ya wena hi vanhu va swifuwo kusukela evuntshweni bya hina ku fikela sweswi, hina ni vatata wa hina,\u2019 leswaku mi ta tshama etikweni ra Goxeni; hikuva murisi un\u2019wana ni un\u2019wana wa swifuwo i nchumu lowu nyenyetsaka eka Vaegipta.' },
  ],
  47: [
    { n: 1, text: 'Josefa a nghena, a hlamusela Faro, a ku: Tata wa mina ni vamakwerhu va mina, xikan\u2019we ni swifuwo swa vona swa titsongo ni swa tinhulu, ni hinkwaswo leswi va nga na swona, va humile etikweni ra Kanana; sweswi va le tikweni ra Goxeni.' },
    { n: 2, text: 'A teka vavanuna va ntlhanu exikarhi ka vamakwerhu va yena, a va yimisa mahlweni ka Faro.' },
    { n: 3, text: 'Faro a ku eka vamakwerhu va yena: I yini mutirho wa n\u2019wina ke? Va ku eka Faro: Malandza ya wena hi varisi va swifuwo, hina ni vatata wa hina.' },
    { n: 4, text: 'Va tlhela va ku eka Faro: Hi fikele ku ta luva etikweni leri, hikuva a ku nga ha ri na matlelo ya swifuwo swa malandza ya wena, hikuva ndlala yi tlimba swinene etikweni ra Kanana; sweswi, hi kombela leswaku malandza ya wena ma tshama etikweni ra Goxeni.' },
    { n: 5, text: 'Faro a vulavula na Josefa, a ku: Tata wa wena ni vamakwerhu va wena va fikile eka wena;' },
    { n: 6, text: 'tiko la Egipta ri mahlweni ka wena; tshamisa tata wa wena ni vamakwerhu va wena endhawini yo saseka swinene ya tiko; a va tshame etikweni ra Goxeni. Loko u tiva leswaku ku ni vavanuna va vutlhari exikarhi ka vona, va veke va va valanguteri va swifuwo swa mina.' },
    { n: 7, text: 'Josefa a nghenisa Akobo tata wa yena, a n\u2019wi yimisa mahlweni ka Faro; kutani Akobo a katekisa Faro.' },
    { n: 8, text: 'Faro a ku eka Akobo: Xana malembe ya vutomi bya wena ma njhani ke?' },
    { n: 9, text: 'Akobo a ku eka Faro: Masiku ya malembe ya ku rhendzeleka ka mina i dzenge ra malembe ya mune-khume ni makume-nharhu (130); masiku ya malembe ya vutomi bya mina ma vile matsongo ni ku tala hi ku karhateka, naswona a ma fikanga eka masiku ya malembe ya vutomi bya vatata wa mina emasikwini ya ku rhendzeleka ka vona.' },
    { n: 10, text: 'Akobo a katekisa Faro, a suka mahlweni ka Faro.' },
    { n: 11, text: 'Josefa a tshamisa tata wa yena ni vamakwerhu va yena, a va nyika tshomba etikweni la Egipta, endhawini yo saseka swinene ya tiko, etikweni ra Ramese, hilaha Faro a nga lerisa hakona.' },
    { n: 12, text: 'Josefa a phamela tata wa yena, ni vamakwerhu va yena, ni yindlu hinkwayo ya tata wa yena hi swakudya, hi ku landza ntsengo wa vana va titsongo.' },
    { n: 13, text: 'Kambe a ku nga ha ri na swakudya etikweni hinkwaro, hikuva ndlala a yi tlimba swinene; tiko la Egipta ni tiko ra Kanana swi tsana hikwalaho ka ndlala.' },
    { n: 14, text: 'Josefa a hlengeleta mali hinkwayo leyi a yi kumiwa etikweni la Egipta ni le tikweni ra Kanana hikwalaho ka mavele lawa va nga ya xava; Josefa a nghenisa mali leyi endlwini ya Faro.' },
    { n: 15, text: 'Loko mali yi hela etikweni la Egipta ni le tikweni ra Kanana, Vaegipta hinkwavo va fika eka Josefa, va ku: Hi nyike swakudya; ha yini hi fanele ku fa mahlweni ka wena xana, hikuva mali yi herile ke?' },
    { n: 16, text: 'Josefa a ku: Tisani swifuwo swa n\u2019wina, ndzi ta mi nyika swakudya hikwalaho ka swifuwo swa n\u2019wina, loko mali yi herile.' },
    { n: 17, text: 'Va tisa swifuwo swa vona eka Josefa; Josefa a va nyika swakudya hikwalaho ka tihanci, ni swifuwo swa titsongo, ni swifuwo swa tinhulu, ni timbanga; a va hlayisa hi swakudya hikwalaho ka swifuwo swa vona hinkwaswo hi lembe rero.' },
    { n: 18, text: 'Loko lembe rero ri herile, va fika eka yena hi lembe leri landzelaka, va ku eka yena: A hi nga n\u2019wi fihleri n\u2019wini wa hina leswaku mali yi herile, ni swifuwo swa hina i swa n\u2019wini wa hina; a ku nga ha salanga nchumu mahlweni ka n\u2019wini wa hina, handle ka mimiri ya hina ni misava ya hina.' },
    { n: 19, text: 'Ha yini hi fanele ku fa mahlweni ka mahlo ya wena, hina ni misava ya hina ke? Hi xave, hina ni misava ya hina hikwalaho ka swakudya, kutani hina ni misava ya hina hi ta va mahlonga ya Faro; hi nyike mbewu, leswaku hi hanya, hi nga fi, ni misava yi nga saleli ku va rhumbi.' },
    { n: 20, text: 'Josefa a xavela Faro misava hinkwayo ya Egipta; hikuva Muegipta un\u2019wana ni un\u2019wana a xavisa nsimu ya yena, hikuva ndlala a yi va tlimba; hiloko misava yi va ya Faro.' },
    { n: 21, text: 'Kasi vanhu, a va hundzuluxela emitini kusukela emugandzelweni un\u2019wana wa tiko ra Egipta ku fikela eka lowu un\u2019wana.' },
    { n: 22, text: 'Ntsena misava ya vaprista a nga yi xavanga; hikuva vaprista a va ri ni xiphemu lexi a xi humesiwa hi Faro, va dya xiphemu xa vona lexi Faro a nga va nyika xona; hikwalaho a va xavisanga misava ya vona.' },
    { n: 23, text: 'Josefa a ku eka vanhu: Vonani, namuntlha ndzi mi xavile, n\u2019wina ni misava ya n\u2019wina, mi va va Faro; sweswi, hi leyi mbewu ya n\u2019wina, byalani misava.' },
    { n: 24, text: 'Loko ku tshembiwa ku tshovela, mi ta nyika Faro xiphemu xa vuntlhanu (1/5), kutani swiphemu swa mune swi ta va swa n\u2019wina ku va mbewu ya nsimu, ni swakudya swa n\u2019wina, ni swa lava nga tindyandlu ta n\u2019wina, ni ku va swakudya swa vana va n\u2019wina va titsongo.' },
    { n: 25, text: 'Va ku: U hiponisile vutomi! Hi pfumelele ku kuma tintswalo mahlweni ka n\u2019wini wa hina, hi ta va mahlonga ya Faro.' },
    { n: 26, text: 'Josefa a endla nawu lowu ehenhla ka misava ya Egipta ku fikela namuntlha, leswaku xiphemu xa vuntlhanu xi va xa Faro; ntsena misava ya vaprista a yi fanyisangi ku va ya Faro.' },
    { n: 27, text: 'Israyele a tshama etikweni la Egipta, etikweni ra Goxeni; va kuma swilo kwalaho, va tswalana, va andza swinene.' },
    { n: 28, text: 'Akobo a hanya etikweni la Egipta malembe ya khume na nkombo (17); masiku ya Akobo, malembe ya vutomi bya yena, ma ve dzenge ra malembe ya mune-khume ni makume-ntandathu na nkombo (147).' },
    { n: 29, text: 'Loko masiku ya ku fa ka Israyele ma tshinela, a vitana Josefa n\u2019wana wa yena, a ku eka yena: Loko sweswi ndzi kumile tintswalo emantweni ya wena, nghenisa voko ra wena ehansi ka xirhendze xa mina, u ndzi komba tintswalo ni ntiyiso: ndzi kombela u nga ndzi lahli eEgipta;' },
    { n: 30, text: 'kambe ndzi lava ku etlela ni vatata wa mina; u ta ndzi rwala u ndzi humesa eEgipta, u ya ndzi lahla esirheni ra vona. Josefa a ku: Ndzi ta endla hilaha u nga vula hakona.' },
    { n: 31, text: 'Akobo a ku: Ndzi hambele xihambalo. A n\u2019wi hambela xihambalo. Hiloko Israyele a khinsama enhlokweni ya mbedli.' },
  ],
  48: [
    { n: 1, text: 'Endzhaku ka swilo leswi, va hlamusela Josefa, va ku: Vona, tata wa wena wa vabya. Hiloko a teka vana va yena vambirhi, Manase na Efraimi, a famba na vona.' },
    { n: 2, text: 'Va hlamusela Akobo, va ku: Vona, n\u2019wana wa wena Josefa wa fika eka wena. Israyele a tiyisa mbilu, a tshama embedleni.' },
    { n: 3, text: 'Akobo a ku eka Josefa: Xikwembu xa Matimba Hinkwako xi ndzi humelele eLuza, etikweni ra Kanana, xi ndzi katekisa;' },
    { n: 4, text: 'xi ku eka mina: \u2018Vona, ndzi ta ku endla u tswalana, ndzi ku andzisa, ndzi ku endla u va nhlengeletano ya matiko; ndzi ta nyika misava leyi vana va wena endzhaku ka wena ku va tshomba leri nga heriki.\u2019' },
    { n: 5, text: 'Sweswi, vana va wena vambirhi lava nga ku tswaleriwa etikweni la Egipta, ndzi nga si fika eka wena eEgipta, i vana va mina; Efraimi na Manase va ta va va mina ku fana na Rubeni na Simiyoni.' },
    { n: 6, text: 'Kambe vana va wena lava u nga ta va tswala endzhaku ka vona va ta va va wena; va ta vitaniwa hi vito ra vamakwerhu va vona etshombeni ra vona.' },
    { n: 7, text: 'Kasi mina, loko ndzi huma ePadani, Rahele a ndzi fela endleleni etikweni ra Kanana, loko ka ha sele nkarhi muntsongo ku fika eEfrata; ndzi n\u2019wi lahla kwalaho endleleni ya Efrata (leyi nga Betlehema).' },
    { n: 8, text: 'Israyele a vona vana va Josefa, a ku: I vamani lava ke?' },
    { n: 9, text: 'Josefa a ku eka tata wa yena: I vana va mina, lava Xikwembu xi nga ndzi nyika vona kwala. Akobo a ku: Ndzi kombela u va tisa kusuhi na mina, ndzi va katekisa.' },
    { n: 10, text: 'Mahlo ya Israyele a ya tsanile hikwalaho ka vukhalabye, a a nga ha swi koti ku vona kahle. Josefa a va tisa kusuhi na yena; kutani a va ntswontswa, a va rhandzela.' },
    { n: 11, text: 'Israyele a ku eka Josefa: A ndzi nga ha ehleketi ku vona xikandza xa wena, kambe vona, Xikwembu xi ndzi kombisile ni vana va wena.' },
    { n: 12, text: 'Josefa a va humesa exikarhi ka matsolo ya yena, a khinsama xikandza xa yena xi khumba hansi.' },
    { n: 13, text: 'Josefa a va teka vambirhi: Efraimi hi voko ra yena ra xinene a ya evokweni ra ximatsi ra Israyele, ni Manase hi voko ra yena ra ximatsi a ya evokweni ra xinene ra Israyele; a va tisa kusuhi na yena.' },
    { n: 14, text: 'Kambe Israyele a navisa voko ra yena ra xinene, a xi veka ehenhla ka nhloko ya Efraimi, loyi a a ri lontsongo, ni voko ra yena ra ximatsi a xi veka ehenhla ka nhloko ya Manase; a hlayisele mavoko ya yena hi vutlhari, hikuva Manase a a ri mativula.' },
    { n: 15, text: 'A katekisa Josefa, a ku: Xikwembu lexi vatata wa mina Abrahama na Isaka va nga famba mahlweni ka xona, Xikwembu lexi nga ndzi risa kusukela evutomi bya mina ku fikela namuntlha,' },
    { n: 16, text: 'Ntsumi leyi nga ndzi ponisa eka vubihi hinkwabyo, a yi katekise majaha lawa; vito ra mina a ri vitaniwe eka vona, ni mavito ya vatata wa mina Abrahama na Isaka; a va andze va va ntsandza-vahlayi exikarhi ka misava.' },
    { n: 17, text: 'Loko Josefa a vona leswaku tata wa yena u vekile voko ra yena ra xinene ehenhla ka nhloko ya Efraimi, swi n\u2019wi tlimba mbilu; a teka voko ra tata wa yena ku xi fambisa enhlokweni ya Efraimi a xi yisa enhlokweni ya Manase.' },
    { n: 18, text: 'Josefa a ku eka tata wa yena: E-e, tata wa mina, hikuva loyi i mativula; veka voko ra wena ra xinene ehenhla ka nhloko ya yena.' },
    { n: 19, text: 'Kambe tata wa yena a ala, a ku: Ndzi swi tiva, n\u2019wana wa mina, ndzi swi tiva; na yena u ta va tiko, na yena u ta va nkulu; kambe makwerhu wa yena lontsongo u ta va nkulu ku n\u2019wi tlula, ni vana va yena va ta va ku tala ka matiko.' },
    { n: 20, text: 'A va katekisa hi siku rero, a ku: Hi n\u2019wina Israyele a nga ta katekisa ha kona, a ku: \u2018Xikwembu a xi ku endle u fana na Efraimi ni ku fana na Manase.\u2019 Hiloko a veka Efraimi emahlweni ka Manase.' },
    { n: 21, text: 'Israyele a ku eka Josefa: Vona, ndzi le kusuhi ni ku fa; kambe Xikwembu xi ta va na n\u2019wina, xi mi vuyisa etikweni ra vatata wa n\u2019wina.' },
    { n: 22, text: 'Kutani mina ndzi ku nyika xiphemu xin\u2019we xo hlawuleka ku tlula vamakwerhu va wena, lexi ndzi nga xi teka emavokweni ya Vaamori hi banga ra mina ni hi vurha bya mina.' },
  ],
  49: [
    { n: 1, text: 'Akobo a vitana vana va yena, a ku: Hlengeletanani, ndzi mi hlamusela leswi nga ta mi kela emasikwini lama taka.' },
    { n: 2, text: 'Hlengeletanani, mi yingisela, n\u2019wina vana va Akobo; yingiselani Israyele tata wa n\u2019wina.' },
    { n: 3, text: 'Rubeni, u mativula ya mina, ntamu wa mina ni ku sungula ka matimba ya mina; u tlula van\u2019wana hi xindzhuti ni ku tlula hi ntamu.' },
    { n: 4, text: 'U tsutsumile ku fana ni mati, u nga ka u nga tluli van\u2019wana, hikuva u nghenile embedleni ya tata wa wena; hiloko u yi nyamikisile; u nghenile embedleni ya mina.' },
    { n: 5, text: 'Simiyoni na Levi i vamakwerhu; mabanga ya vona i swibya swa madzolonga.' },
    { n: 6, text: 'Mbilu ya mina, u nga ngheni exihundleni xa vona; xindzhuti xa mina, u nga hlangani ni nhlengeletano ya vona; hikuva eku hlundgukeni ka vona va dlayile vanhu, ni le ku tisunguleni ka vona va tsemile tinyenge ta tihomu.' },
    { n: 7, text: 'A ku rhukaniwe ku hlundguka ka vona, hikuva ku ni matimba, ni rito ra vona ra ku lwa, hikuva ri ni tihanyi; ndzi ta va avanyisa eka Akobo, ndzi va hangalasa eIsrayele.' },
    { n: 8, text: 'Yuda, wena vamakwerhu va wena va ta ku dzunisa; voko ra wena ri ta va enon\u2019wini wa valala va wena; vana va tata wa wena va ta ku khinsamela.' },
    { n: 9, text: 'Yuda i n\u2019wana wa nghala; u tlhandlukile eku dlayeni, n\u2019wana wa mina; u khinsamile, u lale ku fana ni nghala, ni ku fana ni nghala ya xisati; i mani la nga n\u2019wi pfuxaka ke?' },
    { n: 10, text: 'Nhonga ya vuhosi a yi nga ka yi nga suki eka Yuda, hambi ku ri nhonga ya mulawuri exikarhi ka milenge ya yena, ku fikela loko Xilo a fika; kutani vanhu va ta n\u2019wi yingisela.' },
    { n: 11, text: 'A boha mbanga ya yena emundzhwini wa vhinyo, ni n\u2019wana wa mbanga ya yena emundzhwini wo saseka swinene; u hlantsa tinguvu ta yena evhinyweni, ni nguvu ya yena e ngatingati ya madiriva;' },
    { n: 12, text: 'mahlo ya yena ma ta va yo tshuka hi vhinyo, ni meno ya yena ya ta va yo basa hi ntswamba.' },
    { n: 13, text: 'Zebuloni u ta tshama eribuweni ra lwandle; u ta va ribuwe ra swikepe, ni ndzilakana wa yena wu ta fika eSidoni.' },
    { n: 14, text: 'Isakara i mbanga ya matimba, leyi laleke exikarhi ka swiphala swa timbanga.' },
    { n: 15, text: 'A vona leswaku ku wisa ku tsakisile, ni leswaku misava yi sasekile; a rhelerisa phela ra yena ku rwala ndzhwalo, a hundzuka nandza wa ku luva.' },
    { n: 16, text: 'Dani u ta avanyisa vanhu va yena, ku fana ni un\u2019wana wa tinyimba ta Israyele.' },
    { n: 17, text: 'Dani u ta va nyoka endleleni, nyoka ya lomu byanyini leyi lumaka xirhendze xa hanci, leswaku mugadi wa rona a wela endzhaku.' },
    { n: 18, text: 'Ndzi rindzerile kuponisa ka wena, Yehovha.' },
    { n: 19, text: 'Gadi, ntlawa wa vaphangeri wu ta n\u2019wi pfukela, kambe yena u ta va pfukela endzhaku ka vona.' },
    { n: 20, text: 'Eka Axere, swakudya swa yena swi ta va ni mafurha, naswona u ta humesa swakudya swa vuhosi.' },
    { n: 21, text: 'Neftali i mhala leyi ntshunxiweke, leyi vulavulaka marito yo saseka.' },
    { n: 22, text: 'Josefa i rhavi leri tswalaka swinene, rhavi leri tswalaka swinene kusuhi ni xihlovo; marhavi ya rona ma tlula khumbi.' },
    { n: 23, text: 'Vatshatshi va n\u2019wi karhatile swinene, va n\u2019wi fambisa hi maseve, va n\u2019wi venga;' },
    { n: 24, text: 'kambe vurha bya yena byi tshamile byi tiyile, ni mavoko ya yena ma ve ni matimba hi mavoko ya Loyi wa Matimba wa Akobo, hi vito ra Murisi, Ribye ra Israyele,' },
    { n: 25, text: 'hi Xikwembu xa tata wa wena lexi nga ta ku pfuna, ni hi Loyi wa Matimba Hinkwako la nga ta ku katekisa hi mikatekiso ya le tilweni ehenhla, mikatekiso ya lwandle leri nga ehansi, mikatekiso ya tisele ni ya mbeleko.' },
    { n: 26, text: 'Mikatekiso ya tata wa wena yi tlurile mikatekiso ya vatata wa mina ku fikela emindzilakanini ya switsunga leswi nga heriki; a yi ve ehenhla ka nhloko ya Josefa, ni le henhla ka mhani wa nhloko ya loyi a nga hlawuriwa exikarhi ka vamakwerhu va yena.' },
    { n: 27, text: 'Benjamini i mbyana ya nhova leyi handzulaka; nimpundzu u dya swakudya lesvi a nga swi phanga, ni madyambu u avanyisa swilo lesvi a nga swi phanga.' },
    { n: 28, text: 'Lawa hinkwavo i tinyimba ta khume-mbirhi (12) ta Israyele; ni leswi i lesvi tata wa vona a nga va byela swona loko a va katekisa; un\u2019wana ni un\u2019wana a n\u2019wi katekisa hi ku landza nkatekiso wa yena.' },
    { n: 29, text: 'A va lerisa, a ku eka vona: Ndzi le kusuhi ni ku hlengeletanisiwa ni vanhu va mina; ndzi lahleni ni vatata wa mina ebaku leri nga nsimwini ya Efroni lowu wa Muheti,' },
    { n: 30, text: 'ebaku leri nga nsimwini ya Makpela, mahlweni ka Mamre, etikweni ra Kanana, leli Abrahama a nga ri xava xikan\u2019we ni nsimu eka Efroni lowu wa Muheti ku va tshomba ra masira.' },
    { n: 31, text: 'Kwalaho va lahle Abrahama ni nsati wa yena Sara; kwalaho va lahle Isaka ni nsati wa yena Rebeka; naswona kwalaho ndzi lahle Liyaha.' },
    { n: 32, text: 'Nsimu ni baku leri nga ka yona swi xaviwe eka vana va Heti.' },
    { n: 33, text: 'Loko Akobo a herisile ku lerisa vana va yena, a vuyisela milenge ya yena embedleni, a fa, a hlengeletanisiwa ni vanhu va yena.' },
  ],
  50: [
    { n: 1, text: 'Josefa a wela ehenhla ka xikandza xa tata wa yena, a rila ehenhla ka yena, a n\u2019wi ntswontswa.' },
    { n: 2, text: 'Josefa a lerisa malandza ya yena, tin\u2019anga, ku totisa ntsumbu wa tata wa yena; hiloko tin\u2019anga ti totisa Israyele.' },
    { n: 3, text: 'Va endla tano masiku ya mune-khume (40), hikuva hi wona masiku ya ku totisa; kutani Vaegipta va n\u2019wi rila masiku ya makume-nkombo (70).' },
    { n: 4, text: 'Loko masiku ya ku n\u2019wi rila ya herile, Josefa a vulavula ni yindlu ya Faro, a ku: Loko sweswi ndzi kumile tintswalo emantweni ya n\u2019wina, vulavulani etindleveni ta Faro, mi ku:' },
    { n: 5, text: '\u2018Tata wa mina u ndzi endlile ndzi hambela xihambalo, a ku: \u201cVona, ndzi le kusuhi ni ku fa; u ta ndzi lahla esirheni ra mina leri ndzi nga ri tsemeta etikweni ra Kanana.\u201d Sweswi, ndzi kombela u ndzi pfumelela ndzi tlhandluka ndzi ya lahla tata wa mina, ndzi ta vuya.\u2019' },
    { n: 6, text: 'Faro a ku: Tlhandluka u ya lahla tata wa wena, hilaha a nga ku endlisa xihambalo hakona.' },
    { n: 7, text: 'Josefa a tlhandluka ku ya lahla tata wa yena; kutani malandza hinkwaswo ya Faro, ni vakhalabye va yindlu ya yena, ni vakhalabye hinkwavo va tiko ra Egipta va tlhandluka na yena,' },
    { n: 8, text: 'ni yindlu hinkwayo ya Josefa, ni vamakwerhu va yena, ni yindlu ya tata wa yena; ntsena vana va vona va titsongo, ni swifuwo swa vona va titsongo ni swa tinhulu va swi siya etikweni ra Goxeni.' },
    { n: 9, text: 'Ku tlhandluka na yena ticalichi ni vagadi va tihanci; ku ve ni ntlawa wera kulu swinene.' },
    { n: 10, text: 'Va fika ematleleni ya Atada, lama nga endzhaku ka Yordani, va rila kwalaho hi rito rera kulu ni ro tlimba swinene; Josefa a rila tata wa yena masiku ya nkombo.' },
    { n: 11, text: 'Loko va-Kanana, vaaki va tiko, va vona ku rila loku ematleleni ya Atada, va ku: I ku rila lokukulu eka Vaegipta. Hikwalaho ndhawu yero yi thyeka vito ra Abeli-Mizrayimi, leyi nga endzhaku ka Yordani.' },
    { n: 12, text: 'Vana va yena va n\u2019wi endlerila hilaha a nga va lerisa hakona;' },
    { n: 13, text: 'vana va yena va n\u2019wi rwala va n\u2019wi yisa etikweni ra Kanana, va n\u2019wi lahla ebaku ra nsimu ya Makpela, leli Abrahama a nga ri xava xikan\u2019we ni nsimu eka Efroni lowu wa Muheti ku va tshomba ra masira, mahlweni ka Mamre.' },
    { n: 14, text: 'Endzhaku ka ku lahla tata wa yena, Josefa a vuyela eEgipta, yena ni vamakwerhu va yena, ni hinkwavo lava a va tlhandlukile na yena ku ya lahla tata wa yena.' },
    { n: 15, text: 'Loko vamakwerhu va Josefa va vona leswaku tata wa vona u file, va ku: Kumbexana Josefa u ta hi venga, a hi tlherisela hinkwaro vubihi lebyi hi nga n\u2019wi endlerila byona.' },
    { n: 16, text: 'Va rhumela rito eka Josefa, va ku: Tata wa wena u lerisile a nga si fa, a ku:' },
    { n: 17, text: '\u2018Mi ta ku eka Josefa: \u201cNdzi kombela u rivalela xidyoho xa vamakwerhu va wena ni vubihi bya vona, hikuva va ku endlerile vubihi.\u201d\u2019 Sweswi, ndzi kombela u rivalela xidyoho xa malandza ya Xikwembu xa tata wa wena. Josefa a rila loko va vulavula na yena.' },
    { n: 18, text: 'Vamakwerhu va yena va fika na vona, va khinsama mahlweni ka yena, va ku: Vona, hi mahlonga ya wena.' },
    { n: 19, text: 'Kambe Josefa a ku eka vona: Mi nga chavi; xana ndzi le xihundleni xa Xikwembu ke?' },
    { n: 20, text: 'N\u2019wina mi ndzi rhandzele vubihi, kambe Xikwembu xi ku hundzurile ku va leswo saseka, ku endla leswi nga kona namuntlha, ku ponisa vanhu vo tala.' },
    { n: 21, text: 'Sweswi, mi nga chavi; ndzi ta mi phamela, n\u2019wina ni vana va n\u2019wina va titsongo. Hiloko a va chavelela, a vulavula ni timbilu ta vona.' },
    { n: 22, text: 'Josefa a tshama eEgipta, yena ni yindlu ya tata wa yena; Josefa a hanya malembe ya dzenge ra khume (110).' },
    { n: 23, text: 'Josefa a vona vana va Efraimi ku fika eka xitshungu xa vunharhu; na vana va Makiri n\u2019wana wa Manase va tswaleriwa ematsholweni ya Josefa.' },
    { n: 24, text: 'Josefa a ku eka vamakwerhu va yena: Ndzi le kusuhi ni ku fa; kambe hakunene Xikwembu xi ta mi pfuxa, xi mi humesa etikweni leri, xi mi yisa etikweni leri xi nga hambela xihambalo eka Abrahama, Isaka ni le ka Akobo.' },
    { n: 25, text: 'Josefa a endlisa vana va Israyele xihambalo, a ku: Hakunene Xikwembu xi ta mi pfuxa, kutani mi ta rwala marambu ya mina mi huma na wona kwala.' },
    { n: 26, text: 'Josefa a fa a ri ni malembe ya dzenge ra khume (110); va totisa ntsumbu wa yena, va n\u2019wi veka ebokisini eEgipta.' },
  ],


};
